        /* ---------------------------
            Storage helpers
        --------------------------- */
        function getMylistData() {
            let raw = GM_getValue(STORAGE_KEY);
            const isNewInstall = !raw || typeof raw !== 'object' || raw === null;
            if (isNewInstall) {
                raw = { folders: {} };
            }

            if (!raw.folders) raw.folders = {};

            // 初回インストール時：初期フォルダ3つを作成しデフォルトを先頭フォルダに設定
            if (isNewInstall) {
                FREE_INITIAL_FOLDERS.forEach(name => {
                    raw.folders[name] = [];
                });
                raw.initialRootFolders = [...FREE_INITIAL_FOLDERS];
                setDefaultFolder(FREE_INITIAL_FOLDERS[0]);
            }

            if (ensureInitialRootFolders(raw)) {
                try { GM_setValue(STORAGE_KEY, raw); } catch (_) { }
            }

            if (!raw.folders[getDefaultFolder()]) raw.folders[getDefaultFolder()] = [];
            if (!raw.folders[TRASH_FOLDER_NAME]) raw.folders[TRASH_FOLDER_NAME] = [];
            if (!raw.trashName) raw.trashName = DEFAULT_TRASH_NAME;
            // フォルダごとのソート状態が存在しない、またはオブジェクトでない場合は初期化
            if (!raw.sortStateByFolder || typeof raw.sortStateByFolder !== 'object') {
                raw.sortStateByFolder = {};
            }
            // サブフォルダ動画の表示設定
            if (!raw.showDescendantVideosByFolder || typeof raw.showDescendantVideosByFolder !== 'object') {
                raw.showDescendantVideosByFolder = {};
            }
            // フォルダごとのアイコン色（hex）
            if (!raw.iconColorByFolder || typeof raw.iconColorByFolder !== 'object') {
                raw.iconColorByFolder = {};
            }

            // URLからインポートした再生リストの元ページURL（フォルダ単位）
            if (!raw.folderSourceUrlByFolder || typeof raw.folderSourceUrlByFolder !== 'object') {
                raw.folderSourceUrlByFolder = {};
            }

            ensureFolderOrderIntegrity(raw);

            // 注: 読み込み関数内での GM_setValue は削除（saveMylistData() に任せる）
            return raw;
        }

        function normalizeYouTubePlaylistUrl(url) {
            const raw = String(url || '').trim();
            const m = raw.match(/[?&]list=([a-zA-Z0-9_-]+)/);
            if (!m) return raw;
            return `https://www.youtube.com/playlist?list=${m[1]}`;
        }

        async function showImportAlert(message) {
            if (isMylistPage()) {
                await showCustomModal({ type: 'alert', title: 'インポート', message: message });
                return;
            }
            await createYoutubeModal(message, { okText: 'OK' });
        }

        async function showImportPrompt(title, message, options = {}) {
            if (isMylistPage()) {
                return await showCustomModal({
                    type: 'prompt',
                    title,
                    message,
                    defaultValue: options.defaultValue || '',
                    placeholder: options.placeholder || '',
                    okText: options.okText || 'OK',
                    okClass: options.okClass || 'vm-btn-primary'
                });
            }
            const promptText = title ? `${title}\n${message || ''}` : (message || '');
            return await createYoutubeModal(promptText, {
                inputType: 'text',
                inputValue: options.defaultValue || '',
                inputPlaceholder: options.placeholder || '',
                okText: options.okText || 'OK',
                cancelText: options.cancelText || 'キャンセル'
            });
        }

        async function showImportConfirm(title, message, options = {}) {
            if (isMylistPage()) {
                return await showCustomModal({
                    type: 'confirm',
                    title,
                    message,
                    okText: options.okText || 'OK',
                    cancelText: options.cancelText || 'キャンセル'
                });
            }
            const confirmText = title ? `${title}\n${message || ''}` : (message || '');
            const result = await createYoutubeModal(confirmText, {
                okText: options.okText || 'OK',
                cancelText: options.cancelText || 'キャンセル'
            });
            return !!result;
        }

        function inheritUserVideoMeta(baseVideo, sourceVideo) {
            const next = { ...(baseVideo || {}) };
            const src = sourceVideo && typeof sourceVideo === 'object' ? sourceVideo : null;
            if (!src) return next;

            if ((!next.note || !String(next.note).trim()) && src.note) {
                next.note = String(src.note);
            }
            if ((!next.lastPlayedAt || !String(next.lastPlayedAt).trim()) && src.lastPlayedAt) {
                next.lastPlayedAt = String(src.lastPlayedAt);
            }
            if (!(typeof next.lastPlaybackSec === 'number' && next.lastPlaybackSec > 0) && (typeof src.lastPlaybackSec === 'number' && src.lastPlaybackSec > 0)) {
                next.lastPlaybackSec = src.lastPlaybackSec;
            }
            if (!(typeof next.currentTime === 'number' && next.currentTime > 0) && (typeof src.currentTime === 'number' && src.currentTime > 0)) {
                next.currentTime = src.currentTime;
            }
            if ((!next.addedAt || !String(next.addedAt).trim()) && src.addedAt) {
                next.addedAt = String(src.addedAt);
            }
            if ((!Array.isArray(next.tags) || !next.tags.length) && Array.isArray(src.tags) && src.tags.length) {
                next.tags = src.tags.slice();
            }
            return next;
        }

        function buildExistingVideoMetaMap(data) {
            const map = new Map();
            const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
            Object.values(folders).forEach((list) => {
                if (!Array.isArray(list)) return;
                list.forEach((video) => {
                    const id = video && video.id ? String(video.id) : '';
                    if (!id || map.has(id)) return;
                    map.set(id, video);
                });
            });
            return map;
        }

        async function importPlaylistFromUrlFlow(playlistUrl) {
            if (!isPremiumUser()) {
                showToast(t('limit.playlist_import'), 3500);
                return false;
            }
            const normalizedPlaylistUrl = normalizeYouTubePlaylistUrl(playlistUrl);
            if (!normalizedPlaylistUrl || !/[?&]list=/.test(normalizedPlaylistUrl)) {
                await showImportAlert('有効なYouTube再生リストURLを指定してください。');
                return false;
            }

            showToast('再生リストを処理中...');

            try {
                const result = await fetchPlaylistVideos(normalizedPlaylistUrl);
                const playlistTitle = result.title;
                const videos = result.videos;

                if (videos.length === 0) {
                    await showImportAlert('再生リストに動画が見つかりませんでした。');
                    return false;
                }

                let folderName = '';
                let folderNameInput = playlistTitle;
                // 別のURLとひもついた同名フォルダは使えないため、別名を入力し直せるようループ
                while (true) {
                    const folderNameRaw = await showImportPrompt('保存先フォルダ', `再生リスト「${playlistTitle}」(${videos.length}件) をどのフォルダに登録しますか？`, {
                        defaultValue: folderNameInput,
                        okText: '登録',
                        okClass: 'vm-btn-primary',
                        cancelText: 'キャンセル'
                    });
                    const candidate = String(folderNameRaw || '').trim();
                    if (!candidate) return false;

                    const dataCheck = getMylistData();
                    const existingSourceUrl = dataCheck.folderSourceUrlByFolder?.[candidate];
                    if (existingSourceUrl && existingSourceUrl !== normalizedPlaylistUrl && dataCheck.folders[candidate]) {
                        // 別のURLにひもついた同名フォルダ → 別名を促す
                        folderNameInput = candidate;
                        await showImportAlert(
                            `フォルダ「${candidate}」は別の再生リストと既にひもついています。\n` +
                            `（${existingSourceUrl}）\n\n` +
                            `別のフォルダ名を指定してください。`
                        );
                        continue;
                    }
                    folderName = candidate;
                    break;
                }

                if (!folderName) return false;

                const data = getMylistData();
                const existingList = Array.isArray(data.folders[folderName]) ? data.folders[folderName] : [];
                const existingVideoMetaMap = buildExistingVideoMetaMap(data);

                if (!data.folders[folderName]) {
                    data.folders[folderName] = [];
                    data.folderOrder.push(folderName);
                }

                let addedCount = 0;
                let ignoredCount = 0;

                videos.forEach(video => {
                    const inherited = existingVideoMetaMap.get(video.id);
                    const mergedVideo = inheritUserVideoMeta(video, inherited);
                    if (!existingList.some(v => v.id === video.id)) {
                        existingList.push(mergedVideo);
                        addedCount++;
                    } else {
                        const existingIndex = existingList.findIndex(v => v.id === video.id);
                        if (existingIndex !== -1) {
                            existingList[existingIndex] = inheritUserVideoMeta(existingList[existingIndex], inherited);
                        }
                        ignoredCount++;
                    }
                });

                data.folders[folderName] = existingList;

                if (!data.folderSourceUrlByFolder || typeof data.folderSourceUrlByFolder !== 'object') {
                    data.folderSourceUrlByFolder = {};
                }
                data.folderSourceUrlByFolder[folderName] = normalizedPlaylistUrl;

                saveMylistData(data);

                const enableAutoSync = await showImportConfirm('自動同期設定', `インポートが完了しました。\n追加: ${addedCount}件 / 登録済みスキップ: ${ignoredCount}件\n\nこの再生リストを自動同期の対象にしますか？\n（新しい動画が追加されたとき自動で取り込まれます）`, {
                    okText: '自動同期を有効にする',
                    cancelText: '手動のみ'
                });

                // 「手動のみ」を選んだ場合でも同期設定一覧に登録して、後から有効化できるようにする
                const playlistSyncData = getPlaylistSyncData();
                const prevSyncInfo = playlistSyncData.syncPlaylists[normalizedPlaylistUrl] || null;
                playlistSyncData.syncPlaylists[normalizedPlaylistUrl] = {
                    ...(prevSyncInfo || {}),
                    folderName: folderName,
                    playlistTitle: playlistTitle,
                    enabled: !!enableAutoSync,
                    createdAt: prevSyncInfo?.createdAt || new Date().toISOString(),
                    lastSync: enableAutoSync ? new Date().toISOString() : (prevSyncInfo?.lastSync || ''),
                    lastVideoCount: videos.length
                };
                savePlaylistSyncData(playlistSyncData);
                if (enableAutoSync) {
                    showToast(`✅ 「${folderName}」の自動同期を有効にしました`);
                } else {
                    showToast(`📝 「${folderName}」を手動同期対象として登録しました（設定から後でON可能）`);
                }

                if (isMylistPage()) {
                    renderMylistPage();
                }
                return true;
            } catch (error) {
                await showImportAlert(`インポートに失敗しました: ${error.message.split(':').slice(-1)[0].trim()}`);
                return false;
            }
        }

        function openUrlInNewTab(url) {
            if (!url) return;
            // 動画ページ(youtube.com/watch) は設定によって同タブ遷移を許可
            try {
                const isWatchUrl = /(?:^|\/\/)(?:www\.)?youtube\.com\/watch\?/i.test(String(url));
                if (isWatchUrl) {
                    const target = (typeof GM_getValue === 'function') ? GM_getValue(VIDEO_OPEN_TARGET_KEY, 'newtab') : 'newtab';
                    if (target === 'sametab') {
                        try { window.location.href = url; return; } catch (_) {/* fallback */ }
                    }
                }
            } catch (_) {/* noop */ }
            try {
                if (typeof GM_openInTab === 'function') {
                    GM_openInTab(url, { active: true });
                } else {
                    window.open(url, '_blank', 'noopener');
                }
            } catch (_) {
                try { window.open(url, '_blank'); } catch (__) { }
            }
        }

        function getImportedPlaylistUrlForFolder(folderPath, data) {
            const direct = data?.folderSourceUrlByFolder?.[folderPath];
            if (direct) return direct;

            // 旧データ/自動同期のみ設定されている場合のフォールバック
            const playlistSyncData = getPlaylistSyncData();
            const syncPlaylists = playlistSyncData?.syncPlaylists || {};
            for (const [playlistUrl, info] of Object.entries(syncPlaylists)) {
                if (info && info.folderName === folderPath) {
                    return playlistUrl;
                }
            }
            return null;
        }
