        /* ---------------------------
            削除ログ（同期時の動画復活防止）
            vm_deleted_log_v1: { entries: [{ videoId, folderName, deletedAt }] }
        --------------------------- */
        function getDeletedVideoLog() {
            try {
                const raw = GM_getValue(DELETED_VIDEO_LOG_KEY, null);
                if (raw && typeof raw === 'object' && Array.isArray(raw.entries)) return raw;
            } catch (_) { }
            return { entries: [] };
        }
        function saveDeletedVideoLog(log) {
            try { GM_setValue(DELETED_VIDEO_LOG_KEY, log); } catch (_) { }
        }
        function addDeletedVideoLogEntries(entries) {
            // entries: [{ videoId, folderName }]
            if (!entries || !entries.length) return;
            const log = getDeletedVideoLog();
            const now = new Date().toISOString();
            entries.forEach(({ videoId, folderName }) => {
                if (!videoId || !folderName) return;
                log.entries.push({ videoId: String(videoId), folderName: String(folderName), deletedAt: now });
            });
            // 30日以上古いエントリを削除
            const cutoff = Date.now() - 30 * 24 * 60 * 60 * 1000;
            log.entries = log.entries.filter(e => new Date(e.deletedAt).getTime() > cutoff);
            saveDeletedVideoLog(log);
        }
        function isVideoDeletedFromFolder(videoId, folderName) {
            try {
                const log = getDeletedVideoLog();
                return log.entries.some(e => e.videoId === String(videoId) && e.folderName === String(folderName));
            } catch (_) { return false; }
        }
        function clearDeletedVideoLogForFolder(folderName) {
            try {
                const log = getDeletedVideoLog();
                log.entries = log.entries.filter(e => e.folderName !== String(folderName));
                saveDeletedVideoLog(log);
            } catch (_) { }
        }

