        function getDefaultShortcutKeyConfig() {
            return {
                version: 1,
                actions: {
                    timestamp: { combo: '' },
                    note: { combo: '' },
                    prev_video: { combo: '' },
                    next_video: { combo: '' }
                }
            };
        }

        function isShortcutModifierKeyName(keyName) {
            const k = String(keyName || '').toLowerCase();
            return k === 'ctrl' || k === 'shift' || k === 'alt' || k === 'meta';
        }

        function normalizeShortcutMainKey(rawKey) {
            const key = String(rawKey || '');
            if (!key) return '';
            if (key === ' ') return 'space';
            const lower = key.toLowerCase();
            if (lower === 'escape') return 'esc';
            if (lower === 'arrowup') return 'up';
            if (lower === 'arrowdown') return 'down';
            if (lower === 'arrowleft') return 'left';
            if (lower === 'arrowright') return 'right';
            if (lower === 'control' || lower === 'ctrl') return '';
            if (lower === 'shift' || lower === 'alt' || lower === 'meta' || lower === 'os') return '';
            if (/^[a-z0-9]$/i.test(key)) return lower;
            if (/^f([1-9]|1[0-2])$/i.test(key)) return lower;
            if (['enter', 'tab', 'space', 'backspace', 'delete', 'insert', 'home', 'end', 'pageup', 'pagedown'].includes(lower)) return lower;
            if (key.length === 1) return lower;
            return lower;
        }

        function normalizeShortcutComboString(raw) {
            if (typeof raw !== 'string') return '';
            const text = raw.trim();
            if (!text) return '';
            const tokens = text.split('+').map(t => String(t || '').trim()).filter(Boolean);
            if (!tokens.length) return '';

            const mods = new Set();
            let main = '';
            tokens.forEach((token) => {
                const lower = token.toLowerCase();
                if (lower === 'control') {
                    mods.add('ctrl');
                    return;
                }
                if (lower === 'command' || lower === 'cmd' || lower === 'windows' || lower === 'win' || lower === 'os') {
                    mods.add('meta');
                    return;
                }
                if (lower === 'ctrl' || lower === 'shift' || lower === 'alt' || lower === 'meta') {
                    mods.add(lower);
                    return;
                }
                if (!main) {
                    main = normalizeShortcutMainKey(token);
                }
            });

            if (!main || isShortcutModifierKeyName(main)) return '';
            const orderedMods = ['ctrl', 'shift', 'alt', 'meta'].filter(m => mods.has(m));
            const parts = orderedMods.concat([main]);
            if (parts.length < 1 || parts.length > 3) return '';
            return parts.join('+');
        }

        function formatShortcutComboLabel(combo) {
            const normalized = normalizeShortcutComboString(combo);
            if (!normalized) return '未設定';
            const map = {
                ctrl: 'Ctrl',
                shift: 'Shift',
                alt: 'Alt',
                meta: 'Meta',
                esc: 'Esc',
                up: '↑',
                down: '↓',
                left: '←',
                right: '→',
                pageup: 'PageUp',
                pagedown: 'PageDown',
                backspace: 'Backspace',
                delete: 'Delete',
                insert: 'Insert',
                home: 'Home',
                end: 'End',
                enter: 'Enter',
                tab: 'Tab',
                space: 'Space'
            };
            const parts = normalized.split('+').map((part) => {
                if (map[part]) return map[part];
                if (/^f([1-9]|1[0-2])$/.test(part)) return part.toUpperCase();
                if (part.length === 1) return part.toUpperCase();
                return part;
            });
            return parts.join(' + ');
        }

        function buildShortcutComboFromKeyboardEvent(ev) {
            const main = normalizeShortcutMainKey(ev && ev.key);
            if (!main) return { combo: '', error: '修飾キー単体は設定できません。' };

            const parts = [];
            if (ev && ev.ctrlKey) parts.push('ctrl');
            if (ev && ev.shiftKey) parts.push('shift');
            if (ev && ev.altKey) parts.push('alt');
            if (ev && ev.metaKey) parts.push('meta');
            parts.push(main);

            if (parts.length > 3) {
                return { combo: '', error: '同時押しは最大3キーまでです。' };
            }
            const combo = normalizeShortcutComboString(parts.join('+'));
            if (!combo) return { combo: '', error: 'このキーの組み合わせは設定できません。' };
            return { combo, error: '' };
        }

        function normalizeShortcutKeyConfig(raw) {
            const defaults = getDefaultShortcutKeyConfig();
            const src = raw && typeof raw === 'object' ? raw : {};
            const srcActions = src.actions && typeof src.actions === 'object' ? src.actions : {};
            return {
                version: 1,
                actions: {
                    timestamp: { combo: normalizeShortcutComboString(srcActions.timestamp && srcActions.timestamp.combo) || defaults.actions.timestamp.combo },
                    note: { combo: normalizeShortcutComboString(srcActions.note && srcActions.note.combo) || defaults.actions.note.combo },
                    prev_video: { combo: normalizeShortcutComboString(srcActions.prev_video && srcActions.prev_video.combo) || defaults.actions.prev_video.combo },
                    next_video: { combo: normalizeShortcutComboString(srcActions.next_video && srcActions.next_video.combo) || defaults.actions.next_video.combo }
                }
            };
        }

        function getShortcutKeyConfig() {
            try {
                const gmRaw = GM_getValue(SHORTCUT_KEY_CONFIG_KEY, null);
                if (gmRaw != null) {
                    const parsed = typeof gmRaw === 'string' ? JSON.parse(gmRaw) : gmRaw;
                    return normalizeShortcutKeyConfig(parsed);
                }
                const raw = localStorage.getItem(SHORTCUT_KEY_CONFIG_KEY);
                if (!raw) return getDefaultShortcutKeyConfig();
                const parsed = JSON.parse(raw);
                const normalized = normalizeShortcutKeyConfig(parsed);
                try { GM_setValue(SHORTCUT_KEY_CONFIG_KEY, normalized); } catch (_) {/* noop */ }
                return normalized;
            } catch (_) {
                return getDefaultShortcutKeyConfig();
            }
        }

        function saveShortcutKeyConfig(config) {
            try {
                const normalized = normalizeShortcutKeyConfig(config);
                try { GM_setValue(SHORTCUT_KEY_CONFIG_KEY, normalized); } catch (_) {/* noop */ }
                localStorage.setItem(SHORTCUT_KEY_CONFIG_KEY, JSON.stringify(normalized));
                return normalized;
            } catch (_) {
                return normalizeShortcutKeyConfig(config);
            }
        }

        function getWatchActionButtonTooltip(actionId, fallbackTitle) {
            try {
                const baseLabelMap = {
                    timestamp: t('shortcut.action.timestamp'),
                    note: t('shortcut.action.note'),
                    prev_video: t('shortcut.action.prev_video'),
                    next_video: t('shortcut.action.next_video')
                };
                const baseLabel = baseLabelMap[actionId] || fallbackTitle || '';
                const cfg = getShortcutKeyConfig();
                const combo = cfg && cfg.actions && cfg.actions[actionId] ? cfg.actions[actionId].combo : '';
                const normalizedCombo = normalizeShortcutComboString(combo);
                if (!normalizedCombo) return fallbackTitle || baseLabel;
                return `${baseLabel}(${formatShortcutComboLabel(normalizedCombo)})`;
            } catch (_) {
                return fallbackTitle || '';
            }
        }

        function shortcutEventMatchesCombo(ev, combo) {
            const expected = normalizeShortcutComboString(combo);
            if (!expected) return false;
            const built = buildShortcutComboFromKeyboardEvent(ev);
            if (!built.combo) return false;
            return built.combo === expected;
        }

        function isEditableTargetElement(el) {
            if (!el || typeof el !== 'object') return false;
            if (el.isContentEditable) return true;
            const tag = String(el.tagName || '').toLowerCase();
            if (tag === 'textarea' || tag === 'select') return true;
            if (tag === 'input') {
                const type = String(el.type || '').toLowerCase();
                if (['button', 'checkbox', 'radio', 'range', 'color', 'file', 'submit', 'reset'].includes(type)) return false;
                return true;
            }
            if (typeof el.closest === 'function') {
                const editableParent = el.closest('[contenteditable="true"], textarea, input, select');
                if (editableParent) return true;
            }
            return false;
        }

        let __vmShortcutCaptureActive = false;
        let __vmWatchShortcutKeyListenerAttached = false;

        function openShortcutCaptureModal(actionLabel) {
            return new Promise((resolve) => {
                const overlay = document.createElement('div');
                overlay.id = 'vm-shortcut-capture-overlay';
                overlay.className = 'vm-modal-overlay';

                const modal = document.createElement('div');
                modal.className = 'vm-modal-content';
                modal.style.maxWidth = '460px';
                modal.style.width = 'min(460px, 92vw)';

                const title = document.createElement('h3');
                title.textContent = `${actionLabel} のショートカット設定`;
                modal.appendChild(title);

                const msg = document.createElement('p');
                msg.textContent = '設定するキーを押してください（1〜3キーまで）';
                msg.style.margin = '0 0 8px';
                msg.style.fontSize = '13px';
                msg.style.color = '#d9d9d9';
                modal.appendChild(msg);

                const sub = document.createElement('p');
                sub.textContent = '例: P / Shift + P / Ctrl + Shift + P';
                sub.style.margin = '0 0 10px';
                sub.style.fontSize = '12px';
                sub.style.color = '#9a9a9a';
                modal.appendChild(sub);

                const preview = document.createElement('div');
                preview.textContent = '入力待ち...';
                Object.assign(preview.style, {
                    border: '1px solid #3a3a3a',
                    background: '#141414',
                    borderRadius: '8px',
                    padding: '10px 12px',
                    fontFamily: 'monospace',
                    fontSize: '13px',
                    color: '#e6e6e6',
                    marginBottom: '10px'
                });
                modal.appendChild(preview);

                const err = document.createElement('div');
                err.style.minHeight = '18px';
                err.style.fontSize = '12px';
                err.style.color = '#ff9898';
                err.style.marginBottom = '8px';
                modal.appendChild(err);

                const actions = document.createElement('div');
                actions.className = 'vm-modal-actions';
                Object.assign(actions.style, {
                    display: 'grid',
                    gridTemplateColumns: '1fr 1fr 1fr',
                    gap: '8px',
                    alignItems: 'stretch'
                });
                const cancelBtn = document.createElement('button');
                cancelBtn.className = 'vm-btn';
                cancelBtn.textContent = 'キャンセル';
                actions.appendChild(cancelBtn);
                modal.appendChild(actions);

                const close = (value) => {
                    __vmShortcutCaptureActive = false;
                    try { document.removeEventListener('keydown', onKeyDown, true); } catch (_) {/* noop */ }
                    try { overlay.remove(); } catch (_) {/* noop */ }
                    resolve(value);
                };

                const onKeyDown = (ev) => {
                    if (!ev) return;
                    if (ev.key === 'Escape') {
                        ev.preventDefault();
                        ev.stopPropagation();
                        close(null);
                        return;
                    }
                    const built = buildShortcutComboFromKeyboardEvent(ev);
                    if (!built.combo) {
                        ev.preventDefault();
                        ev.stopPropagation();
                        err.textContent = built.error || '設定できないキーです。';
                        return;
                    }
                    ev.preventDefault();
                    ev.stopPropagation();
                    err.textContent = '';
                    preview.textContent = formatShortcutComboLabel(built.combo);
                    close(built.combo);
                };

                cancelBtn.addEventListener('click', () => close(null));
                overlay.addEventListener('click', (ev) => {
                    if (ev.target === overlay) close(null);
                });

                overlay.appendChild(modal);
                document.body.appendChild(overlay);
                __vmShortcutCaptureActive = true;
                document.addEventListener('keydown', onKeyDown, true);
                cancelBtn.focus();
            });
        }

        function triggerWatchShortcutAction(actionId) {
            if (actionId === 'timestamp') {
                const timeBtn = document.getElementById('vm-mylist-add-with-time');
                if (timeBtn) {
                    timeBtn.click();
                    return true;
                }
                showToast('時計ボタンの準備中です');
                return false;
            }
            if (actionId === 'note') {
                const noteBtn = document.getElementById('vm-mylist-note-open');
                if (noteBtn) {
                    noteBtn.click();
                    return true;
                }
                openWatchNoteModalForCurrentVideo();
                return true;
            }
            if (actionId === 'next_video') {
                return vmNavigateNextVideo();
            }
            if (actionId === 'prev_video') {
                return vmNavigatePrevVideo();
            }
            return false;
        }

        function onWatchShortcutKeydown(ev) {
            try {
                if (__vmShortcutCaptureActive) return;
                if (!isWatchLikePath()) return;
                if (!ev || ev.repeat) return;
                if (isEditableTargetElement(ev.target)) return;
                // 同一eventで2回処理しないためのガード（window/document両方で発火するため）
                if (ev.__vmShortcutHandled) return;

                const cfg = getShortcutKeyConfig();
                const actions = cfg && cfg.actions ? cfg.actions : {};
                const orderedActionIds = ['timestamp', 'note', 'prev_video', 'next_video'];
                for (const actionId of orderedActionIds) {
                    const action = actions[actionId];
                    const combo = action && typeof action === 'object' ? action.combo : '';
                    if (!combo) continue;
                    if (!shortcutEventMatchesCombo(ev, combo)) continue;
                    ev.__vmShortcutHandled = true;
                    try { ev.preventDefault(); } catch (_) {/* noop */ }
                    try { ev.stopPropagation(); } catch (_) {/* noop */ }
                    try { ev.stopImmediatePropagation(); } catch (_) {/* noop */ }
                    triggerWatchShortcutAction(actionId);
                    return;
                }
            } catch (_) {/* noop */ }
        }

        function ensureWatchShortcutKeyListener() {
            if (__vmWatchShortcutKeyListenerAttached) return;
            // window の capture phase が最も早く発火する。YouTube 内蔵ホットキーが
            // document 上で stopImmediatePropagation を呼ぶケースに備えて両方に登録。
            try { window.addEventListener('keydown', onWatchShortcutKeydown, true); } catch (_) {/* noop */ }
            try { document.addEventListener('keydown', onWatchShortcutKeydown, true); } catch (_) {/* noop */ }
            __vmWatchShortcutKeyListenerAttached = true;
        }

        function getDefaultWatchButtonCustomize() {
            return {
                size: 11,
                order: ['mylistAdd', 'mylistTime', 'noteOpen', 'channelAdd', 'mylistOpen', 'channelOpen', 'folderQuick'],
                items: {
                    mylistAdd: { enabled: true, color: '#FF0000' },
                    mylistTime: { enabled: true, color: '#0B84FF' },
                    noteOpen: { enabled: true, color: '#4E5968' },
                    channelAdd: { enabled: true, color: '#065fd4' },
                    mylistOpen: { enabled: true, color: '#000000' },
                    channelOpen: { enabled: true, color: '#000000' },
                    folderQuick: { enabled: true, color: '#5a2d82' }
                }
            };
        }

        function normalizeWatchButtonCustomize(raw) {
            const defaults = getDefaultWatchButtonCustomize();
            const src = raw && typeof raw === 'object' ? raw : {};
            const defaultOrder = Array.isArray(defaults.order) ? defaults.order.slice() : Object.keys(defaults.items);
            const srcOrder = Array.isArray(src.order) ? src.order : [];
            const seenOrder = new Set();
            const nextOrder = [];
            srcOrder.forEach((key) => {
                if (!Object.prototype.hasOwnProperty.call(defaults.items, key)) return;
                if (seenOrder.has(key)) return;
                seenOrder.add(key);
                nextOrder.push(key);
            });
            defaultOrder.forEach((key) => {
                if (seenOrder.has(key)) return;
                seenOrder.add(key);
                nextOrder.push(key);
            });
            const next = {
                size: Math.min(20, Math.max(9, parseInt(src.size, 10) || defaults.size)),
                order: nextOrder,
                items: {}
            };
            Object.keys(defaults.items).forEach((key) => {
                const def = defaults.items[key];
                const cur = src.items && typeof src.items === 'object' ? (src.items[key] || {}) : {};
                const color = /^#([0-9a-f]{3}|[0-9a-f]{6})$/i.test(String(cur.color || '')) ? String(cur.color) : def.color;
                next.items[key] = {
                    enabled: cur.enabled == null ? !!def.enabled : !!cur.enabled,
                    color
                };
            });
            return next;
        }

        function getWatchButtonCustomize() {
            try {
                const gmRaw = GM_getValue(WATCH_BUTTON_CUSTOMIZE_KEY, null);
                if (gmRaw != null) {
                    const gmParsed = (typeof gmRaw === 'string') ? JSON.parse(gmRaw) : gmRaw;
                    return normalizeWatchButtonCustomize(gmParsed);
                }

                const raw = localStorage.getItem(WATCH_BUTTON_CUSTOMIZE_KEY);
                if (!raw) return getDefaultWatchButtonCustomize();
                const parsed = JSON.parse(raw);
                const normalized = normalizeWatchButtonCustomize(parsed);
                try { GM_setValue(WATCH_BUTTON_CUSTOMIZE_KEY, normalized); } catch (_) { /* noop */ }
                return normalized;
            } catch (_) {
                return getDefaultWatchButtonCustomize();
            }
        }

        function saveWatchButtonCustomize(cfg) {
            try {
                const normalized = normalizeWatchButtonCustomize(cfg);
                try { GM_setValue(WATCH_BUTTON_CUSTOMIZE_KEY, normalized); } catch (_) { /* noop */ }
                localStorage.setItem(WATCH_BUTTON_CUSTOMIZE_KEY, JSON.stringify(normalized));
                return normalized;
            } catch (_) {
                return normalizeWatchButtonCustomize(cfg);
            }
        }

