        // 同期設定管理関数（簡素化版：ON/OFFのみ）
        async function manageSyncGlobalSettings() {
            const playlistSyncData = getPlaylistSyncData();
            const { syncSettings } = playlistSyncData;

            const enabledStr = await showCustomModal({
                type: 'prompt',
                title: '自動同期設定',
                message: '自動同期を有効にしますか？\n\n※同期間隔は「フォルダ別同期設定」で個別に設定できます。',
                defaultValue: syncSettings.autoSyncEnabled ? 'yes' : 'no',
                placeholder: 'yes/no',
                okText: '保存'
            });

            if (!enabledStr) return;

            const enabled = enabledStr.toLowerCase() === 'yes';

            playlistSyncData.syncSettings = {
                ...syncSettings,
                autoSyncEnabled: enabled
            };
            savePlaylistSyncData(playlistSyncData);

            await showCustomModal({
                type: 'alert',
                title: '設定完了',
                message: `自動同期: ${enabled ? 'ON' : 'OFF'}\n\n各フォルダの同期間隔は「フォルダ別同期設定」から個別に設定してください。`
            });
        }

        async function executeManualSync() {
            showToast(t('plsync.manual.start'));

            try {
                vmSyncLog('[手動同期] 開始');
                const playlistSyncData = getPlaylistSyncData();
                vmSyncLog('[手動同期] 同期対象:', playlistSyncData.syncPlaylists);

                const result = await syncAllPlaylists(true); // 手動同期フラグをtrueに

                vmSyncLog('[手動同期] 完了:', result);

                if (result && result.totalNewVideos > 0) {
                    const successResults = result.syncResults.filter(r => r.success && r.addedCount > 0);
                    const message = successResults.map(r =>
                        `${r.folderName}: ${r.addedCount}件`
                    ).join('\n');

                    await showCustomModal({
                        type: 'alert',
                        title: t('plsync.manual.done.title'),
                        message: `${message}\n\n${t('plsync.manual.done.added').replace('{n}', String(result.totalNewVideos))}`
                    });
                } else {
                    await showCustomModal({
                        type: 'alert',
                        title: t('plsync.manual.done.title'),
                        message: t('plsync.manual.done.none')
                    });
                }

                renderMylistPage();

            } catch (error) {
                await showCustomModal({
                    type: 'alert',
                    title: t('plsync.manual.err.title'),
                    message: t('plsync.manual.err.message').replace('{msg}', error.message)
                });
            }
        }

        async function removeSyncTargets() {
            const playlistSyncData = getPlaylistSyncData();
            const { syncPlaylists } = playlistSyncData;

            const syncList = Object.entries(syncPlaylists);
            if (syncList.length === 0) {
                await showCustomModal({ type: 'alert', title: t('plsync.remove.none.title'), message: t('plsync.remove.none.message') });
                return;
            }

            let message = t('plsync.remove.select.message');
            syncList.forEach(([url, info], index) => {
                message += `${index + 1}. ${info.folderName} (${info.playlistTitle})\n`;
            });

            const choice = await showCustomModal({
                type: 'prompt',
                title: t('plsync.remove.select.title'),
                message: message,
                placeholder: t('plsync.remove.select.placeholder'),
                okText: t('common.delete')
            });

            if (!choice) return;

            const index = parseInt(choice) - 1;
            if (isNaN(index) || index < 0 || index >= syncList.length) {
                await showCustomModal({ type: 'alert', title: t('plsync.remove.invalid.title'), message: t('plsync.remove.invalid.message') });
                return;
            }

            const [url, info] = syncList[index];
            const confirmed = await showCustomModal({
                type: 'confirm',
                title: t('plsync.remove.confirm.title'),
                message: t('plsync.remove.confirm.message').replace('{folder}', info.folderName),
                okText: t('plsync.remove.confirm.ok')
            });

            if (confirmed) {
                delete playlistSyncData.syncPlaylists[url];
                savePlaylistSyncData(playlistSyncData);

                await showCustomModal({
                    type: 'alert',
                    title: t('plsync.remove.done.title'),
                    message: t('plsync.remove.done.message').replace('{folder}', info.folderName)
                });
            }
        }

        // 同期設定のフォルダ名を修正する機能
        async function fixSyncFolderNames() {
            const playlistSyncData = getPlaylistSyncData();
            const { syncPlaylists } = playlistSyncData;
            const data = getMylistData();

            const syncList = Object.entries(syncPlaylists);
            if (syncList.length === 0) {
                await showCustomModal({ type: 'alert', title: t('plsync.fix.none.title'), message: t('plsync.fix.none.message') });
                return;
            }

            let issues = [];
            syncList.forEach(([url, info]) => {
                if (!data.folders.hasOwnProperty(info.folderName)) {
                    issues.push({ url, info, folderName: info.folderName });
                }
            });

            if (issues.length === 0) {
                await showCustomModal({
                    type: 'alert',
                    title: t('plsync.fix.ok.title'),
                    message: t('plsync.fix.ok.message')
                });
                return;
            }

            // UIモーダルを作成
            await showFolderNameFixUI(issues, playlistSyncData, data);
        }

