        function getViewModeMap() {
            try {
                const modes = JSON.parse(localStorage.getItem(VIEW_MODE_KEY) || '{}');
                return (modes && typeof modes === 'object') ? modes : {};
            } catch (_) {
                return {};
            }
        }

        function saveViewModeMap(modes) {
            try {
                const next = (modes && typeof modes === 'object') ? modes : {};
                localStorage.setItem(VIEW_MODE_KEY, JSON.stringify(next));
            } catch (_) { }
        }

        function getGridItemsPerRow() {
            try {
                const gmRaw = GM_getValue(GRID_ITEMS_PER_ROW_KEY, null);
                const gmNum = parseInt(gmRaw, 10);
                if (Number.isFinite(gmNum)) return Math.min(7, Math.max(1, gmNum));
            } catch (_) { }
            try {
                const raw = parseInt(localStorage.getItem(GRID_ITEMS_PER_ROW_KEY) || '', 10);
                if (!Number.isFinite(raw)) return 5;
                return Math.min(7, Math.max(1, raw));
            } catch (_) {
                return 5;
            }
        }

        function saveGridItemsPerRow(value) {
            try {
                const num = parseInt(value, 10);
                const normalized = Math.min(7, Math.max(1, Number.isFinite(num) ? num : 5));
                try { GM_setValue(GRID_ITEMS_PER_ROW_KEY, normalized); } catch (_) { }
                localStorage.setItem(GRID_ITEMS_PER_ROW_KEY, String(normalized));
                return normalized;
            } catch (_) {
                return 5;
            }
        }

        function applyGridItemsPerRowToContainer(gridContainer) {
            if (!gridContainer) return;
            if (window.innerWidth <= 768) {
                gridContainer.style.gridTemplateColumns = '';
                gridContainer.classList.remove('dense-grid');
                delete gridContainer.dataset.vmGridCols;
                gridContainer.style.removeProperty('--vm-action-row-pad');
                gridContainer.style.removeProperty('--vm-action-gap');
                gridContainer.style.removeProperty('--vm-action-btn-pad');
                gridContainer.style.removeProperty('--vm-action-btn-radius');
                gridContainer.style.removeProperty('--vm-action-btn-font');
                return;
            }

            const desiredCols = getGridItemsPerRow();
            const minCardWidth = 220;
            const containerWidth = Math.max(0, Math.floor(gridContainer.clientWidth || gridContainer.getBoundingClientRect().width || 0));
            const maxColsByWidth = containerWidth > 0 ? Math.max(1, Math.floor(containerWidth / minCardWidth)) : desiredCols;
            const cols = Math.max(1, Math.min(desiredCols, maxColsByWidth));
            gridContainer.style.gridTemplateColumns = `repeat(${cols}, minmax(0, 1fr))`;
            gridContainer.dataset.vmGridCols = String(cols);
            gridContainer.classList.toggle('dense-grid', cols >= 7);

            let rowPad = '7px';
            let gap = '5px';
            let btnPad = '5px 6px';
            let btnRadius = '4px';
            let btnFont = '11px';
            if (cols >= 7) {
                rowPad = '5px';
                gap = '4px';
                btnPad = '3px 4px';
                btnRadius = '3px';
                btnFont = '10px';
            } else if (cols === 6) {
                rowPad = '6px';
                gap = '4px';
                btnPad = '4px 5px';
                btnRadius = '3px';
                btnFont = '10px';
            } else if (cols === 5) {
                rowPad = '6px';
                gap = '5px';
                btnPad = '5px 6px';
                btnRadius = '4px';
                btnFont = '10.5px';
            }
            gridContainer.style.setProperty('--vm-action-row-pad', rowPad);
            gridContainer.style.setProperty('--vm-action-gap', gap);
            gridContainer.style.setProperty('--vm-action-btn-pad', btnPad);
            gridContainer.style.setProperty('--vm-action-btn-radius', btnRadius);
            gridContainer.style.setProperty('--vm-action-btn-font', btnFont);
        }




        /* ---------------------------
            Toast
        --------------------------- */
        function showToast(msg, duration = 2000, pos) {
            const id = 'vm-mylist-toast';
            let toast = document.getElementById(id);
            if (toast) toast.remove();
            toast = document.createElement('div');
            toast.id = id; toast.textContent = msg;

            const point = (() => {
                try {
                    if (!pos || typeof pos !== 'object') return null;
                    const x = Number.isFinite(pos.x) ? pos.x : (Number.isFinite(pos.clientX) ? pos.clientX : null);
                    const y = Number.isFinite(pos.y) ? pos.y : (Number.isFinite(pos.clientY) ? pos.clientY : null);
                    if (!Number.isFinite(x) || !Number.isFinite(y)) return null;
                    return { x, y };
                } catch (_) { return null; }
            })();

            if (point) {
                Object.assign(toast.style, {
                    position: 'fixed', left: point.x + 'px', top: point.y + 'px',
                    bottom: 'auto', transform: 'translate(-50%, calc(-100% - 12px))',
                    padding: '12px 20px', background: 'rgba(0,0,0,0.9)', color: '#fff',
                    borderRadius: '8px', zIndex: 999999, fontSize: '15px',
                    boxShadow: '0 4px 12px rgba(0,0,0,0.5)', whiteSpace: 'pre-wrap',
                    textAlign: 'center', maxWidth: '80%', lineHeight: '1.4'
                });
            } else {
                Object.assign(toast.style, {
                    position: 'fixed', bottom: '80px', left: '50%', transform: 'translateX(-50%)',
                    padding: '12px 20px', background: 'rgba(0,0,0,0.9)', color: '#fff',
                    borderRadius: '8px', zIndex: 999999, fontSize: '15px',
                    boxShadow: '0 4px 12px rgba(0,0,0,0.5)', whiteSpace: 'pre-wrap',
                    textAlign: 'center', maxWidth: '80%', lineHeight: '1.4'
                });
            }

            document.body.appendChild(toast);

            // 画面外に出ないように補正
            if (point) {
                requestAnimationFrame(() => {
                    try {
                        if (!toast || !toast.isConnected) return;
                        const pad = 8;
                        let rect = toast.getBoundingClientRect();

                        // 上に出せない場合は下に出す
                        if (rect.top < pad) {
                            toast.style.transform = 'translate(-50%, 12px)';
                            rect = toast.getBoundingClientRect();
                        }

                        // 左右のはみ出しを補正
                        if (rect.left < pad) {
                            const dx = pad - rect.left;
                            toast.style.left = (rect.left + dx + rect.width / 2) + 'px';
                            rect = toast.getBoundingClientRect();
                        }
                        if (rect.right > window.innerWidth - pad) {
                            const dx = rect.right - (window.innerWidth - pad);
                            toast.style.left = (rect.left - dx + rect.width / 2) + 'px';
                            rect = toast.getBoundingClientRect();
                        }
                    } catch (_) {/* noop */ }
                });
            }

            setTimeout(() => toast.remove(), duration);
        }

        // ---- Undo スタック ----
        // 最大 5 操作分のスナップショットをメモリに保持する
        const __vmUndoStack = [];
        const VM_UNDO_MAX = 5;

        /**
         * Undo 用スナップショットを積む
         * @param {object} snapshot - { data: deep-copy of mylistData, label: string }
         */
        function pushUndoSnapshot(snapshot) {
            __vmUndoStack.push(snapshot);
            if (__vmUndoStack.length > VM_UNDO_MAX) __vmUndoStack.shift();
        }

        /**
         * Undo ボタン付きのトーストを表示する
         * @param {string} msg    - トースト本文
         * @param {number} duration - 表示ミリ秒
         */
        function showToastWithUndo(msg, duration = 4000) {
            const id = 'vm-mylist-toast';
            let toast = document.getElementById(id);
            if (toast) toast.remove();
            toast = document.createElement('div');
            toast.id = id;
            Object.assign(toast.style, {
                position: 'fixed', bottom: '80px', left: '50%',
                transform: 'translateX(-50%)',
                padding: '10px 16px', background: 'rgba(0,0,0,0.9)', color: '#fff',
                borderRadius: '8px', zIndex: 999999, fontSize: '14px',
                boxShadow: '0 4px 12px rgba(0,0,0,0.5)',
                display: 'flex', alignItems: 'center', gap: '12px',
                whiteSpace: 'pre-wrap', maxWidth: '80%'
            });

            const msgEl = document.createElement('span');
            msgEl.textContent = msg;
            toast.appendChild(msgEl);

            if (__vmUndoStack.length > 0) {
                const undoBtn = document.createElement('button');
                undoBtn.textContent = t('undo.btn');
                Object.assign(undoBtn.style, {
                    background: '#3ea6ff', color: '#0f0f0f', border: 'none',
                    borderRadius: '4px', padding: '4px 10px', cursor: 'pointer',
                    fontWeight: '700', fontSize: '13px', flexShrink: '0'
                });
                undoBtn.onclick = () => {
                    const snap = __vmUndoStack.pop();
                    if (!snap) return;
                    saveMylistData(snap.data);
                    toast.remove();
                    showToast(t('undo.done'), 2000);
                    renderMylistPage();
                };
                toast.appendChild(undoBtn);
            }

            document.body.appendChild(toast);
            const tid = setTimeout(() => { try { toast.remove(); } catch (_) { } }, duration);
            toast.addEventListener('click', (e) => {
                // Undo ボタン以外のクリックでは閉じない
                if (e.target === undoBtn) return;
            });
            // Undo ボタンクリック時にタイマー停止
            try {
                const undoBtn = toast.querySelector('button');
                if (undoBtn) undoBtn.addEventListener('click', () => clearTimeout(tid));
            } catch (_) { }
        }


        function secondsToIso(totalSeconds) {
            const s = parseInt(totalSeconds, 10);
            if (!Number.isFinite(s) || s <= 0) return '';
            const h = Math.floor(s / 3600);
            const m = Math.floor((s % 3600) / 60);
            const sec = s % 60;
            let iso = 'PT';
            if (h > 0) iso += `${h}H`;
            if (m > 0) iso += `${m}M`;
            iso += `${sec}S`;
            return iso;
        }

        // 動画メタデータは YouTube Data API v3 のみ（watch ページ HTML の fetch は行わない）。
        // API 未設定時は視聴ページ追加時の DOM 取得分（チャンネル名・再生時間など）と追加日のみで十分とする。
        async function getVideoDuration(videoId) {
            if (!hasUsableYouTubeApiKey()) return '';
            try {
                const key = getApiKey();
                if (key) {
                    const url = `https://www.googleapis.com/youtube/v3/videos?part=contentDetails&id=${videoId}&key=${key}&_=${Date.now()}`;
                    const res = await fetch(url, { cache: 'no-store' });
                    const js = await res.json();
                    const item = js?.items?.[0];
                    if (item) {
                        const d = item.contentDetails?.duration || '';
                        if (d) return d;
                    }
                }
            } catch (e) { }
            return '';
        }

        // ------------------------------------------------------------
        // 再生時間の後追い取得（ライブ配信終了後など、duration が空の動画に対し
        // 1時間ごとにバックグラウンドで再取得を試みる）
        // ------------------------------------------------------------
        const VM_DURATION_BACKFILL_LAST_AT_KEY = 'vm-duration-backfill-last-at-v1';
        const VM_DURATION_BACKFILL_INTERVAL_MS = 1 * 60 * 60 * 1000; // 1時間
        const VM_DURATION_BACKFILL_BATCH_LIMIT = 20;             // 1回あたり最大件数（負荷抑制）
        const VM_DURATION_BACKFILL_REQUEST_GAP_MS = 1500;        // リクエスト間隔
        let __vmDurationBackfillRunning = false;
        let __vmDurationBackfillTimer = null;

        function isMissingDurationValue(d) {
            if (d === null || d === undefined) return true;
            const s = String(d).trim();
            if (!s) return true;
            // ライブ配信中などで 'PT0S' / '0' になっていた場合も再取得対象にする
            if (s === 'PT0S' || s === '0' || s === 'P0D') return true;
            return false;
        }

        async function backfillMissingDurationsOnce({ force = false, forceReset = false } = {}) {
            if (!hasUsableYouTubeApiKey()) return { ran: false, reason: 'no-api-key' };
            if (forceReset) __vmDurationBackfillRunning = false;
            if (__vmDurationBackfillRunning) return { ran: false, reason: 'busy' };
            try {
                if (!force) {
                    const lastAt = Number(GM_getValue(VM_DURATION_BACKFILL_LAST_AT_KEY, 0)) || 0;
                    if (lastAt && (Date.now() - lastAt) < VM_DURATION_BACKFILL_INTERVAL_MS) {
                        return { ran: false, reason: 'cooldown' };
                    }
                }
            } catch (_) { }

            __vmDurationBackfillRunning = true;
            let updatedCount = 0;
            try {
                const data = getMylistData();
                if (!data || !data.folders) return { ran: false, reason: 'no-data' };

                // 重複ID排除しつつ、最初に見つかったエントリを対象にする
                const seen = new Set();
                const targets = []; // { id }
                for (const folderName of Object.keys(data.folders)) {
                    const arr = data.folders[folderName];
                    if (!Array.isArray(arr)) continue;
                    for (const v of arr) {
                        if (!v || !v.id) continue;
                        if (seen.has(v.id)) continue;
                        if (!isMissingDurationValue(v.duration)) continue;
                        seen.add(v.id);
                        targets.push({ id: v.id });
                        if (targets.length >= VM_DURATION_BACKFILL_BATCH_LIMIT) break;
                    }
                    if (targets.length >= VM_DURATION_BACKFILL_BATCH_LIMIT) break;
                }

                if (targets.length === 0) {
                    try { GM_setValue(VM_DURATION_BACKFILL_LAST_AT_KEY, Date.now()); } catch (_) { }
                    return { ran: true, updated: 0, scanned: 0 };
                }

                for (const t of targets) {
                    try {
                        const dur = await withTimeout(getVideoDuration(t.id), 8000, '');
                        if (dur && !isMissingDurationValue(dur)) {
                            // 取得直後に最新データを再取得して全フォルダにわたって更新
                            const latest = getMylistData();
                            let changed = false;
                            for (const folderName of Object.keys(latest.folders || {})) {
                                const arr = latest.folders[folderName];
                                if (!Array.isArray(arr)) continue;
                                for (const v of arr) {
                                    if (v && v.id === t.id && isMissingDurationValue(v.duration)) {
                                        v.duration = dur;
                                        changed = true;
                                    }
                                }
                            }
                            if (changed) {
                                saveMylistData(latest);
                                updatedCount++;
                            }
                        }
                    } catch (_) {/* noop */ }
                    // 連続リクエストの負荷を抑える
                    await new Promise(r => setTimeout(r, VM_DURATION_BACKFILL_REQUEST_GAP_MS));
                }

                try { GM_setValue(VM_DURATION_BACKFILL_LAST_AT_KEY, Date.now()); } catch (_) { }

                if (updatedCount > 0) {
                    try {
                        if (typeof renderMylistPage === 'function' && typeof isMylistPage === 'function' && isMylistPage()) {
                            renderMylistPage();
                        }
                        if (typeof showToast === 'function') showToast(`再生時間を ${updatedCount} 件取得しました`);
                    } catch (_) { }
                }
                return { ran: true, updated: updatedCount, scanned: targets.length };
            } finally {
                __vmDurationBackfillRunning = false;
            }
        }

        function startDurationBackfillScheduler() {
            if (!hasUsableYouTubeApiKey()) return;
            // タブ間で重複起動しないよう setInterval は単一タブで十分（複数タブでも問題は最後の保存が勝つ程度）
            if (__vmDurationBackfillTimer) return;
            // 起動直後にも1度試行（クールダウン未経過なら自動でスキップ）
            setTimeout(() => { backfillMissingDurationsOnce().catch(() => { }); }, 5000);
            __vmDurationBackfillTimer = setInterval(() => {
                backfillMissingDurationsOnce().catch(() => { });
            }, VM_DURATION_BACKFILL_INTERVAL_MS);
        }

        // ---- Helpers (top-level) ----
        async function getVideoTitle() {
            try {
                let el = document.querySelector('h1.ytd-watch-metadata') || document.querySelector('h1.title yt-formatted-string');
                let t = (el && (el.textContent || el.innerText) || '').trim();
                if (t) return t.replace(/\s*-\s*YouTube$/i, '');
            } catch (e) { }
            try {
                const og = document.querySelector('meta[property="og:title"]')?.content || '';
                if (og) return og.replace(/\s*-\s*YouTube$/i, '');
            } catch (e) { }
            try {
                const vt = window.ytInitialPlayerResponse?.videoDetails?.title || '';
                if (vt) return vt.replace(/\s*-\s*YouTube$/i, '');
            } catch (e) { }
            return document.title.replace(/\s*-\s*YouTube$/i, '').trim();
        }

        function withTimeout(promise, ms, fallback) {
            let timer;
            return Promise.race([
                promise.finally(() => clearTimeout(timer)),
                new Promise(resolve => { timer = setTimeout(() => resolve(fallback), ms); })
            ]);
        }

        // 透明なドラッグイメージを返す（Chromium系でドラッグを安定させる）
        let __vmTransparentDragImg = null;
        function getTransparentDragImage() {
            try {
                if (__vmTransparentDragImg) return __vmTransparentDragImg;
                const canvas = document.createElement('canvas');
                canvas.width = 1; canvas.height = 1;
                const ctx = canvas.getContext('2d');
                ctx.clearRect(0, 0, 1, 1);
                const img = new Image();
                img.src = canvas.toDataURL('image/png');
                __vmTransparentDragImg = img;
                return img;
            } catch (e) { return null; }
        }

        // small debounce helper
        function debounce(fn, wait = 120) {
            let t = 0; let lastArgs = null; let lastThis = null;
            return function (...args) {
                lastArgs = args; lastThis = this;
                clearTimeout(t);
                t = setTimeout(() => { fn.apply(lastThis, lastArgs); }, wait);
            };
        }

        async function getChannelInfo(videoId) {
            if (!hasUsableYouTubeApiKey()) return { channelId: '', channelTitle: '' };
            try {
                const key = getApiKey();
                if (key) {
                    const url = `https://www.googleapis.com/youtube/v3/videos?part=snippet&id=${videoId}&key=${key}&_=${Date.now()}`;
                    const res = await fetch(url, { cache: 'no-store' });
                    const js = await res.json();
                    const item = js?.items?.[0];
                    if (item) {
                        const channelId = item.snippet?.channelId || '';
                        const channelTitle = item.snippet?.channelTitle || '';
                        return { channelId, channelTitle };
                    }
                }
            } catch (e) { }
            return { channelId: '', channelTitle: '' };
        }
        async function getPublishedAt(videoId) {
            if (!hasUsableYouTubeApiKey()) return '';
            try {
                const key = getApiKey();
                if (key) {
                    const url = `https://www.googleapis.com/youtube/v3/videos?part=snippet,liveStreamingDetails&id=${videoId}&key=${key}&_=${Date.now()}`;
                    const res = await fetch(url, { cache: 'no-store' });
                    const js = await res.json();
                    const item = js?.items?.[0];
                    if (item) {
                        const live = item.liveStreamingDetails;
                        let ts = (live && live.actualStartTime) || item.snippet?.publishedAt || '';
                        if (ts) {
                            if (__lastPubVideoId && __lastPubVideoId !== videoId && __lastPubValue && __lastPubValue === ts) {
                                await new Promise(r => setTimeout(r, 200));
                                const res2 = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=snippet,liveStreamingDetails&id=${videoId}&key=${key}&_=${Date.now()}`, { cache: 'no-store' });
                                const js2 = await res2.json();
                                const item2 = js2?.items?.[0];
                                if (item2) {
                                    const live2 = item2.liveStreamingDetails;
                                    const ts2 = (live2 && live2.actualStartTime) || item2.snippet?.publishedAt || '';
                                    if (ts2) ts = ts2;
                                }
                            }
                            __lastPubVideoId = videoId;
                            __lastPubValue = ts;
                            return ts;
                        }
                    }
                }
            } catch (e) { }
            return '';
        }

        function sanitizeTitle(t) {
            if (!t) return '';
            return String(t).replace(/\s*-\s*YouTube$/i, '').trim();
        }

        // ノートの高さを行の高さにフィットさせ、残りはスクロールさせる
        function fitNoteHeightToRow(tr, td, noteEl) {
            // max-height は CSS (.note-text { max-height: 105px }) で固定しているため
            // JS による動的計算は行わない。visibility だけ解除する。
            try {
                if (noteEl) noteEl.style.visibility = '';
            } catch (_) { }
        }

        // ---- Playback time helpers (for auto note insertion) ----
        function getCurrentPlaybackSeconds() {
            try {
                const v = document.querySelector('video.html5-main-video') || document.querySelector('video');
                if (!v) return null;
                const t = Math.floor(Number(v.currentTime));
                if (!Number.isFinite(t) || t < 0) return null;
                return t;
            } catch (_) { return null; }
        }

        // ---- Playback progress tracking (last played datetime + time) ----
        function updateLastPlaybackMetaForVideoId(videoId, sec, playedAtIso) {
            try {
                if (!videoId) return false;
                const s = Math.max(0, Math.floor(Number(sec)));
                if (!Number.isFinite(s)) return false;
                const playedAt = playedAtIso || new Date().toISOString();
                const data = getMylistData();
                const folders = data && data.folders && typeof data.folders === 'object' ? data.folders : {};
                let updated = false;
                for (const [folderName, arr] of Object.entries(folders)) {
                    if (!Array.isArray(arr) || !arr.length) continue;
                    // ゴミ箱は対象外（必要なら後で変えられる）
                    if (folderName === TRASH_FOLDER_NAME) continue;
                    for (let i = 0; i < arr.length; i++) {
                        const v = arr[i];
                        if (!v || v.id !== videoId) continue;
                        const prevAt = v.lastPlayedAt || '';
                        const prevSec = Number(v.lastPlaybackSec);
                        const changed = (prevAt !== playedAt) || (!Number.isFinite(prevSec) || prevSec !== s);
                        if (changed) {
                            v.lastPlayedAt = playedAt;
                            v.lastPlaybackSec = s;
                            updated = true;
                        }
                    }
                }
                if (updated) saveMylistData(data);
                return updated;
            } catch (e) {
                return false;
            }
        }

        function setupPlaybackProgressTracking() {
            try {
                if (!isWatchLikePath()) return;
                if (location.pathname.startsWith('/shorts')) return;

                const state = window.__vmPlaybackProgressState || (window.__vmPlaybackProgressState = {
                    intervalId: null,
                    attachTimerId: null,
                    video: null,
                    videoId: null,
                    lastSavedSec: -1,
                    lastSavedAt: 0,
                    listeners: null,
                });

                const cleanupListeners = () => {
                    try {
                        if (state.listeners && state.video) {
                            const v = state.video;
                            for (const [type, fn] of Object.entries(state.listeners)) {
                                try { v.removeEventListener(type, fn); } catch (e) { }
                            }
                        }
                    } catch (e) { }
                    state.listeners = null;
                };

                const detachAll = () => {
                    cleanupListeners();
                    try { if (state.intervalId) clearInterval(state.intervalId); } catch (e) { }
                    try { if (state.attachTimerId) clearInterval(state.attachTimerId); } catch (e) { }
                    state.intervalId = null;
                    state.attachTimerId = null;
                    state.video = null;
                    state.videoId = null;
                    state.lastSavedSec = -1;
                    state.lastSavedAt = 0;
                };

                // 他ページからwatchへ来たとき、前回の残りを一旦掃除して付け直す
                detachAll();

                const getVideoIdFromUrl = () => getCurrentVideoId();

                const shouldSaveNow = (sec, reason) => {
                    const now = Date.now();
                    if (!Number.isFinite(sec) || sec <= 0) return false;
                    if (reason === 'ended' || reason === 'pause' || reason === 'visibility' || reason === 'unload') return true;
                    if (state.lastSavedAt && (now - state.lastSavedAt) < 15000) return false;
                    if (state.lastSavedSec >= 0 && Math.abs(sec - state.lastSavedSec) < 20) return false;
                    return true;
                };

                const saveProgress = (reason) => {
                    try {
                        const vid = getVideoIdFromUrl();
                        const vEl = state.video;
                        if (!vid || !vEl) return;
                        const sec = Math.floor(Number(vEl.currentTime));
                        if (!shouldSaveNow(sec, reason)) return;
                        const playedAt = new Date().toISOString();
                        const ok = updateLastPlaybackMetaForVideoId(vid, sec, playedAt);
                        if (ok) {
                            state.lastSavedSec = sec;
                            state.lastSavedAt = Date.now();
                        }
                    } catch (e) { }
                };

                const tryAttach = () => {
                    if (!isWatchLikePath()) return;
                    const vid = getVideoIdFromUrl();
                    const v = document.querySelector('video.html5-main-video') || document.querySelector('video');
                    if (!vid || !v) return;

                    const changed = (state.video !== v) || (state.videoId !== vid);
                    if (!changed) return;

                    // 切替前に一度保存
                    try { if (state.video) saveProgress('unload'); } catch (e) { }

                    cleanupListeners();
                    state.video = v;
                    state.videoId = vid;
                    state.lastSavedSec = -1;
                    state.lastSavedAt = 0;

                    const onPause = () => saveProgress('pause');
                    const onEnded = () => saveProgress('ended');
                    const onSeeked = () => saveProgress('seeked');
                    const onTimeUpdate = (() => {
                        let last = 0;
                        return () => {
                            const now = Date.now();
                            if (now - last < 2000) return;
                            last = now;
                            saveProgress('timeupdate');
                        };
                    })();

                    state.listeners = {
                        pause: onPause,
                        ended: onEnded,
                        seeked: onSeeked,
                        timeupdate: onTimeUpdate,
                    };
                    for (const [type, fn] of Object.entries(state.listeners)) {
                        try { v.addEventListener(type, fn); } catch (e) { }
                    }

                    // 初回も少し後に保存（視聴開始直後の値反映）
                    setTimeout(() => saveProgress('interval'), 5000);
                };

                state.attachTimerId = setInterval(tryAttach, 1000);
                state.intervalId = setInterval(() => saveProgress('interval'), 30000);

                const onVis = () => {
                    if (document.visibilityState !== 'visible') saveProgress('visibility');
                };
                const onBeforeUnload = () => saveProgress('unload');
                document.addEventListener('visibilitychange', onVis, true);
                window.addEventListener('beforeunload', onBeforeUnload, true);

                // detachAll は次回呼び出し時に走るので、ここではリスナーをcleanupに含める
                const prevCleanup = window.__vmPlaybackProgressCleanup;
                window.__vmPlaybackProgressCleanup = () => {
                    try { if (typeof prevCleanup === 'function') prevCleanup(); } catch (e) { }
                    try { document.removeEventListener('visibilitychange', onVis, true); } catch (e) { }
                    try { window.removeEventListener('beforeunload', onBeforeUnload, true); } catch (e) { }
                    try { detachAll(); } catch (e) { }
                };

                tryAttach();
            } catch (e) { }
        }

        function formatHms(sec) {
            const h = Math.floor(sec / 3600);
            const m = Math.floor((sec % 3600) / 60);
            const s = sec % 60;
            return h > 0 ? `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}` : `${m}:${String(s).padStart(2, '0')}`;
        }

        function upsertPlaybackTimeNote(note, sec) {
            const timeStr = formatHms(sec);
            const raw = (note == null ? '' : String(note));
            if (!raw.trim()) return timeStr;
            const lines = raw.split('\n');
            let replaced = false;
            const reLabeled = /^\s*再生位置:\s*\d{1,2}:\d{2}(?::\d{2})?\s*$/;
            const reBare = /^\s*\d{1,2}:\d{2}(?::\d{2})?\s*$/;
            for (let i = 0; i < lines.length; i++) {
                if (!replaced && (reLabeled.test(lines[i]) || reBare.test(lines[i]))) {
                    lines[i] = timeStr;
                    replaced = true;
                }
            }
            if (!replaced) {
                return raw.endsWith('\n') ? (raw + timeStr) : (raw + '\n' + timeStr);
            }
            return lines.join('\n');
        }

        // 単純に末尾へ時刻行を追記する（消さない・置換しない）
        // タイムスタンプ行の先頭に入り込んでしまった絵文字を除去するヘルパー
        // \p{Extended_Pictographic} で時計系に限らずすべての絵文字を対象にする
        function stripTimeEmoji(text) {
            try {
                return text.replace(/^[\p{Extended_Pictographic}\ufe0f]+\s*/u, '');
            } catch (_) {
                // フォールバック: u フラグ非対応環境用
                return text.replace(/^(?:⏱|⏰|⏲|⏳|⌚|⌛|📝|🕐|🕑|🕒|🕓|🕔|🕕|🕖|🕗|🕘|🕙|🕚|🕛|\ufe0f)+\s*/, '');
            }
        }

        function appendPlaybackTimeNote(note, sec) {
            const timeStr = formatHms(Math.max(0, sec | 0));
            const raw = (note == null ? '' : String(note));
            // 行単位で時計系絵文字を除去（過去のデータクリーニング）
            const cleanRaw = raw.split('\n').map(stripTimeEmoji).join('\n').trimEnd();
            if (!cleanRaw.trim()) return timeStr;
            return cleanRaw.endsWith('\n') ? (cleanRaw + timeStr) : (cleanRaw + '\n' + timeStr);
        }

        /* ---------------------------
            Add to mylist
        --------------------------- */
        function addToMylist(video, toastPos) {
            // オプションに応じて、現在の再生位置をメモ(note)に自動追記/置換
            if (AUTO_APPEND_PLAYBACK_TIME_TO_NOTE) {
                try {
                    const sec = getCurrentPlaybackSeconds();
                    if (sec != null) {
                        video.note = upsertPlaybackTimeNote(video.note || '', sec);
                    }
                } catch (_) { }
            }
            const data = getMylistData();
            const list = Array.isArray(data.folders[getDefaultFolder()]) ? data.folders[getDefaultFolder()] : [];
            if (!video.id) { showToast('動画IDが取得できません', 2000, toastPos); return; }
            if (list.some(v => v.id === video.id)) { showToast('登録済みです', 2000, toastPos); return; }
            if (!canAddVideo(data, toastPos, getDefaultFolder())) return;
            list.push(video);
            saveMylistData(data);
            showToast('登録しました', 2000, toastPos);
        }

        // 指定フォルダへ追加（サムネの追加フォルダボタン用）
        function addToMylistFolder(video, folderName, toastPos) {
            if (!video || !video.id) { showToast('動画IDが取得できません', 2000, toastPos); return; }
            const data = getMylistData();
            if (!data.folders[folderName]) {
                showToast(`フォルダ「${folderName}」が見つかりません`, 2000, toastPos);
                return;
            }
            const list = data.folders[folderName];
            if (list.some(v => v.id === video.id)) {
                showToast(`「${folderName}」に登録済みです`, 2000, toastPos);
                return;
            }
            if (!canAddVideo(data, toastPos, folderName)) return;
            list.push(Object.assign({}, video, { addedAt: video.addedAt || new Date().toISOString() }));
            saveMylistData(data);
            showToast(`「${folderName}」に登録しました`, 2000, toastPos);
        }

        /* ---------------------------
            Button insertion (watch page)
        --------------------------- */
        function styleBtn(btn, bgColor, fontSize = '11px') {
            Object.assign(btn.style, {
                margin: '2px 4px 2px 0', padding: '2px 6px', background: bgColor, color: '#fff',
                border: 'none', borderRadius: '3px', cursor: 'pointer', fontSize: fontSize,
                display: 'inline-flex', alignItems: 'center', gap: '4px', lineHeight: 'normal'
            });
        }
        // タイトル直下のボタンコンテナを確実に用意する（watchメタデータ配下を優先）
        function ensureTitleButtonsContainer() {
            let container = document.getElementById('vm-mylist-buttons');
            const metadata = document.querySelector('ytd-watch-metadata');

            // 配置先アンカー（常にタイトル外のブロックに置く）
            let anchor = null;
            if (metadata) {
                anchor = metadata.querySelector('#title')
                    || metadata.querySelector('#container > h1')
                    || metadata.querySelector('h1')
                    || metadata.querySelector('#info-strings')
                    || metadata.querySelector('#date');
            }
            if (!anchor) {
                anchor = document.querySelector('ytd-watch-metadata #title')
                    || document.querySelector('#title h1')
                    || document.querySelector('#title');
            }
            if (!anchor || !anchor.parentNode) return null;

            if (!container) {
                container = document.createElement('div');
                container.id = 'vm-mylist-buttons';
            }

            // タイトル長に依存しない左寄せ固定レイアウト
            Object.assign(container.style, {
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'flex-start',
                flexWrap: 'wrap',
                gap: '6px',
                margin: '8px 0 0 0',
                width: '100%',
                boxSizing: 'border-box'
            });

            const parent = anchor.parentNode;
            const shouldMove = !container.isConnected
                || container.parentNode !== parent
                || container.previousSibling !== anchor;
            if (shouldMove) {
                if (anchor.nextSibling) {
                    parent.insertBefore(container, anchor.nextSibling);
                } else {
                    parent.appendChild(container);
                }
            }

            return container;
        }

        function createWatchActionSvgIcon(kind) {
            const NS = 'http://www.w3.org/2000/svg';
            const svg = document.createElementNS(NS, 'svg');
            svg.setAttribute('viewBox', '0 0 24 24');
            svg.setAttribute('width', '24');
            svg.setAttribute('height', '24');
            svg.style.width = '100%';
            svg.style.height = '100%';
            svg.style.display = 'block';
            svg.style.pointerEvents = 'none';
            const stroke = 'currentColor';

            if (kind === 'clock') {
                const circle = document.createElementNS(NS, 'circle');
                circle.setAttribute('cx', '12');
                circle.setAttribute('cy', '12');
                circle.setAttribute('r', '9');
                circle.setAttribute('fill', 'none');
                circle.setAttribute('stroke', stroke);
                circle.setAttribute('stroke-width', '2');
                const hand1 = document.createElementNS(NS, 'path');
                hand1.setAttribute('d', 'M12 12V7');
                hand1.setAttribute('fill', 'none');
                hand1.setAttribute('stroke', stroke);
                hand1.setAttribute('stroke-width', '2');
                hand1.setAttribute('stroke-linecap', 'round');
                const hand2 = document.createElementNS(NS, 'path');
                hand2.setAttribute('d', 'M12 12L15 15');
                hand2.setAttribute('fill', 'none');
                hand2.setAttribute('stroke', stroke);
                hand2.setAttribute('stroke-width', '2');
                hand2.setAttribute('stroke-linecap', 'round');
                svg.appendChild(circle);
                svg.appendChild(hand1);
                svg.appendChild(hand2);
                return svg;
            }

            if (kind === 'prev_video') {
                // |◀ 前の動画
                const bar = document.createElementNS(NS, 'rect');
                bar.setAttribute('x', '4'); bar.setAttribute('y', '4');
                bar.setAttribute('width', '2.5'); bar.setAttribute('height', '16');
                bar.setAttribute('rx', '1'); bar.setAttribute('fill', stroke);
                const tri = document.createElementNS(NS, 'polygon');
                tri.setAttribute('points', '20,4 8,12 20,20');
                tri.setAttribute('fill', stroke);
                svg.appendChild(bar);
                svg.appendChild(tri);
                return svg;
            }

            if (kind === 'next_video') {
                // ▶| 次の動画
                const tri = document.createElementNS(NS, 'polygon');
                tri.setAttribute('points', '4,4 16,12 4,20');
                tri.setAttribute('fill', stroke);
                const bar = document.createElementNS(NS, 'rect');
                bar.setAttribute('x', '17.5'); bar.setAttribute('y', '4');
                bar.setAttribute('width', '2.5'); bar.setAttribute('height', '16');
                bar.setAttribute('rx', '1'); bar.setAttribute('fill', stroke);
                svg.appendChild(tri);
                svg.appendChild(bar);
                return svg;
            }

            const page = document.createElementNS(NS, 'path');
            page.setAttribute('d', 'M7 3h8l4 4v14H7z');
            page.setAttribute('fill', 'none');
            page.setAttribute('stroke', stroke);
            page.setAttribute('stroke-width', '2');
            page.setAttribute('stroke-linejoin', 'round');
            const fold = document.createElementNS(NS, 'path');
            fold.setAttribute('d', 'M15 3v5h5');
            fold.setAttribute('fill', 'none');
            fold.setAttribute('stroke', stroke);
            fold.setAttribute('stroke-width', '2');
            fold.setAttribute('stroke-linecap', 'round');
            const line1 = document.createElementNS(NS, 'path');
            line1.setAttribute('d', 'M10 12h6');
            line1.setAttribute('fill', 'none');
            line1.setAttribute('stroke', stroke);
            line1.setAttribute('stroke-width', '2');
            line1.setAttribute('stroke-linecap', 'round');
            const line2 = document.createElementNS(NS, 'path');
            line2.setAttribute('d', 'M10 16h6');
            line2.setAttribute('fill', 'none');
            line2.setAttribute('stroke', stroke);
            line2.setAttribute('stroke-width', '2');
            line2.setAttribute('stroke-linecap', 'round');
            svg.appendChild(page);
            svg.appendChild(fold);
            svg.appendChild(line1);
            svg.appendChild(line2);
            return svg;
        }

        function ensureWatchPlayerBarButtons() {
            if (!isWatchLikePath()) return;
            const controls = document.querySelector('.html5-video-player .ytp-right-controls') || document.querySelector('.ytp-right-controls');
            if (!controls) return;

            // ytp-right-controls 内の最初のYouTubeデフォルトボタン（拡張機能以外）を返す
            const getDefaultBtnAnchor = () =>
                Array.from(controls.children).find(el => !el.classList.contains('vm-ytp-watch-extra-btn')) || null;

            const applyWatchPlayerBarButtonSizing = (btn, iconKind) => {
                try {
                    if (!(btn instanceof HTMLElement)) return;
                    const isCompact = iconKind === 'clock' || iconKind === 'note' || iconKind === 'prev_video' || iconKind === 'next_video';
                    btn.style.width = isCompact ? '40px' : '';
                    btn.style.minWidth = isCompact ? '40px' : '';
                    btn.style.padding = isCompact ? '0 6px' : '';
                    const icon = btn.querySelector('svg');
                    if (icon instanceof SVGElement) {
                        icon.setAttribute('width', isCompact ? '20' : '24');
                        icon.setAttribute('height', isCompact ? '20' : '24');
                        icon.style.width = isCompact ? '20px' : '100%';
                        icon.style.height = isCompact ? '20px' : '100%';
                    }
                } catch (_) {/* noop */ }
            };

            // 拡張ボタンをデフォルトボタンの左側（手前）に挿入する共通関数
            // insertBeforeId: 指定した拡張ボタンIDの手前に挿入（順序制御用）
            const ensureRightBtn = (id, title, iconKind, insertBeforeId, onClick) => {
                let btn = document.getElementById(id);
                if (!btn) {
                    btn = document.createElement('button');
                    btn.id = id;
                    btn.type = 'button';
                    btn.className = 'ytp-button vm-ytp-watch-extra-btn';
                    btn.addEventListener('click', (ev) => {
                        ev.preventDefault();
                        ev.stopPropagation();
                        onClick(ev);
                    });
                }
                btn.title = title;
                btn.setAttribute('aria-label', title);
                btn.style.marginLeft = '';

                if (!btn.firstElementChild) {
                    btn.appendChild(createWatchActionSvgIcon(iconKind));
                }

                applyWatchPlayerBarButtonSizing(btn, iconKind);

                // 既に正しい親にいる場合も順序を保証するため位置チェック
                const anchor = insertBeforeId
                    ? (controls.querySelector(`#${insertBeforeId}`) || getDefaultBtnAnchor())
                    : getDefaultBtnAnchor();
                if (btn.parentNode !== controls || (anchor && btn.nextSibling !== anchor && btn !== anchor)) {
                    controls.insertBefore(btn, anchor);
                }
            };

            // 連続再生中のみ前/次ボタンを表示
            const playlistRaw = vmPlaybackGetItem(VM_PLAYLIST_KEY);
            let playlistIds = [];
            try { playlistIds = JSON.parse(playlistRaw || '[]'); } catch (_) {/* noop */ }
            const hasPlaylist = Array.isArray(playlistIds) && playlistIds.length > 1;

            const pbarCfg = getPlayerBarBtnConfig();

            if (hasPlaylist && pbarCfg.prevNext) {
                // 順序: [←] [→] [デフォルトボタン群...]
                ensureRightBtn('vm-ytp-prev-video', getWatchActionButtonTooltip('prev_video', '前の動画へ'), 'prev_video', 'vm-ytp-next-video', () => vmNavigatePrevVideo());
                ensureRightBtn('vm-ytp-next-video', getWatchActionButtonTooltip('next_video', '次の動画へ'), 'next_video', 'vm-ytp-mylist-add-with-time', () => vmNavigateNextVideo());
            } else {
                // 再生リストがなければボタンを削除
                const pb = document.getElementById('vm-ytp-prev-video');
                const nb = document.getElementById('vm-ytp-next-video');
                if (pb) pb.remove();
                if (nb) nb.remove();
            }

            if (pbarCfg.time) {
                ensureRightBtn('vm-ytp-mylist-add-with-time', getWatchActionButtonTooltip('timestamp', '現在の再生位置をメモに追記してマイリストに保存'), 'clock', 'vm-ytp-mylist-note-open', (ev) => {
                    const source = document.getElementById('vm-mylist-add-with-time');
                    if (source) {
                        // source.click() だと座標が 0,0 になるため、クリック座標を持った MouseEvent を作って dispatch する
                        const rect = source.getBoundingClientRect();
                        const originX = (ev && Number.isFinite(ev.clientX) && ev.clientX > 0) ? ev.clientX : (rect.left + rect.width / 2);
                        const originY = (ev && Number.isFinite(ev.clientY) && ev.clientY > 0) ? ev.clientY : (rect.top + rect.height / 2);
                        source.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true, clientX: originX, clientY: originY }));
                        return;
                    }
                    showToast('時計ボタンの準備中です');
                });
            } else {
                const tb = document.getElementById('vm-ytp-mylist-add-with-time');
                if (tb) tb.remove();
            }

            if (pbarCfg.note) {
                ensureRightBtn('vm-ytp-mylist-note-open', getWatchActionButtonTooltip('note', 'マイリストに保存されたこの動画のメモを開く'), 'note', null, () => {
                    const source = document.getElementById('vm-mylist-note-open');
                    if (source) {
                        source.click();
                        return;
                    }
                    openWatchNoteModalForCurrentVideo();
                });
            } else {
                const ob = document.getElementById('vm-ytp-mylist-note-open');
                if (ob) ob.remove();
            }
        }

        async function addCurrentChannelFromWatchPage(toastPos) {
            try {
                const videoId = getCurrentVideoId();
                let channelId = '';
                let channelTitle = '';

                let watchUcId = '', watchHandle = '';
                try {
                    const chEls = document.querySelectorAll(
                        'ytd-channel-name a[href], #owner a[href], a.yt-simple-endpoint[href*="/channel/"], a.yt-simple-endpoint[href^="/@"]'
                    );
                    for (const chEl of chEls) {
                        const href = chEl.getAttribute('href') || chEl.href || '';
                        if (!channelTitle) channelTitle = (chEl.textContent || chEl.innerText || chEl.getAttribute?.('title') || '').trim();
                        if (!watchUcId) { const m = href.match(/\/channel\/(UC[\w-]{20,})/); if (m) watchUcId = m[1]; }
                        if (!watchHandle) { const m2 = href.match(/\/@([^\/?#]+)/); if (m2) watchHandle = '@' + m2[1]; }
                        if (watchUcId && watchHandle) break;
                    }
                    channelId = watchUcId || watchHandle;
                } catch (_) {/* noop */ }

                if ((!channelId || !channelTitle) && videoId) {
                    const info = await withTimeout(getChannelInfo(videoId), 2500, { channelId: '', channelTitle: '' });
                    if (!channelId) channelId = info.channelId || '';
                    if (!channelTitle) channelTitle = info.channelTitle || '';
                }

                if (!channelId && !channelTitle) {
                    showToast(t('ch.add.infoFail'), 2500, toastPos);
                    return;
                }
                await addChannelToCustomList(channelId || '', channelTitle || channelId || '', watchUcId, watchHandle);
            } catch (_) {
                showToast(t('ch.add.failShort'), 2500, toastPos);
            }
        }

        function findMylistEntryByVideoId(videoId) {
            if (!videoId) return null;
            const data = getMylistData();
            const folders = data && data.folders ? data.folders : {};
            const ordered = Array.isArray(data && data.folderOrder) ? data.folderOrder : [];

            for (const folderName of ordered) {
                if (folderName === TRASH_FOLDER_NAME) continue;
                const list = Array.isArray(folders[folderName]) ? folders[folderName] : null;
                if (!list) continue;
                const index = list.findIndex(v => v && v.id === videoId);
                if (index > -1) {
                    return { folder: folderName, index, item: list[index] };
                }
            }

            for (const [folderName, list] of Object.entries(folders)) {
                if (folderName === TRASH_FOLDER_NAME || !Array.isArray(list)) continue;
                const index = list.findIndex(v => v && v.id === videoId);
                if (index > -1) {
                    return { folder: folderName, index, item: list[index] };
                }
            }

            return null;
        }

        function extractPlaybackSecondsFromText(text) {
            if (!text) return [];
            const raw = String(text);
            const seen = new Set();
            const times = [];
            const regex = /(\d{1,2}:\d{2}(?::\d{2})?)/g;
            let match;
            while ((match = regex.exec(raw))) {
                const t = match[1];
                const sec = durationToSecondsAny(t);
                if (!Number.isFinite(sec) || sec < 0) continue;
                const key = `${sec}-${match.index}`;
                if (seen.has(key)) continue;
                seen.add(key);
                times.push({
                    label: t,
                    seconds: Math.floor(sec),
                    index: match.index
                });
            }
            return times;
        }

        function seekWatchVideoTo(seconds) {
            if (!Number.isFinite(seconds) || seconds < 0) return;
            const sec = Math.floor(seconds);
            try {
                const video = document.querySelector('video');
                if (video) {
                    video.currentTime = sec;
                    showToast(`${formatHms(sec)}`, 1200);
                    return;
                }
            } catch (_) {/* noop */ }
            try {
                const url = new URL(location.href);
                url.searchParams.set('t', String(sec));
                location.href = url.toString();
            } catch (_) {/* noop */ }
        }

        function getWatchNoteWindowState() {
            try {
                let raw = null;
                if (typeof GM_getValue === 'function') {
                    const gm = GM_getValue(WATCH_NOTE_WINDOW_KEY, null);
                    if (gm != null) raw = gm;
                }
                if (raw == null) {
                    const ls = localStorage.getItem(WATCH_NOTE_WINDOW_KEY);
                    if (ls != null) {
                        raw = ls;
                        try { if (typeof GM_setValue === 'function') GM_setValue(WATCH_NOTE_WINDOW_KEY, raw); } catch (_) {/* noop */ }
                    }
                }
                const obj = (typeof raw === 'string') ? JSON.parse(raw) : raw;
                if (!obj || typeof obj !== 'object') return null;
                const w = parseInt(obj.width, 10);
                const h = parseInt(obj.height, 10);
                const l = parseInt(obj.left, 10);
                const t = parseInt(obj.top, 10);
                if (!Number.isFinite(w) || !Number.isFinite(h) || !Number.isFinite(l) || !Number.isFinite(t)) return null;
                return { width: w, height: h, left: l, top: t };
            } catch (_) {
                return null;
            }
        }

        function saveWatchNoteWindowState(state) {
            try {
                if (!state || typeof state !== 'object') return;
                const payload = {
                    width: Math.max(360, parseInt(state.width, 10) || 560),
                    height: Math.max(220, parseInt(state.height, 10) || 360),
                    left: parseInt(state.left, 10) || 24,
                    top: parseInt(state.top, 10) || 24
                };
                try { if (typeof GM_setValue === 'function') GM_setValue(WATCH_NOTE_WINDOW_KEY, payload); } catch (_) {/* noop */ }
                try { localStorage.setItem(WATCH_NOTE_WINDOW_KEY, JSON.stringify(payload)); } catch (_) {/* noop */ }
            } catch (_) {/* noop */ }
        }

        function normalizeWatchNoteWindowState(state) {
            const vw = Math.max(420, window.innerWidth || 1200);
            const vh = Math.max(280, window.innerHeight || 800);
            const margin = 8;
            const minW = 360;
            const minH = 220;
            const maxW = Math.max(minW, vw - margin * 2);
            const maxH = Math.max(minH, vh - margin * 2);
            const width = Math.min(maxW, Math.max(minW, parseInt(state && state.width, 10) || 560));
            const height = Math.min(maxH, Math.max(minH, parseInt(state && state.height, 10) || 360));
            const defLeft = Math.round((vw - width) / 2);
            const defTop = Math.round((vh - height) / 2);
            const left = Math.min(vw - width - margin, Math.max(margin, parseInt(state && state.left, 10) || defLeft));
            const top = Math.min(vh - height - margin, Math.max(margin, parseInt(state && state.top, 10) || defTop));
            return { width, height, left, top };
        }

        function openWatchNoteModalForCurrentVideo() {
            const videoId = getCurrentVideoId();
            if (!videoId) {
                showToast('動画IDが取得できません');
                return;
            }

            const found = findMylistEntryByVideoId(videoId);
            if (!found || !found.item) {
                showToast('この動画はマイリストに登録されていません');
                return;
            }

            const old = document.getElementById('vm-watch-note-modal');
            if (old) old.remove();

            let currentNote = (found.item.note || '');
            const autoSaveDisabled = isWatchNoteAutoSaveDisabled();
            const overlay = document.createElement('div');
            overlay.id = 'vm-watch-note-modal';
            overlay.style.cssText = [
                'position:fixed',
                'inset:0',
                'background:rgba(0,0,0,0.45)',
                'z-index:2147483647',
                'display:block'
            ].join(';');

            const panel = document.createElement('div');
            panel.id = 'vm-watch-note-panel';
            panel.style.cssText = [
                'position:fixed',
                'left:24px',
                'top:24px',
                'width:560px',
                'height:360px',
                'background:#0f0f0f',
                'color:#fff',
                'border:1px solid rgba(255,255,255,0.18)',
                'border-radius:10px',
                'box-shadow:0 12px 36px rgba(0,0,0,0.45)',
                'padding:14px',
                'box-sizing:border-box',
                'display:flex',
                'flex-direction:column',
                'gap:10px',
                'overflow:hidden',
                'user-select:none'
            ].join(';');

            const saved = getWatchNoteWindowState();
            const initialRect = normalizeWatchNoteWindowState(saved || null);
            panel.style.left = `${initialRect.left}px`;
            panel.style.top = `${initialRect.top}px`;
            panel.style.width = `${initialRect.width}px`;
            panel.style.height = `${initialRect.height}px`;

            const header = document.createElement('div');
            header.style.cssText = 'display:flex;align-items:center;justify-content:space-between;gap:8px;';
            header.style.cursor = 'move';

            const title = document.createElement('div');
            title.textContent = `メモ (${found.folder})`;
            title.style.cssText = 'font-weight:700;font-size:14px;';

            const actionRow = document.createElement('div');
            actionRow.style.cssText = 'display:flex;align-items:center;gap:8px;';

            const modeBtn = document.createElement('button');
            modeBtn.textContent = '編集';
            modeBtn.style.cssText = [
                'background:#2f2f2f',
                'color:#fff',
                'border:1px solid rgba(255,255,255,0.2)',
                'border-radius:6px',
                'padding:6px 10px',
                'cursor:pointer',
                'font-size:12px'
            ].join(';');

            const saveBtn = document.createElement('button');
            saveBtn.textContent = '保存';
            saveBtn.style.cssText = [
                'background:#1b6f3b',
                'color:#fff',
                'border:1px solid rgba(255,255,255,0.2)',
                'border-radius:6px',
                'padding:6px 10px',
                'cursor:pointer',
                'font-size:12px'
            ].join(';');

            const closeBtn = document.createElement('button');
            closeBtn.textContent = '閉じる';
            closeBtn.style.cssText = [
                'background:#2f2f2f',
                'color:#fff',
                'border:1px solid rgba(255,255,255,0.2)',
                'border-radius:6px',
                'padding:6px 10px',
                'cursor:pointer',
                'font-size:12px'
            ].join(';');

            const editor = document.createElement('textarea');
            editor.style.cssText = [
                'overflow:auto',
                'white-space:pre-wrap',
                'line-height:1.6',
                'font-size:13px',
                'background:#181818',
                'color:#fff',
                'border:1px solid rgba(255,255,255,0.1)',
                'border-radius:8px',
                'padding:10px',
                'min-height:120px',
                'flex:1 1 auto',
                'resize:none',
                'outline:none',
                'user-select:text'
            ].join(';');
            editor.placeholder = 'メモを入力';
            editor.value = currentNote;

            const memoBox = document.createElement('div');
            memoBox.style.cssText = [
                'background:#181818',
                'border:1px solid rgba(255,255,255,0.1)',
                'border-radius:8px',
                'padding:10px',
                'min-height:120px',
                'flex:1 1 auto',
                'box-sizing:border-box',
                'overflow:auto'
            ].join(';');

            editor.style.background = 'transparent';
            editor.style.border = 'none';
            editor.style.borderRadius = '0';
            editor.style.padding = '0';
            editor.style.minHeight = '100%';
            editor.style.width = '100%';
            editor.style.boxSizing = 'border-box';

            const preview = document.createElement('div');
            preview.style.cssText = [
                'padding:0',
                'font-size:13px',
                'line-height:1.6',
                'color:#fff',
                'min-height:100%',
                'white-space:pre-wrap',
                'word-break:break-word',
                'cursor:text'
            ].join(';');

            const renderNotePreview = (rawText) => {
                renderNoteWithLinks(preview, rawText || '', videoId);
            };

            let isEditMode = false;
            const setEditMode = (nextEditMode, opts = {}) => {
                isEditMode = !!nextEditMode;
                const preserveDraft = !!opts.preserveDraft;
                if (isEditMode) {
                    modeBtn.textContent = 'プレビュー';
                    preview.style.display = 'none';
                    editor.style.display = 'block';
                    if (!preserveDraft) {
                        editor.value = currentNote;
                    }
                    setTimeout(() => {
                        try {
                            editor.focus();
                            editor.setSelectionRange(editor.value.length, editor.value.length);
                        } catch (_) {/* noop */ }
                    }, 0);
                } else {
                    modeBtn.textContent = '編集';
                    editor.style.display = 'none';
                    preview.style.display = 'block';
                    const source = preserveDraft ? editor.value : currentNote;
                    renderNotePreview(source);
                }
            };

            preview.addEventListener('click', (ev) => {
                const anchor = ev && ev.target && ev.target.closest ? ev.target.closest('a') : null;
                if (anchor) {
                    ev.preventDefault();
                    ev.stopPropagation();
                    try {
                        const href = anchor.getAttribute('href') || '';
                        const u = new URL(href, location.href);
                        const t = parseInt(u.searchParams.get('t') || '0', 10);
                        if (Number.isFinite(t) && t >= 0) {
                            seekWatchVideoTo(t);
                        }
                    } catch (_) {/* noop */ }
                    return;
                }
                setEditMode(true);
            });

            memoBox.appendChild(editor);
            memoBox.appendChild(preview);
            setEditMode(false);

            const getPanelRect = () => ({
                left: parseInt(panel.style.left, 10) || 24,
                top: parseInt(panel.style.top, 10) || 24,
                width: parseInt(panel.style.width, 10) || 560,
                height: parseInt(panel.style.height, 10) || 360
            });
            const persistPanelRect = () => {
                const normalized = normalizeWatchNoteWindowState(getPanelRect());
                panel.style.left = `${normalized.left}px`;
                panel.style.top = `${normalized.top}px`;
                panel.style.width = `${normalized.width}px`;
                panel.style.height = `${normalized.height}px`;
                saveWatchNoteWindowState(normalized);
            };

            let autoSaveTimer = null;
            const AUTO_SAVE_DELAY_MS = 600;

            const clearAutoSaveTimer = () => {
                if (autoSaveTimer) {
                    clearTimeout(autoSaveTimer);
                    autoSaveTimer = null;
                }
            };

            const saveNote = (opts = {}) => {
                const silent = !!opts.silent;
                const keepEditing = !!opts.keepEditing;
                const showFailureToast = opts.showFailureToast !== false;
                const next = String(editor.value || '');
                if (next === currentNote) return true;
                const data = getMylistData();
                const updatedCount = updateVideoNoteAcrossAllFolders(data, videoId, next, { skipTrash: true });
                if (updatedCount > 0) {
                    saveMylistData(data);
                    currentNote = next;
                    renderNotePreview(currentNote);
                    if (!keepEditing) {
                        setEditMode(false);
                    }
                    if (!silent) {
                        showToast(t('note.saved'), 1200);
                    }
                    return true;
                } else {
                    if (showFailureToast) {
                        showToast(t('note.noTarget'), 1500);
                    }
                    return false;
                }
            };

            const flushAutoSave = () => {
                clearAutoSaveTimer();
                if (autoSaveDisabled) return;
                saveNote({ silent: true, keepEditing: true, showFailureToast: false });
            };

            const queueAutoSave = () => {
                if (autoSaveDisabled) return;
                clearAutoSaveTimer();
                autoSaveTimer = setTimeout(() => {
                    autoSaveTimer = null;
                    saveNote({ silent: true, keepEditing: true, showFailureToast: false });
                }, AUTO_SAVE_DELAY_MS);
            };

            let dragging = false;
            let dragOffsetX = 0;
            let dragOffsetY = 0;
            const onDragMove = (ev) => {
                if (!dragging) return;
                const rect = getPanelRect();
                const margin = 8;
                const vw = Math.max(420, window.innerWidth || 1200);
                const vh = Math.max(280, window.innerHeight || 800);
                const nextLeft = Math.max(margin, Math.min(vw - rect.width - margin, ev.clientX - dragOffsetX));
                const nextTop = Math.max(margin, Math.min(vh - rect.height - margin, ev.clientY - dragOffsetY));
                panel.style.left = `${Math.round(nextLeft)}px`;
                panel.style.top = `${Math.round(nextTop)}px`;
            };
            const onDragEnd = () => {
                if (!dragging) return;
                dragging = false;
                document.removeEventListener('mousemove', onDragMove, true);
                document.removeEventListener('mouseup', onDragEnd, true);
                persistPanelRect();
            };
            header.addEventListener('mousedown', (ev) => {
                if (ev.button !== 0) return;
                if (ev.target && ev.target.closest && ev.target.closest('button')) return;
                const rect = panel.getBoundingClientRect();
                dragging = true;
                dragOffsetX = ev.clientX - rect.left;
                dragOffsetY = ev.clientY - rect.top;
                document.addEventListener('mousemove', onDragMove, true);
                document.addEventListener('mouseup', onDragEnd, true);
                ev.preventDefault();
            });

            const resizeHandle = document.createElement('div');
            resizeHandle.style.cssText = [
                'position:absolute',
                'right:2px',
                'bottom:2px',
                'width:16px',
                'height:16px',
                'cursor:nwse-resize',
                'border-right:2px solid rgba(255,255,255,0.6)',
                'border-bottom:2px solid rgba(255,255,255,0.6)',
                'border-bottom-right-radius:6px'
            ].join(';');
            panel.appendChild(resizeHandle);

            let resizing = false;
            let startX = 0;
            let startY = 0;
            let startW = 560;
            let startH = 360;
            const onResizeMove = (ev) => {
                if (!resizing) return;
                const vw = Math.max(420, window.innerWidth || 1200);
                const vh = Math.max(280, window.innerHeight || 800);
                const left = parseInt(panel.style.left, 10) || 24;
                const top = parseInt(panel.style.top, 10) || 24;
                const minW = 360;
                const minH = 220;
                const maxW = Math.max(minW, vw - left - 8);
                const maxH = Math.max(minH, vh - top - 8);
                const nextW = Math.max(minW, Math.min(maxW, startW + (ev.clientX - startX)));
                const nextH = Math.max(minH, Math.min(maxH, startH + (ev.clientY - startY)));
                panel.style.width = `${Math.round(nextW)}px`;
                panel.style.height = `${Math.round(nextH)}px`;
            };
            const onResizeEnd = () => {
                if (!resizing) return;
                resizing = false;
                document.removeEventListener('mousemove', onResizeMove, true);
                document.removeEventListener('mouseup', onResizeEnd, true);
                persistPanelRect();
            };
            resizeHandle.addEventListener('mousedown', (ev) => {
                if (ev.button !== 0) return;
                resizing = true;
                startX = ev.clientX;
                startY = ev.clientY;
                startW = parseInt(panel.style.width, 10) || 560;
                startH = parseInt(panel.style.height, 10) || 360;
                document.addEventListener('mousemove', onResizeMove, true);
                document.addEventListener('mouseup', onResizeEnd, true);
                ev.preventDefault();
                ev.stopPropagation();
            });

            window.addEventListener('resize', persistPanelRect, { passive: true });

            header.appendChild(title);
            actionRow.appendChild(modeBtn);
            actionRow.appendChild(saveBtn);
            actionRow.appendChild(closeBtn);
            header.appendChild(actionRow);
            panel.appendChild(header);
            panel.appendChild(memoBox);
            overlay.appendChild(panel);
            document.documentElement.appendChild(overlay);

            const close = () => {
                flushAutoSave();
                persistPanelRect();
                window.removeEventListener('resize', persistPanelRect, { passive: true });
                document.removeEventListener('mousemove', onDragMove, true);
                document.removeEventListener('mouseup', onDragEnd, true);
                document.removeEventListener('mousemove', onResizeMove, true);
                document.removeEventListener('mouseup', onResizeEnd, true);
                try { overlay.remove(); } catch (_) {/* noop */ }
                document.removeEventListener('keydown', onKey, true);
            };
            const onKey = (ev) => {
                if (!ev) return;
                if ((ev.ctrlKey || ev.metaKey) && ev.key.toLowerCase() === 's') {
                    ev.preventDefault();
                    saveNote();
                    return;
                }
                if (ev.key === 'Escape') close();
            };
            editor.addEventListener('input', queueAutoSave);
            saveBtn.addEventListener('click', saveNote);
            modeBtn.addEventListener('click', () => {
                if (isEditMode) {
                    setEditMode(false, { preserveDraft: true });
                } else {
                    setEditMode(true);
                }
            });
            closeBtn.addEventListener('click', close);
            overlay.addEventListener('click', (ev) => {
                if (ev.target === overlay) close();
            });
            document.addEventListener('keydown', onKey, true);
        }

        /* フォルダクイック追加ボタン（選択されたフォルダ名を表示）の更新 */
        function updateFolderQuickBtn() {
            const container = document.getElementById('vm-mylist-buttons');
            const storedFolder = (() => { try { return GM_getValue(FOLDER_QUICK_ADD_TARGET_KEY, '') || ''; } catch (_) { return ''; } })();
            let existingBtn = document.getElementById('vm-folder-quick-btn');

            // フォルダが選択されていない、または実在しない場合はボタンを除去
            if (!storedFolder) {
                if (existingBtn) existingBtn.remove();
                return;
            }
            const dataCheck = getMylistData();
            if (!dataCheck.folders || !(storedFolder in dataCheck.folders)) {
                try { GM_setValue(FOLDER_QUICK_ADD_TARGET_KEY, ''); } catch (_) { }
                if (existingBtn) existingBtn.remove();
                return;
            }

            if (existingBtn) {
                // 既存ボタンのテキストとタイトルを更新
                const nameSpan = existingBtn.querySelector('.vm-fq-name');
                if (nameSpan) nameSpan.textContent = formatFolderDisplayName(storedFolder, null);
                existingBtn.title = `「${formatFolderDisplayName(storedFolder, null)}」に追加`;
                // SPA遅移後にコンテナから外れている場合は再挿入
                if (container && existingBtn.parentNode !== container) {
                    const folderAddEl = document.getElementById('vm-mylist-folder-add');
                    if (folderAddEl && folderAddEl.parentNode === container) {
                        container.insertBefore(existingBtn, folderAddEl.nextSibling);
                    } else {
                        container.appendChild(existingBtn);
                    }
                }
                return;
            }

            if (!container) return;

            // 新規ボタン作成
            const btn = document.createElement('button');
            btn.id = 'vm-folder-quick-btn';
            btn.title = `「${formatFolderDisplayName(storedFolder, null)}」に追加`;
            styleBtn(btn, '#5a2d82', '11px');

            const nameSpan = document.createElement('span');
            nameSpan.className = 'vm-fq-name';
            nameSpan.textContent = formatFolderDisplayName(storedFolder, null);
            nameSpan.style.pointerEvents = 'none';

            const clearSpan = document.createElement('span');
            clearSpan.textContent = '×';
            clearSpan.style.cssText = 'opacity:0.65;font-size:10px;margin-left:3px;pointer-events:auto;';
            clearSpan.addEventListener('click', (e) => {
                e.stopPropagation();
                try { GM_setValue(FOLDER_QUICK_ADD_TARGET_KEY, ''); } catch (_) { }
                btn.remove();
            });

            btn.appendChild(nameSpan);
            btn.appendChild(clearSpan);

            btn.addEventListener('click', async (ev) => {
                // クリックターゲットが clearSpan の場合はキャンセル済み
                if (ev.target === clearSpan) return;
                ev.stopPropagation();
                const toastPos = (ev && Number.isFinite(ev.clientX) && Number.isFinite(ev.clientY)) ? { x: ev.clientX, y: ev.clientY } : null;
                const target = (() => { try { return GM_getValue(FOLDER_QUICK_ADD_TARGET_KEY, '') || ''; } catch (_) { return ''; } })();
                if (!target) { btn.remove(); return; }
                const videoId = getCurrentVideoId();
                if (!videoId) { showToast('動画IDが取得できません', 2000, toastPos); return; }
                try {
                    const d = getMylistData();
                    const list = Array.isArray(d.folders[target]) ? d.folders[target] : [];
                    if (list.some(v => v && v.id === videoId)) {
                        showToast(`「${target}」に登録済です`, 2000, toastPos);
                        return;
                    }
                    const title = await withTimeout(getVideoTitle(), 1000, document.title.replace(/\s*-\s*YouTube$/i, '').trim());
                    const thumb = `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`;
                    const published = await withTimeout(getPublishedAt(videoId), 1500, '');
                    let info = await withTimeout(getChannelInfo(videoId), 3000, { channelId: '', channelTitle: '' });
                    let channelId = info.channelId || '';
                    let channelTitle = info.channelTitle || '';
                    if (!channelId) {
                        try {
                            const chEl = document.querySelector('ytd-channel-name a[href]')
                                || document.querySelector('#owner a[href]')
                                || document.querySelector('a.yt-simple-endpoint[href*="/channel/"]')
                                || document.querySelector('a.yt-simple-endpoint[href^="/@"]')
                                || document.querySelector('a.yt-simple-endpoint[href*="/c/"]')
                                || document.querySelector('a.yt-simple-endpoint[href*="/user/"]');
                            if (chEl) {
                                if (!channelTitle) channelTitle = (chEl.textContent || chEl.innerText || '').trim();
                                channelId = extractChannelRefFromUrl(chEl.getAttribute('href') || chEl.href || '') || channelId;
                            }
                        } catch (_) { }
                    }
                    const durationEl = document.querySelector('span.ytp-time-duration') || document.querySelector('.ytp-time-duration');
                    let duration = '';
                    if (durationEl) {
                        const txt = durationEl.textContent.trim();
                        if (/^\d+:\d+$/.test(txt)) {
                            const [m, s] = txt.split(':').map(Number);
                            duration = `PT${m}M${s}S`;
                        } else if (/^\d+:\d+:\d+$/.test(txt)) {
                            const [h, m, s] = txt.split(':').map(Number);
                            duration = `PT${h}H${m}M${s}S`;
                        } else { duration = txt; }
                    }
                    if (!duration) {
                        try {
                            const ls = window.ytInitialPlayerResponse?.videoDetails?.lengthSeconds;
                            if (ls) duration = secondsToIso(ls);
                        } catch (_) { }
                    }
                    // 非同期待機中に登録済みになっている場合も対応
                    const d2 = getMylistData();
                    const list2 = Array.isArray(d2.folders[target]) ? d2.folders[target] : [];
                    if (list2.some(v => v && v.id === videoId)) {
                        showToast(`「${target}」に登録済です`, 2000, toastPos);
                        return;
                    }
                    if (!Array.isArray(d2.folders[target])) d2.folders[target] = [];
                    d2.folders[target].push({ id: videoId, title, thumb, note: '', addedAt: new Date().toISOString(), publishedAt: published, duration, channelId, channelTitle });
                    saveMylistData(d2);
                    showToast(`「${target}」に登録しました`, 2000, toastPos);
                    if (!duration) {
                        getVideoDuration(videoId).then(dv => {
                            if (!dv) return;
                            const d3 = getMylistData();
                            const arr = Array.isArray(d3.folders[target]) ? d3.folders[target] : [];
                            const idx = arr.findIndex(v => v && v.id === videoId);
                            if (idx > -1) { arr[idx].duration = dv; saveMylistData(d3); }
                        });
                    }
                } catch (_) {
                    showToast('追加に失敗しました', 2000, toastPos);
                }
            });

            // folderAddBtnの直後に挿入
            const folderAddEl = document.getElementById('vm-mylist-folder-add');
            if (folderAddEl && folderAddEl.parentNode === container) {
                container.insertBefore(btn, folderAddEl.nextSibling);
            } else {
                container.appendChild(btn);
            }
        }

