        function getChannelPageUcId() {
            // ページのメタデータから UC ID を取得する（@handle と UC ID の対応解決用）
            // 複数の場所を順番に確認して最初に見つかったものを返す

            // 1. link[rel="canonical"] タグ（最も信頼性が高い）
            try {
                const canonical = document.querySelector('link[rel="canonical"]');
                if (canonical) {
                    const ucm = (canonical.getAttribute('href') || '').match(/\/channel\/(UC[^/?#]+)/);
                    if (ucm) return ucm[1];
                }
            } catch (_) { }

            // 2. ytInitialData.metadata（チャンネルページで安定して存在する）
            try {
                const externalId = window.ytInitialData &&
                    window.ytInitialData.metadata &&
                    window.ytInitialData.metadata.channelMetadataRenderer &&
                    window.ytInitialData.metadata.channelMetadataRenderer.externalId;
                if (externalId && String(externalId).startsWith('UC')) return String(externalId);
            } catch (_) { }

            // 3. ytInitialData.header（タブによって構造が異なる）
            try {
                const hdr = window.ytInitialData && window.ytInitialData.header;
                const ucId =
                    (hdr && hdr.pageHeaderRenderer && hdr.pageHeaderRenderer.channelId) ||
                    (hdr && hdr.c4TabbedHeaderRenderer && hdr.c4TabbedHeaderRenderer.channelId);
                if (ucId && String(ucId).startsWith('UC')) return String(ucId);
            } catch (_) { }

            // 4. og:url（@handle形式の場合があるためUC形式のみ使用）
            try {
                const metaUrl = document.querySelector('meta[property="og:url"]');
                if (metaUrl) {
                    const ucm = (metaUrl.getAttribute('content') || '').match(/\/channel\/(UC[^/?#]+)/);
                    if (ucm) return ucm[1];
                }
            } catch (_) { }

            // 5. DOM内の隠し属性（ytd-channel-name や yt-formatted-string の data-channel-external-id 等）
            try {
                const el = document.querySelector('[data-channel-external-id]');
                if (el) {
                    const id = el.getAttribute('data-channel-external-id') || '';
                    if (id.startsWith('UC')) return id;
                }
            } catch (_) { }

            // 6. ytInitialData のすべての browserId / browseId を探す（フォールバック）
            try {
                const browseId =
                    window.ytInitialData &&
                    window.ytInitialData.header &&
                    window.ytInitialData.header.c4TabbedHeaderRenderer &&
                    window.ytInitialData.header.c4TabbedHeaderRenderer.navigationEndpoint &&
                    window.ytInitialData.header.c4TabbedHeaderRenderer.navigationEndpoint.browseEndpoint &&
                    window.ytInitialData.header.c4TabbedHeaderRenderer.navigationEndpoint.browseEndpoint.browseId;
                if (browseId && String(browseId).startsWith('UC')) return String(browseId);
            } catch (_) { }

            return '';
        }

        function insertChannelPageAddButton() {
            if (!isChannelPage()) return;

            // チャンネルID・チャンネル名を取得
            let channelId = '';
            let channelTitle = '';
            let channelUcId = '';
            try {
                const p = String(location.pathname || '').replace(/\/+$/, '');
                const m = p.match(/^\/@([^\/]+)/) || p.match(/^\/channel\/([^\/]+)/);
                if (m) channelId = p.startsWith('/@') ? `@${m[1]}` : m[1];
                channelUcId = getChannelPageUcId();
                const nameEl = document.querySelector(
                    'ytd-page-header-renderer yt-dynamic-text-view-model, ' +
                    'yt-page-header-view-model yt-dynamic-text-view-model, ' +
                    'ytd-channel-name #text, ytd-channel-name'
                );
                if (nameEl) channelTitle = (nameEl.textContent || '').trim().split('\n')[0].trim();
            } catch (_) { }

            if (!channelId && !channelTitle) return;

            // チャンネル名要素の直後に挿入
            const titleEl =
                document.querySelector('ytd-page-header-renderer yt-dynamic-text-view-model') ||
                document.querySelector('yt-page-header-view-model yt-dynamic-text-view-model') ||
                document.querySelector('ytd-channel-name');

            if (!titleEl) return; // DOM未準備→リトライに任せる

            // 既存ボタンがある場合は状態だけ更新して返す
            const existing = document.getElementById('vm-channel-page-add-btn');
            if (existing) {
                updateChannelPageBtnState(existing, channelId, channelTitle, channelUcId);
                return;
            }

            const btn = document.createElement('button');
            btn.id = 'vm-channel-page-add-btn';
            Object.assign(btn.style, {
                display: 'inline-flex',
                alignItems: 'center',
                alignSelf: 'center',
                verticalAlign: 'middle',
                flexShrink: '0',
                flexGrow: '0',
                width: 'fit-content',
                marginLeft: '12px',
                color: '#fff',
                border: 'none',
                borderRadius: '18px',
                padding: '6px 14px',
                fontSize: '13px',
                fontWeight: '600',
                cursor: 'pointer',
                lineHeight: '1.3',
                whiteSpace: 'nowrap',
                transition: 'background 0.15s',
            });

            updateChannelPageBtnState(btn, channelId, channelTitle, channelUcId);

            btn.addEventListener('click', async () => {
                if (btn.disabled) return;
                const isRegistered = btn.dataset.vmRegistered === '1';
                if (isRegistered) {
                    // 登録解除の確認
                    const cid = btn.dataset.vmChannelId || channelId;
                    const cname = btn.dataset.vmChannelName || channelTitle;
                    const unregisterConfirmed = await showCustomModal({
                        type: 'confirm',
                        title: t('ch.unregister.confirm.title'),
                        message: t('ch.unregister.confirm').replace('{name}', cname),
                        okText: t('common.delete'),
                        cancelText: t('common.cancel')
                    });
                    if (!unregisterConfirmed) return;
                    btn.disabled = true;
                    btn.textContent = '...';
                    try {
                        const data = getChannelListData();
                        const folder = data.folders['お気に入り'];
                        const idx = folder.findIndex(ch => ch.id === cid);
                        if (idx >= 0) {
                            folder.splice(idx, 1);
                            saveChannelListData(data);
                            showToast(t('ch.unregister.success').replace('{name}', cname));
                        }
                    } catch (_) {
                        showToast(t('ch.unregister.fail'), 2500);
                    }
                    btn.disabled = false;
                    updateChannelPageBtnState(btn, channelId, channelTitle, channelUcId);
                } else {
                    // 新規登録
                    btn.disabled = true;
                    btn.textContent = '...';
                    try {
                        let ct = channelTitle;
                        try {
                            const ne = document.querySelector(
                                'ytd-page-header-renderer yt-dynamic-text-view-model, ' +
                                'yt-page-header-view-model yt-dynamic-text-view-model, ' +
                                'ytd-channel-name #text'
                            );
                            if (ne) ct = (ne.textContent || '').trim().split('\n')[0].trim() || ct;
                        } catch (_) { }
                        await addChannelToCustomList(channelUcId || channelId || '', ct || channelId || '', channelUcId, channelId.startsWith('@') ? channelId : '');
                    } catch (_) {
                        showToast(t('ch.add.failShort'), 2500);
                    }
                    btn.disabled = false;
                    updateChannelPageBtnState(btn, channelId, channelTitle, channelUcId);
                }
            });

            titleEl.insertAdjacentElement('afterend', btn);
        }

        function updateChannelPageBtnState(btn, channelId, channelTitle, channelUcId) {
            try {
                const data = getChannelListData();
                const list = data.folders['お気に入り'] || [];
                // IDフォーマットの違い（@handle vs UCxxx）を吸収するため
                // ID・UC ID・チャンネル名のいずれかに一致したエントリを登録済みとみなす
                const normTitle = channelTitle ? channelTitle.trim().replace(/\s+/g, ' ') : '';
                // channelId はURLから取得した@handle、channelUcId はページDOMから取得したUC ID
                const matchedEntry = list.find(ch => {
                    if (channelUcId && ch.ucId && ch.ucId === channelUcId) return true;
                    if (channelId && ch.handle && ch.handle === channelId) return true;
                    if (channelUcId && (ch.id === channelUcId)) return true;
                    if (channelId && (ch.id === channelId || ch.id === channelId.replace(/^@/, ''))) return true;
                    if (normTitle && ch.name && ch.name.trim().replace(/\s+/g, ' ') === normTitle) return true;
                    return false;
                });
                const isRegistered = !!matchedEntry;
                // 解除時に使う実際の ID は登録時のものを使わせる
                const resolvedId = matchedEntry ? matchedEntry.id : channelId;
                btn.dataset.vmRegistered = isRegistered ? '1' : '0';
                btn.dataset.vmChannelId = resolvedId;
                btn.dataset.vmChannelName = channelTitle;
                if (isRegistered) {
                    btn.textContent = t('ch.registered');
                    btn.title = t('ch.registered.title');
                    btn.style.background = '#2e7d32';
                    btn.onmouseenter = () => { if (!btn.disabled) { btn.style.background = '#1b5e20'; btn.textContent = t('ch.unregister.hover'); } };
                    btn.onmouseleave = () => { if (!btn.disabled) { btn.style.background = '#2e7d32'; btn.textContent = t('ch.registered'); } };
                } else {
                    btn.textContent = t('watch.btn.channelAdd');
                    btn.title = t('watch.btn.channelAdd.title');
                    btn.style.background = '#065fd4';
                    btn.onmouseenter = () => { if (!btn.disabled) btn.style.background = '#0556c0'; };
                    btn.onmouseleave = () => { if (!btn.disabled) btn.style.background = '#065fd4'; };
                }
            } catch (_) { }
        }

        function setupChannelPageAddButton() {
            if (!isChannelPage()) return;
            teardownChannelPageAddButton();
            insertChannelPageAddButton();
            // 段階的リトライ（YouTubeのDOM遅延レンダリング対策）
            // 各リトライでボタンの存在確認＋登録状態を必ず更新する
            [600, 1800, 4000].forEach(delay => {
                _channelPageBtnTimers.push(setTimeout(() => { insertChannelPageAddButton(); }, delay));
            });
            // ページ遷移直後に登録状態が正しく反映されない場合のフォールバック
            // insertChannelPageAddButton は既存ボタンがあれば updateChannelPageBtnState を呼ぶが、
            // GM_getValue が例外を投げた場合などに備えて 2.5 秒後にも状態を更新する
            _channelPageBtnTimers.push(setTimeout(() => {
                try {
                    const btn = document.getElementById('vm-channel-page-add-btn');
                    if (!btn || !isChannelPage()) return;
                    const p = String(location.pathname || '').replace(/\/+$/, '');
                    const m = p.match(/^\/@([^\/]+)/) || p.match(/^\/channel\/([^\/]+)/);
                    if (!m) return;
                    const cid = p.startsWith('/@') ? `@${m[1]}` : m[1];
                    const ucId = getChannelPageUcId();
                    updateChannelPageBtnState(btn, cid, btn.dataset.vmChannelName || cid, ucId);
                } catch (_) { }
            }, 2500));
            try {
                let _btnObserverTimer = null;
                _channelPageBtnObserver = new MutationObserver(() => {
                    // 高頻度DOM変更対策: デバウンスして500msに1回だけ処理
                    if (_btnObserverTimer) return;
                    _btnObserverTimer = setTimeout(() => {
                        _btnObserverTimer = null;
                        if (!isChannelPage()) { teardownChannelPageAddButton(); return; }
                        // ボタンがなければ再挿入のみ（重いgetChannelListDataはここで呼ばない）
                        if (!document.getElementById('vm-channel-page-add-btn')) {
                            insertChannelPageAddButton();
                        }
                    }, 500);
                });
                _channelPageBtnObserver.observe(document.body, { childList: true, subtree: true });
            } catch (_) { }
        }

        function isChannelPlaylistTabTargetPath() {
            try {
                const p = String(location.pathname || '').replace(/\/+$/, '');
                if (!p) return false;
                return /^\/@[^\/]+\/playlists$/i.test(p)
                    || /^\/channel\/[^\/]+\/playlists$/i.test(p)
                    || /^\/(c|user)\/[^\/]+\/playlists$/i.test(p);
            } catch (_) {/* noop */ }
            return false;
        }

        function isListTargetPath() {
            if (isHomeTargetPath() || isChannelListTargetPath()) return true;
            // 検索結果ページ（/results?search_query=...）
            try {
                if (String(location.pathname || '').replace(/\/+$/, '') === '/results') return true;
            } catch (_) { }
            return false;
        }

