        function extractVideoIdFromHref(href) {
            try {
                if (!href) return null;
                const url = new URL(href, location.origin);
                if (url.pathname === '/watch') {
                    return url.searchParams.get('v');
                }
                if (url.pathname.startsWith('/shorts/')) {
                    const parts = url.pathname.split('/').filter(Boolean);
                    return parts[1] || null;
                }
                if (url.pathname.startsWith('/live/')) {
                    const parts = url.pathname.split('/').filter(Boolean);
                    return parts[1] || null;
                }
            } catch (_) {
                // noop
            }
            return null;
        }

        function extractChannelRefFromUrl(urlLike) {
            try {
                const raw = String(urlLike || '').trim();
                if (!raw) return '';
                const url = new URL(raw, location.origin);
                const parts = String(url.pathname || '').split('/').filter(Boolean);
                if (parts.length < 2) return '';
                const head = String(parts[0] || '').toLowerCase();
                const tail = String(parts[1] || '').trim();
                if (!tail) return '';
                if (head === 'channel') return tail;
                if (head === '@') return `@${tail.replace(/^@/, '')}`;
                if (head === 'c' || head === 'user') return `${head}/${tail}`;
                if (parts[0].startsWith('@')) return parts[0];
            } catch (_) {
                // noop
            }
            return '';
        }

        function parseChannelFromRenderer(renderer) {
            // ucId: "UC..." 形式, handle: "@xxx" 形式（両方取得を試みる）
            try {
                const anchors = renderer.querySelectorAll(
                    'ytd-channel-name a[href], #channel-name a[href], a.yt-simple-endpoint[href^="/@"], a.yt-simple-endpoint[href*="/channel/"], a[href^="/@"], a[href*="/channel/"]'
                );
                let ucId = '', handle = '', channelTitle = '';
                for (const a of anchors) {
                    const href = String(a.getAttribute('href') || '');
                    if (!channelTitle) channelTitle = (a.textContent || a.innerText || a.getAttribute('title') || '').trim();
                    if (!ucId) {
                        const m = href.match(/\/channel\/(UC[\w-]{20,})/);
                        if (m) ucId = m[1];
                    }
                    if (!handle) {
                        const m2 = href.match(/\/@([^\/?#]+)/);
                        if (m2) handle = '@' + m2[1];
                    }
                    if (ucId && handle) break;
                }
                // 旧来の channelId 互換: ucId か handle のいずれかを返す
                const channelId = ucId || handle;
                return { ucId, handle, channelId, channelTitle };
            } catch (_) {
                return { ucId: '', handle: '', channelId: '', channelTitle: '' };
            }
        }

        function buildChannelPageUrl(channelId, channelTitle) {
            const rawId = String(channelId || '').trim();
            if (rawId) {
                if (/^https?:\/\/(www\.)?youtube\.com\//i.test(rawId)) return rawId;
                if (rawId.startsWith('/')) return `https://www.youtube.com${rawId}`;

                const id = rawId.replace(/^https?:\/\/(www\.)?youtube\.com\//i, '').replace(/^\/+/, '');

                const mChannel = id.match(/^channel\/([^/?#]+)/i);
                if (mChannel) {
                    const ch = String(mChannel[1] || '').trim();
                    if (/^UC[\w-]{20,}$/.test(ch)) return `https://www.youtube.com/channel/${ch}`;
                    return ch ? `https://www.youtube.com/@${encodeURIComponent(ch.replace(/^@/, ''))}` : '#';
                }

                if (/^UC[\w-]{20,}$/.test(id)) return `https://www.youtube.com/channel/${id}`;
                if (/^@[^/?#]+/.test(id)) return `https://www.youtube.com/${id}`;
                if (/^(c|user)\//i.test(id)) return `https://www.youtube.com/${id}`;

                return `https://www.youtube.com/@${encodeURIComponent(id.replace(/^@/, ''))}`;
            }

            const title = String(channelTitle || '').trim();
            return title ? `https://www.youtube.com/results?search_query=${encodeURIComponent(title)}` : '#';
        }

        function vmParseRelativePublishedAtToIso(text) {
            try {
                const raw = String(text || '').trim();
                if (!raw) return '';

                // Prefer explicit date formats if present
                // e.g. 2026/02/21, 2026-02-21, 2026年2月21日
                const mJp = raw.match(/(\d{4})\s*年\s*(\d{1,2})\s*月\s*(\d{1,2})\s*日/);
                if (mJp) {
                    const y = parseInt(mJp[1], 10);
                    const mo = parseInt(mJp[2], 10);
                    const d = parseInt(mJp[3], 10);
                    const dt = new Date(y, mo - 1, d);
                    if (!Number.isNaN(dt.getTime())) return dt.toISOString();
                }
                const mIso = raw.match(/(\d{4})-(\d{2})-(\d{2})/);
                if (mIso) {
                    const dt = new Date(`${mIso[1]}-${mIso[2]}-${mIso[3]}T00:00:00Z`);
                    if (!Number.isNaN(dt.getTime())) return dt.toISOString();
                }
                const mSlash = raw.match(/(\d{4})\/(\d{1,2})\/(\d{1,2})/);
                if (mSlash) {
                    const y = parseInt(mSlash[1], 10);
                    const mo = parseInt(mSlash[2], 10);
                    const d = parseInt(mSlash[3], 10);
                    const dt = new Date(y, mo - 1, d);
                    if (!Number.isNaN(dt.getTime())) return dt.toISOString();
                }

                // Japanese relative
                const now = Date.now();
                if (/一昨日/.test(raw)) return new Date(now - 2 * 24 * 60 * 60 * 1000).toISOString();
                if (/昨日/.test(raw)) return new Date(now - 1 * 24 * 60 * 60 * 1000).toISOString();
                if (/今日/.test(raw)) return new Date(now).toISOString();

                const mRelJp = raw.match(/(\d+)\s*(秒|分|時間|日|週間|週|か月|ヶ月|月|年)\s*前/);
                if (mRelJp) {
                    const n = parseInt(mRelJp[1], 10);
                    const unit = mRelJp[2];
                    const sec = (function () {
                        switch (unit) {
                            case '秒': return n;
                            case '分': return n * 60;
                            case '時間': return n * 60 * 60;
                            case '日': return n * 24 * 60 * 60;
                            case '週':
                            case '週間': return n * 7 * 24 * 60 * 60;
                            case '月':
                            case 'か月':
                            case 'ヶ月': return n * 30 * 24 * 60 * 60;
                            case '年': return n * 365 * 24 * 60 * 60;
                            default: return 0;
                        }
                    })();
                    if (sec > 0) return new Date(now - sec * 1000).toISOString();
                }

                // English relative (e.g. "3 days ago", "Streamed 2 weeks ago")
                const cleaned = raw
                    .replace(/^(Streamed|Premiered|Scheduled|Live|Watched)\s+/i, '')
                    .replace(/\s+streamed$/i, '')
                    .trim();
                const mRelEn = cleaned.match(/(\d+)\s*(second|minute|hour|day|week|month|year)s?\s*ago/i);
                if (mRelEn) {
                    const n = parseInt(mRelEn[1], 10);
                    const unit = String(mRelEn[2] || '').toLowerCase();
                    const sec = (function () {
                        switch (unit) {
                            case 'second': return n;
                            case 'minute': return n * 60;
                            case 'hour': return n * 60 * 60;
                            case 'day': return n * 24 * 60 * 60;
                            case 'week': return n * 7 * 24 * 60 * 60;
                            case 'month': return n * 30 * 24 * 60 * 60;
                            case 'year': return n * 365 * 24 * 60 * 60;
                            default: return 0;
                        }
                    })();
                    if (sec > 0) return new Date(now - sec * 1000).toISOString();
                }
            } catch (_) {/* noop */ }
            return '';
        }

        function extractDurationFromHomeCard(card) {
            try {
                if (!card || !(card instanceof HTMLElement)) return '';

                // Typical overlay: ytd-thumbnail-overlay-time-status-renderer #text
                const candidates = [
                    'ytd-thumbnail-overlay-time-status-renderer #text',
                    'ytd-thumbnail-overlay-time-status-renderer span#text',
                    'ytd-thumbnail-overlay-time-status-renderer',
                    '#overlays ytd-thumbnail-overlay-time-status-renderer #text',
                ];
                for (const sel of candidates) {
                    const el = card.querySelector(sel);
                    if (!(el instanceof HTMLElement)) continue;
                    const t = String(el.textContent || el.innerText || '').replace(/\s+/g, '').trim();
                    if (!t) continue;
                    if (/^(LIVE|ライブ)$/.test(t)) return 'P0D';
                    if (/^\d{1,2}:\d{2}(?::\d{2})?$/.test(t)) return t;
                }

                // Fallback: any overlay text matching time format
                const all = card.querySelectorAll('span, yt-formatted-string');
                for (const el of all) {
                    if (!(el instanceof HTMLElement)) continue;
                    const t = String(el.textContent || '').replace(/\s+/g, '').trim();
                    if (/^\d{1,2}:\d{2}(?::\d{2})?$/.test(t)) return t;
                    if (/^(LIVE|ライブ)$/.test(t)) return 'P0D';
                }
            } catch (_) {/* noop */ }
            return '';
        }

        function extractPublishedAtFromHomeCard(card) {
            try {
                if (!card || !(card instanceof HTMLElement)) return '';

                const metaLine = card.querySelector('#metadata-line') || card.querySelector('ytd-video-meta-block #metadata-line');
                if (metaLine && metaLine instanceof HTMLElement) {
                    const spans = Array.from(metaLine.querySelectorAll('span'))
                        .map(s => String(s.textContent || '').trim())
                        .filter(Boolean)
                        .filter(s => !/回視聴|views?/i.test(s));

                    // Pick a span that looks like a published time
                    const timeLike = spans
                        .slice()
                        .reverse()
                        .find(s => /前|ago|昨日|今日|一昨日|\d{4}[\/-]\d{1,2}[\/-]\d{1,2}|\d{4}\s*年\s*\d{1,2}\s*月\s*\d{1,2}\s*日/i.test(s));

                    const iso = vmParseRelativePublishedAtToIso(timeLike || '');
                    if (iso) return iso;
                }
            } catch (_) {/* noop */ }
            return '';
        }

        function createHomeAddButton(video) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'vm-mylist-home-add-btn';
            btn.title = 'マイリスト追加';
            btn.setAttribute('aria-label', 'マイリスト追加');
            Object.assign(btn.style, {
                width: '20px', minWidth: '20px', height: '20px',
                display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                padding: '0', margin: '0', border: 'none', borderRadius: '2px',
                background: '#FF0000', color: '#fff', cursor: 'pointer',
                lineHeight: '0', fontSize: '0', flexShrink: '0',
                boxShadow: '0 1px 3px rgba(0,0,0,0.6)', pointerEvents: 'auto'
            });

            // plus icon
            (function () {
                const NS = 'http://www.w3.org/2000/svg';
                const svg = document.createElementNS(NS, 'svg');
                svg.setAttribute('viewBox', '0 0 24 24');
                svg.setAttribute('width', '12');
                svg.setAttribute('height', '12');
                svg.style.display = 'block';
                const p = document.createElementNS(NS, 'path');
                p.setAttribute('d', 'M10 4h4v6h6v4h-6v6h-4v-6H4v-4h6z');
                p.setAttribute('fill', 'currentColor');
                svg.appendChild(p);
                btn.appendChild(svg);
            })();

            // YouTube側のキャプチャ段階クリックで遷移されるのを防ぐ（取りこぼし対策）
            const stopEarly = (e) => {
                try { e.stopPropagation(); } catch (_) {/* noop */ }
            };
            btn.addEventListener('pointerdown', stopEarly, true);
            btn.addEventListener('mousedown', stopEarly, true);

            btn.addEventListener('click', (e) => {
                try {
                    e.preventDefault();
                    e.stopPropagation();
                    if (typeof e.stopImmediatePropagation === 'function') e.stopImmediatePropagation();
                } catch (_) {/* noop */ }
                try {
                    const toastPos = (e && Number.isFinite(e.clientX) && Number.isFinite(e.clientY)) ? { x: e.clientX, y: e.clientY } : null;
                    // DOM再利用時に最新の動画情報を取得
                    const currentVideo = btn.__vmMylistVideo || video;
                    let mergedVideo = currentVideo;
                    try {
                        const infoFn = btn.__getVideoInfo;
                        if (typeof infoFn === 'function') {
                            const info = infoFn() || null;
                            if (info && typeof info === 'object') {
                                mergedVideo = Object.assign({}, currentVideo, info);
                            }
                        }
                    } catch (_) {/* noop */ }

                    const v = Object.assign({}, mergedVideo, { addedAt: new Date().toISOString(), note: (mergedVideo && mergedVideo.note) || '' });
                    addToMylist(v, toastPos);

                    // DOMから取れない/不足する場合の補完（非同期・登録自体はブロックしない）
                    try {
                        if (v && v.id) {
                            const videoId = String(v.id);

                            if (!v.publishedAt) {
                                withTimeout(getPublishedAt(videoId), 1500, '').then((pub) => {
                                    try {
                                        if (!pub) return;
                                        const d2 = getMylistData();
                                        const list = Array.isArray(d2.folders[getDefaultFolder()]) ? d2.folders[getDefaultFolder()] : [];
                                        const idx = list.findIndex(x => x && x.id === videoId);
                                        if (idx > -1) {
                                            list[idx].publishedAt = pub;
                                            saveMylistData(d2);
                                        }
                                    } catch (_) {/* noop */ }
                                });
                            }

                            if (!v.duration) {
                                withTimeout(getVideoDuration(videoId), 1500, '').then((dur) => {
                                    try {
                                        if (!dur) return;
                                        const d2 = getMylistData();
                                        const list = Array.isArray(d2.folders[getDefaultFolder()]) ? d2.folders[getDefaultFolder()] : [];
                                        const idx = list.findIndex(x => x && x.id === videoId);
                                        if (idx > -1) {
                                            list[idx].duration = dur;
                                            saveMylistData(d2);
                                        }
                                    } catch (_) {/* noop */ }
                                });
                            }

                            if (!v.channelId || !v.channelTitle) {
                                withTimeout(getChannelInfo(videoId), 1500, { channelId: '', channelTitle: '' }).then((ci) => {
                                    try {
                                        if (!ci || (!ci.channelId && !ci.channelTitle)) return;
                                        const d2 = getMylistData();
                                        const list = Array.isArray(d2.folders[getDefaultFolder()]) ? d2.folders[getDefaultFolder()] : [];
                                        const idx = list.findIndex(x => x && x.id === videoId);
                                        if (idx > -1) {
                                            if (!list[idx].channelId && ci.channelId) list[idx].channelId = ci.channelId;
                                            if (!list[idx].channelTitle && ci.channelTitle) list[idx].channelTitle = ci.channelTitle;
                                            saveMylistData(d2);
                                        }
                                    } catch (_) {/* noop */ }
                                });
                            }
                        }
                    } catch (_) {/* noop */ }
                } catch (_) {
                    showToast('追加に失敗しました');
                }
            }, true);

            // DOM再利用時に動画情報を更新できるようプロパティに保存
            try {
                btn.__vmMylistVideo = video;
            } catch (_) {/* noop */ }

            return btn;
        }

        // サムネ上の追加フォルダ指定ボタン（設定で追加したもの）
        function createHomeFolderAddButton(video, folderName, color) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'vm-mylist-home-add-btn vm-mylist-home-folder-btn';
            btn.title = `「${folderName}」に追加`;
            btn.setAttribute('aria-label', `「${folderName}」に追加`);
            btn.dataset.vmExtraFolder = folderName;
            Object.assign(btn.style, {
                width: '20px', minWidth: '20px', height: '20px',
                display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                padding: '0', marginLeft: '4px', border: 'none', borderRadius: '2px',
                background: color || '#555', color: '#fff', cursor: 'pointer',
                lineHeight: '0', fontSize: '0', flexShrink: '0',
                boxShadow: '0 1px 3px rgba(0,0,0,0.6)', pointerEvents: 'auto'
            });

            // plus icon
            (function () {
                const NS = 'http://www.w3.org/2000/svg';
                const svg = document.createElementNS(NS, 'svg');
                svg.setAttribute('viewBox', '0 0 24 24');
                svg.setAttribute('width', '12');
                svg.setAttribute('height', '12');
                svg.style.display = 'block';
                const p = document.createElementNS(NS, 'path');
                p.setAttribute('d', 'M10 4h4v6h6v4h-6v6h-4v-6H4v-4h6z');
                p.setAttribute('fill', 'currentColor');
                svg.appendChild(p);
                btn.appendChild(svg);
            })();

            const stopEarly = (e) => { try { e.stopPropagation(); } catch (_) { } };
            btn.addEventListener('pointerdown', stopEarly, true);
            btn.addEventListener('mousedown', stopEarly, true);

            btn.addEventListener('click', (e) => {
                try {
                    e.preventDefault();
                    e.stopPropagation();
                    if (typeof e.stopImmediatePropagation === 'function') e.stopImmediatePropagation();
                } catch (_) { }
                try {
                    const toastPos = (e && Number.isFinite(e.clientX) && Number.isFinite(e.clientY)) ? { x: e.clientX, y: e.clientY } : null;
                    const currentVideo = btn.__vmMylistVideo || video;
                    let mergedVideo = currentVideo;
                    try {
                        const infoFn = btn.__getVideoInfo;
                        if (typeof infoFn === 'function') {
                            const info = infoFn() || null;
                            if (info && typeof info === 'object') mergedVideo = Object.assign({}, currentVideo, info);
                        }
                    } catch (_) { }
                    const v = Object.assign({}, mergedVideo, { addedAt: new Date().toISOString(), note: (mergedVideo && mergedVideo.note) || '' });
                    // 指定フォルダに追加
                    addToMylistFolder(v, folderName, toastPos);
                } catch (_) {
                    showToast('追加に失敗しました');
                }
            }, true);

            try { btn.__vmMylistVideo = video; } catch (_) { }
            return btn;
        }

        function isChannelAlreadyRegistered(ucId, handle, channelTitle) {
            try {
                const data = getChannelListData();
                const list = data.folders['お気に入り'];
                const normName = channelTitle ? channelTitle.trim().replace(/\s+/g, ' ') : '';
                return list.some(ch => {
                    // 新形式: ch.ucId / ch.handle フィールドで照合
                    if (ucId && ch.ucId && ch.ucId === ucId) return true;
                    if (handle && ch.handle && ch.handle === handle) return true;
                    // 旧形式互換: ch.id に UC ID か handle が直接入っているケース
                    if (ucId && ch.id === ucId) return true;
                    if (handle && (ch.id === handle || ch.id === handle.replace(/^@/, ''))) return true;
                    // 名前照合（フォールバック）
                    if (normName && ch.name && ch.name.trim().replace(/\s+/g, ' ') === normName) return true;
                    return false;
                });
            } catch (_) { return false; }
        }

        function createHomeChannelAddButton(ucId, handle, channelTitle) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'vm-channel-add-home-btn';
            const titleStr = channelTitle ? t('ch.add.success').replace('{name}', channelTitle).replace('登録しました。', '登録') : t('ch.add.noInfo');
            btn.title = titleStr;
            btn.setAttribute('aria-label', titleStr);
            try {
                btn.dataset.vmChannelUcId = ucId || '';
                btn.dataset.vmChannelHandle = handle || '';
                btn.dataset.vmChannelTitle = channelTitle || '';
            } catch (_) {/* noop */ }

            // 既登録チャンネルは最初から ✓ で表示
            if (isChannelAlreadyRegistered(ucId, handle, channelTitle)) {
                btn.textContent = '✓';
                btn.dataset.vmAdded = '1';
                btn.disabled = true;
            } else {
                btn.textContent = 'ch+';
            }

            const stopEarly = (e) => { try { e.stopPropagation(); } catch (_) { } };
            btn.addEventListener('pointerdown', stopEarly, true);
            btn.addEventListener('mousedown', stopEarly, true);

            btn.addEventListener('click', async (e) => {
                try {
                    e.preventDefault();
                    e.stopPropagation();
                    if (typeof e.stopImmediatePropagation === 'function') e.stopImmediatePropagation();
                } catch (_) { }
                try {
                    const cUcId = (btn.dataset && btn.dataset.vmChannelUcId) || ucId || '';
                    const cHandle = (btn.dataset && btn.dataset.vmChannelHandle) || handle || '';
                    const cName = (btn.dataset && btn.dataset.vmChannelTitle) || channelTitle || cUcId || cHandle || '';
                    if (!cUcId && !cHandle && !cName) {
                        showToast(t('ch.add.noInfo'));
                        return;
                    }
                    await addChannelToCustomList(cUcId || cHandle, cName, cUcId, cHandle);
                    try { btn.dataset.vmAdded = '1'; btn.textContent = '✓'; btn.disabled = true; } catch (_) { }
                } catch (_) {
                    showToast(t('ch.add.fail'));
                }
            }, true);
            return btn;
        }

        function tryAttachHomeChannelAddButtonToRenderer(renderer) {
            try {
                if (!renderer || renderer.nodeType !== 1) return false;
                // チャンネルカード自体（ytd-channel-renderer 等）には付けない
                const tag = (renderer.tagName || '').toUpperCase();
                if (tag === 'YTD-CHANNEL-RENDERER') return false;

                // 外側ラッパ ytd-rich-item-renderer は内部に別の renderer を持つので
                // 内部 renderer 側に処理を任せ、外側はスキップ（重複挿入を防ぐ）
                if (tag === 'YTD-RICH-ITEM-RENDERER') {
                    if (renderer.querySelector('ytd-rich-grid-media, ytd-rich-grid-slim-media, ytd-video-renderer, ytd-grid-video-renderer, ytd-compact-video-renderer, yt-lockup-view-model')) return false;
                }

                // 処理済みマーカー（renderer 自体に付与して重複を防ぐ）
                if (renderer.dataset.vmChAttached === '1') return false;

                const { ucId, handle, channelId, channelTitle } = parseChannelFromRenderer(renderer);
                if (!channelId && !channelTitle) return false;

                // 可視判定ヘルパー: 親が display:none などで描画されない要素は除外
                const isVisible = (el) => {
                    try {
                        if (!el) return false;
                        if (el.offsetParent !== null) return true;
                        // position:fixed の場合 offsetParent は null だが visible のことがある
                        const rect = el.getClientRects && el.getClientRects();
                        return !!(rect && rect.length > 0);
                    } catch (_) { return false; }
                };

                // チャンネル名アンカー候補を全て列挙し、可視な最初の要素を採用
                let chAnchor = null;
                const candidates = renderer.querySelectorAll(
                    'ytd-channel-name a[href], #channel-name a[href], a.yt-simple-endpoint[href^="/@"], a.yt-simple-endpoint[href*="/channel/"], a[href^="/@"], a[href*="/channel/"]'
                );
                for (const a of candidates) {
                    if (isVisible(a)) { chAnchor = a; break; }
                }
                if (!chAnchor) return false;

                // 挿入先: ytd-channel-name または #channel-name の「前の兄弟」として挿入する。
                const chNameBlock = chAnchor.closest('ytd-channel-name')
                    || chAnchor.closest('[id="channel-name"]')
                    || chAnchor.parentElement;
                const insertParent = chNameBlock ? chNameBlock.parentElement : null;

                // chNameBlock 単位での重複防止: 既に同じチャンネル名ブロックに ch+ が付いていればスキップ
                if (chNameBlock && chNameBlock.dataset && chNameBlock.dataset.vmChMarked === '1') {
                    renderer.dataset.vmChAttached = '1';
                    return false;
                }
                // 既に直前に vm-channel-add-inline-slot がある場合もスキップ（DOM 直接チェック）
                if (chNameBlock && chNameBlock.previousElementSibling && chNameBlock.previousElementSibling.classList && chNameBlock.previousElementSibling.classList.contains('vm-channel-add-inline-slot')) {
                    renderer.dataset.vmChAttached = '1';
                    if (chNameBlock.dataset) chNameBlock.dataset.vmChMarked = '1';
                    return false;
                }

                const slot = document.createElement('span');
                slot.className = 'vm-channel-add-inline-slot vm-channel-name-prefix';
                const btn = createHomeChannelAddButton(ucId, handle, channelTitle);
                slot.appendChild(btn);

                let inserted = false;
                // 第1優先: ytd-channel-name の「前」に挿入 → ch+(チャンネル名)
                //   チャンネル名が長くて overflow:hidden で切られても ch+ は常に見える
                if (insertParent && chNameBlock && insertParent.contains(chNameBlock)) {
                    try { insertParent.insertBefore(slot, chNameBlock); inserted = true; } catch (_) { }
                }
                // フォールバック: チャンネル名アンカーの前
                if (!inserted) {
                    try {
                        const ap = chAnchor.parentElement;
                        if (ap && ap.contains(chAnchor)) { ap.insertBefore(slot, chAnchor); inserted = true; }
                    } catch (_) { }
                }
                if (!inserted) return false;

                renderer.dataset.vmChAttached = '1';
                if (chNameBlock && chNameBlock.dataset) chNameBlock.dataset.vmChMarked = '1';
                return true;
            } catch (_) { }
            return false;
        }

        function getHomeCardFromTitleAnchor(titleAnchor) {
            try {
                if (!titleAnchor) return null;
                return titleAnchor.closest('ytd-rich-item-renderer, ytd-rich-grid-media, ytd-rich-grid-slim-media, ytd-video-renderer, ytd-grid-video-renderer, ytd-compact-video-renderer, yt-lockup-view-model');
            } catch (_) {
                return null;
            }
        }

        function isWatchRightSidebarTitleAnchor(titleAnchor) {
            try {
                if (!titleAnchor || !isWatchLikePath()) return false;
                return !!titleAnchor.closest('#related, #secondary, #secondary-inner, ytd-watch-next-secondary-results-renderer');
            } catch (_) {
                return false;
            }
        }

        function tryAttachHomeAddButtonToTitleAnchor(titleAnchor) {
            try {
                if (!titleAnchor || titleAnchor.nodeType !== 1) return false;
                if (isWatchRightSidebarTitleAnchor(titleAnchor)) return false;
                const card = getHomeCardFromTitleAnchor(titleAnchor);
                if (!card) return false;

                ensureHomeAddButtonStyles();

                const hrefRaw = String((titleAnchor instanceof HTMLAnchorElement ? (titleAnchor.getAttribute('href') || titleAnchor.href) : '') || '').trim();
                let videoId = extractVideoIdFromHref(hrefRaw);
                if (!videoId) {
                    const watchA = card.querySelector('a#thumbnail[href], a[href*="watch?v="], a[href^="/shorts/"], a[href^="/live/"]');
                    if (watchA) {
                        const href2 = String(watchA.getAttribute('href') || watchA.href || '').trim();
                        videoId = extractVideoIdFromHref(href2);
                    }
                }
                if (!videoId) return false;

                const rawTitle = (titleAnchor.getAttribute('title') || titleAnchor.textContent || '').trim();
                const title = sanitizeTitle(rawTitle) || sanitizeTitle(document.title);
                const { channelId, channelTitle } = parseChannelFromRenderer(card); // channelId = ucId || handle
                const publishedAt = extractPublishedAtFromHomeCard(card);
                const duration = extractDurationFromHomeCard(card);
                const video = {
                    id: videoId,
                    title,
                    thumb: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
                    note: '',
                    publishedAt: publishedAt || '',
                    duration: duration || '',
                    channelId: channelId || '',
                    channelTitle: channelTitle || ''
                };

                // 既にボタンがある場合は情報だけ更新（DOM再利用対策）
                // スロットは <a> の直後の兄弟要素として挿入（overflow:hidden による非表示を回避）
                const _findSlot = (anchor) => {
                    const sib = anchor.nextElementSibling;
                    if (sib && sib.classList.contains('vm-mylist-inline-slot')) return sib;
                    // 後方互換: <a> 内部にある古い形式も検索
                    return anchor.querySelector(':scope > .vm-mylist-inline-slot') || null;
                };
                const existingSlot = _findSlot(titleAnchor);
                const existingBtn = existingSlot?.querySelector('.vm-mylist-home-add-btn');
                if (existingBtn) {
                    try { existingBtn.__vmMylistVideo = video; } catch (_) {/* noop */ }
                    try {
                        if (existingSlot) {
                            existingSlot.querySelectorAll('.vm-mylist-home-folder-btn').forEach(b => { b.__vmMylistVideo = video; });
                        }
                    } catch (_) {/* noop */ }
                    return false;
                }

                // 古い内部スロットがあれば削除
                titleAnchor.querySelector(':scope > .vm-mylist-inline-slot')?.remove();

                let slot = _findSlot(titleAnchor);
                if (!slot) {
                    slot = document.createElement('span');
                    slot.className = 'vm-mylist-inline-slot';
                    // <a> の直後（兄弟）に挿入することでoverflow:hiddenを回避
                    titleAnchor.insertAdjacentElement('afterend', slot);
                }

                const btn = createHomeAddButton(video);
                while (slot.firstChild) slot.removeChild(slot.firstChild);
                slot.appendChild(btn);
                // 追加フォルダボタンも並べる
                try {
                    const extraList = getThumbExtraFolderBtns();
                    extraList.forEach(entry => {
                        if (entry && entry.folder) slot.appendChild(createHomeFolderAddButton(video, entry.folder, entry.color));
                    });
                } catch (_) {/* noop */ }
                return true;
            } catch (_) {/* noop */ }
            return false;
        }

        function getHomeRenderers(root) {
            try {
                const sel = [
                    'ytd-rich-item-renderer',
                    'ytd-rich-grid-media',
                    'ytd-rich-grid-slim-media',
                    'ytd-video-renderer',
                    'ytd-grid-video-renderer',
                    'ytd-compact-video-renderer',
                    'yt-lockup-view-model'
                ].join(', ');
                return Array.from(root.querySelectorAll ? root.querySelectorAll(sel) : []);
            } catch (_) {
                return [];
            }
        }

        function getThumbnailHostFromRenderer(renderer) {
            try {
                if (!renderer) return null;
                // ytd-thumbnail そのものは避け、外側の #thumbnail へ寄せる
                let host = renderer.querySelector('a#thumbnail') || renderer.querySelector('#thumbnail');

                // 取れない場合: watchリンクから「サムネっぽい」アンカーを探す
                if (!host) {
                    const anchors = renderer.querySelectorAll('a[href*="watch?v="], a[href^="/shorts/"], a[href^="/live/"]');
                    for (const a of anchors) {
                        if (!(a instanceof HTMLElement)) continue;
                        if (a.id === 'thumbnail') { host = a; break; }
                        try {
                            if (a.querySelector && a.querySelector('ytd-thumbnail, img')) {
                                host = a;
                                break;
                            }
                        } catch (_) {/* noop */ }
                    }
                }

                // それでも無ければカード全体（#dismissible）に置く
                if (!host) {
                    host = renderer.querySelector('#dismissible') || null;
                }

                if (host && host instanceof HTMLElement && host.tagName === 'YTD-THUMBNAIL') {
                    host = host.closest('a#thumbnail, #thumbnail') || host.parentElement;
                }
                if (!(host instanceof HTMLElement)) return null;
                return host;
            } catch (_) {
                return null;
            }
        }

        function getVideoIdFromRenderer(renderer) {
            try {
                if (!renderer) return null;
                const a = renderer.querySelector('a[href*="watch?v="], a[href^="/shorts/"], a[href^="/live/"]');
                if (!a) return null;
                const hrefRaw = String(a.getAttribute('href') || a.href || '').trim();
                return extractVideoIdFromHref(hrefRaw);
            } catch (_) {
                return null;
            }
        }

        function tryAttachHomeAddButtonToRenderer(renderer) {
            try {
                if (!renderer || renderer.nodeType !== 1) return { thumb: false, title: false };

                const videoId = getVideoIdFromRenderer(renderer);
                if (!videoId) return { thumb: false, title: false };

                const titleEl = renderer.querySelector('a#video-title')
                    || renderer.querySelector('a#video-title-link')
                    || renderer.querySelector('yt-formatted-string#video-title')
                    || renderer.querySelector('a[title][href*="watch?v="]')
                    || renderer.querySelector('a.yt-lockup-metadata-view-model-wiz__title[href]');
                const rawTitle = (titleEl && (titleEl.getAttribute?.('title') || titleEl.textContent || titleEl.innerText) || '').trim();
                const title = sanitizeTitle(rawTitle) || sanitizeTitle(document.title);
                const { channelId, channelTitle } = parseChannelFromRenderer(renderer); // channelId = ucId || handle
                const publishedAt = extractPublishedAtFromHomeCard(renderer);
                const duration = extractDurationFromHomeCard(renderer);
                const video = {
                    id: videoId,
                    title,
                    thumb: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
                    note: '',
                    publishedAt: publishedAt || '',
                    duration: duration || '',
                    channelId: channelId || '',
                    channelTitle: channelTitle || ''
                };

                ensureHomeAddButtonStyles();

                // サムネ左下に＋ボタンは表示しない（既存の注入があれば削除のみ）
                let attachedThumb = false;
                const thumbHost = getThumbnailHostFromRenderer(renderer);
                if (thumbHost && thumbHost instanceof HTMLElement) {
                    let host = thumbHost;
                    if (host.tagName === 'YTD-THUMBNAIL') {
                        host = host.closest('a#thumbnail, #thumbnail') || host.parentElement || host;
                    }
                    if (host instanceof HTMLElement && ['IMG', 'INPUT'].includes(host.tagName)) {
                        host = host.parentElement;
                    }
                    if (host && host instanceof HTMLElement) {
                        const slot = host.querySelector('.vm-mylist-thumb-slot');
                        if (slot) slot.remove();
                        if (host.classList.contains('vm-mylist-thumb-host') && !host.querySelector('.vm-mylist-thumb-slot')) {
                            host.classList.remove('vm-mylist-thumb-host');
                        }
                    }
                }

                // タイトル末尾に＋ボタンを表示
                let attachedTitle = false;
                let titleAnchor = null;
                if (titleEl && titleEl instanceof HTMLElement) {
                    titleAnchor = (titleEl instanceof HTMLAnchorElement)
                        ? titleEl
                        : (titleEl.closest && titleEl.closest('a[href]'))
                        || titleEl.querySelector?.('a[href]')
                        || null;
                }
                if (!titleAnchor) {
                    const anchorCandidates = Array.from(renderer.querySelectorAll('a[href*="watch?v="], a[href^="/shorts/"], a[href^="/live/"]'));
                    titleAnchor = anchorCandidates.find(a => {
                        if (!(a instanceof HTMLElement)) return false;
                        if (a.id === 'thumbnail') return false;
                        try {
                            if (a.querySelector('ytd-thumbnail, img, yt-image')) return false;
                        } catch (_) {/* noop */ }
                        return true;
                    }) || null;
                }
                if (titleAnchor && titleAnchor instanceof HTMLElement) {
                    if (tryAttachHomeAddButtonToTitleAnchor(titleAnchor)) attachedTitle = true;
                }

                // 何も付けられなかった場合は次のスキャンで再挑戦したいのでフラグは立てない
                if ((attachedThumb || attachedTitle) && renderer.dataset) {
                    renderer.dataset.vmMylistHomeAttached = '1';
                }
                return { thumb: attachedThumb, title: attachedTitle };
            } catch (_) {
                return { thumb: false, title: false };
            }
        }

        function scanAndAttachHomeAddButtons(root = document) {
            try {
                let renderers = getHomeRenderers(root);

                // open shadow root 配下も探索（必要時のみ）
                if (renderers.length === 0 && root === document) {
                    try {
                        renderers = vmDeepQueryAll('ytd-rich-item-renderer, ytd-rich-grid-media, ytd-rich-grid-slim-media, ytd-video-renderer, ytd-grid-video-renderer, ytd-compact-video-renderer, yt-lockup-view-model', document);
                    } catch (_) { renderers = []; }
                }

                let attachedThumb = 0;
                let attachedTitle = 0;
                let attachedChannel = 0;
                let hostFound = 0;
                for (const r of renderers) {
                    try { if (getThumbnailHostFromRenderer(r)) hostFound++; } catch (_) {/* noop */ }
                    const res = tryAttachHomeAddButtonToRenderer(r);
                    if (res.thumb) attachedThumb++;
                    if (res.title) attachedTitle++;
                    try { if (tryAttachHomeChannelAddButtonToRenderer(r)) attachedChannel++; } catch (_) {/* noop */ }
                }

                if (root === document && !vmHomeScanLoggedOnce) {
                    vmHomeScanLoggedOnce = true;
                    vmHomeLog('scan', { renderers: renderers.length, hostFound, attachedThumb, attachedTitle, attachedChannel });
                } else if (root === document && (attachedThumb > 0 || attachedTitle > 0 || attachedChannel > 0)) {
                    vmHomeDebug('scan attach', { attachedThumb, attachedTitle, attachedChannel });
                }
            } catch (_) {/* noop */ }
        }

        function setupHomeAddButtons() {
            // 対象一覧ページ（ホーム + チャンネルの動画/ライブ）だけで有効化
            if (!isListTargetPath()) return;

            // 一度だけ現状をログ（コンソールフィルタ用）
            try {
                const hrefNow = String(location.href || '');
                if (hrefNow && hrefNow !== vmHomeLoggedForHref) {
                    vmHomeLoggedForHref = hrefNow;
                    let n = 0;
                    try { n = document.querySelectorAll('a#thumbnail').length; } catch (_) { n = -1; }
                    vmHomeLog('setup list-page buttons', { path: location.pathname, thumbnails: n });
                }
            } catch (_) {/* noop */ }

            // throttle用の変数
            let homeScheduled = false;
            let homeLastRunAt = 0;
            const HOME_MIN_INTERVAL_MS = 250;

            const scheduleHomeScan = (reason) => {
                if (homeScheduled) return;
                homeScheduled = true;

                requestAnimationFrame(() => {
                    homeScheduled = false;
                    const now = Date.now();
                    if (now - homeLastRunAt < HOME_MIN_INTERVAL_MS) {
                        setTimeout(() => scheduleHomeScan('throttled'), HOME_MIN_INTERVAL_MS);
                        return;
                    }
                    homeLastRunAt = now;
                    vmHomeDebug('scheduleHomeScan', reason);
                    try {
                        scanAndAttachHomeAddButtons(document);
                    } catch (err) {
                        vmHomeDebug('scheduleHomeScan error', err);
                    }
                });
            };

            // timer (initial load)
            if (vmHomeTimer) clearInterval(vmHomeTimer);
            let tries = 0;
            vmHomeTimer = setInterval(() => {
                scheduleHomeScan('timer');
                tries++;
                if (tries >= 20) { clearInterval(vmHomeTimer); vmHomeTimer = null; }
            }, 1200);

            // observer (infinite scroll)
            try {
                if (vmHomeObserver) vmHomeObserver.disconnect();
                vmHomeObserver = new MutationObserver((mutations) => {
                    if (!isListTargetPath()) return;
                    for (const m of mutations) {
                        if (m.type === 'childList') {
                            scheduleHomeScan('mutation:childList');
                            return;
                        }
                    }
                });
                vmHomeObserver.observe(document.body, { childList: true, subtree: true });
            } catch (_) {/* noop */ }
        }

        function teardownHomeAddButtons() {
            try {
                if (vmHomeObserver) {
                    vmHomeObserver.disconnect();
                    vmHomeObserver = null;
                }
                if (vmHomeTimer) {
                    clearInterval(vmHomeTimer);
                    vmHomeTimer = null;
                }
            } catch (_) {/* noop */ }
        }

        // DOM上のホームボタンスロットを全削除し、再スキャンを強制する（設定変更時に呼ぶ）
        function refreshHomeAddButtonSlots() {
            try {
                // inline-slot / ch+ slot / right-slot をすべて削除
                document.querySelectorAll('.vm-mylist-inline-slot, .vm-channel-add-inline-slot, .' + VM_RIGHT_SLOT_CLASS).forEach(el => el.remove());
                // ホームボタン付与済みマーカーをリセット
                document.querySelectorAll('[data-vm-mylist-home-attached]').forEach(el => {
                    delete el.dataset.vmMylistHomeAttached;
                });
                // ch+ボタン付与済みマーカーをリセット
                document.querySelectorAll('[data-vm-ch-attached]').forEach(el => {
                    delete el.dataset.vmChAttached;
                });
                // チャンネル名ブロックのマーカーもリセット
                document.querySelectorAll('[data-vm-ch-marked]').forEach(el => {
                    delete el.dataset.vmChMarked;
                });
                // 視聴ページ右マーカーをリセット
                document.querySelectorAll('[data-vm-mylist-right-attached]').forEach(el => {
                    try { delete el.dataset[VM_RIGHT_DATA_ATTACHED]; } catch (_) { }
                });
            } catch (_) {/* noop */ }
            try {
                if (isListTargetPath()) scanAndAttachHomeAddButtons(document);
            } catch (_) {/* noop */ }
            try {
                if (isWatchLikePath()) addWatchRightTitleButtons();
            } catch (_) {/* noop */ }
        }

        function updatePlaylistCardImportButtonState(btn, playlistUrl) {
            if (!btn) return;
            const busy = btn.dataset.vmBusy === '1';
            const imported = (() => {
                try {
                    const normalized = normalizeYouTubePlaylistUrl(playlistUrl);
                    if (!normalized || !/[?&]list=/.test(normalized)) return false;
                    const data = getMylistData();
                    const sourceMap = data?.folderSourceUrlByFolder || {};
                    if (Object.values(sourceMap).some((url) => normalizeYouTubePlaylistUrl(url) === normalized)) return true;
                    const playlistSyncData = getPlaylistSyncData();
                    const syncPlaylists = playlistSyncData?.syncPlaylists || {};
                    return Object.keys(syncPlaylists).some((url) => normalizeYouTubePlaylistUrl(url) === normalized);
                } catch (_) {/* noop */ }
                return false;
            })();

            if (!isPremiumUser()) {
                btn.disabled = true;
                btn.textContent = '+';
                btn.title = t('limit.playlist_import');
                btn.style.background = '#888';
                btn.style.cursor = 'default';
                btn.style.opacity = '0.5';
                return;
            }

            if (busy) {
                btn.disabled = true;
                btn.textContent = '…';
                btn.title = 'インポート中';
                btn.style.background = '#666';
                btn.style.cursor = 'wait';
                return;
            }

            if (imported) {
                btn.disabled = true;
                btn.textContent = '✓';
                btn.title = '追加済み';
                btn.style.background = '#2e7d32';
                btn.style.cursor = 'default';
                btn.style.opacity = '0.95';
                return;
            }

            btn.disabled = false;
            btn.textContent = '+';
            btn.title = 'この再生リストをインポート';
            btn.style.background = '#ff0000';
            btn.style.cursor = 'pointer';
            btn.style.opacity = '1';
        }

        function attachImportButtonToPlaylistCard(card) {
            try {
                if (!(card instanceof HTMLElement)) return false;

                const links = Array.from(card.querySelectorAll('a[href*="/playlist?list="], a[href*="&list="]'));
                if (!links.length) return false;

                const targetLink = links.find((a) => /再生リストの全体を見る/.test((a.textContent || '').trim()))
                    || links.find((a) => (a.id || '') !== 'thumbnail')
                    || links[0];
                if (!targetLink) return false;

                const hrefRaw = String(targetLink.getAttribute('href') || targetLink.href || '').trim();
                if (!hrefRaw) return false;
                const playlistUrl = normalizeYouTubePlaylistUrl(new URL(hrefRaw, location.origin).href);
                if (!playlistUrl || !/[?&]list=/.test(playlistUrl)) return false;

                let btn = card.querySelector(':scope .vm-playlist-card-import-btn');
                if (!btn) {
                    btn = document.createElement('button');
                    btn.className = 'vm-playlist-card-import-btn';
                    Object.assign(btn.style, {
                        display: 'inline-flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        marginLeft: '8px',
                        minWidth: '22px',
                        height: '22px',
                        borderRadius: '999px',
                        border: 'none',
                        color: '#fff',
                        fontSize: '15px',
                        fontWeight: '700',
                        lineHeight: '1',
                        padding: '0 7px',
                        verticalAlign: 'middle'
                    });
                    btn.addEventListener('click', async (ev) => {
                        ev.preventDefault();
                        ev.stopPropagation();
                        const url = btn.dataset.vmPlaylistUrl || '';
                        if (!url) return;
                        if (btn.dataset.vmBusy === '1') return;
                        btn.dataset.vmBusy = '1';
                        updatePlaylistCardImportButtonState(btn, url);
                        try {
                            const ok = await importPlaylistFromUrlFlow(url);
                            if (ok) {
                                showToast('再生リストを追加しました');
                            }
                        } finally {
                            btn.dataset.vmBusy = '0';
                            updatePlaylistCardImportButtonState(btn, url);
                        }
                    });
                }

                btn.dataset.vmPlaylistUrl = playlistUrl;
                updatePlaylistCardImportButtonState(btn, playlistUrl);

                if (btn.parentNode !== targetLink.parentNode) {
                    targetLink.insertAdjacentElement('afterend', btn);
                }
                return true;
            } catch (_) {/* noop */ }
            return false;
        }

        function scanAndAttachChannelPlaylistImportButtons(root = document) {
            try {
                const cards = Array.from((root.querySelectorAll ? root.querySelectorAll('ytd-grid-playlist-renderer, ytd-rich-grid-media, yt-lockup-view-model') : []));
                let attached = 0;
                cards.forEach((card) => {
                    if (attachImportButtonToPlaylistCard(card)) attached++;
                });
                if (root === document && attached > 0) {
                    vmHomeDebug('playlist-tab attach', { attached });
                }
            } catch (_) {/* noop */ }
        }

        function setupChannelPlaylistImportButtons() {
            if (!isChannelPlaylistTabTargetPath()) return;

            let scheduled = false;
            let lastRunAt = 0;
            const MIN_INTERVAL_MS = 250;

            const scheduleScan = () => {
                if (scheduled) return;
                scheduled = true;
                requestAnimationFrame(() => {
                    scheduled = false;
                    const now = Date.now();
                    if (now - lastRunAt < MIN_INTERVAL_MS) {
                        setTimeout(scheduleScan, MIN_INTERVAL_MS);
                        return;
                    }
                    lastRunAt = now;
                    scanAndAttachChannelPlaylistImportButtons(document);
                });
            };

            scheduleScan();

            if (vmChannelPlaylistTimer) clearInterval(vmChannelPlaylistTimer);
            let tries = 0;
            vmChannelPlaylistTimer = setInterval(() => {
                if (!isChannelPlaylistTabTargetPath()) return;
                scheduleScan();
                tries++;
                if (tries >= 20) {
                    clearInterval(vmChannelPlaylistTimer);
                    vmChannelPlaylistTimer = null;
                }
            }, 1200);

            try {
                if (vmChannelPlaylistObserver) vmChannelPlaylistObserver.disconnect();
                vmChannelPlaylistObserver = new MutationObserver((mutations) => {
                    if (!isChannelPlaylistTabTargetPath()) return;
                    for (const mutation of mutations) {
                        if (mutation.type === 'childList') {
                            scheduleScan();
                            return;
                        }
                    }
                });
                vmChannelPlaylistObserver.observe(document.body, { childList: true, subtree: true });
            } catch (_) {/* noop */ }
        }

        function teardownChannelPlaylistImportButtons() {
            try {
                if (vmChannelPlaylistObserver) {
                    vmChannelPlaylistObserver.disconnect();
                    vmChannelPlaylistObserver = null;
                }
                if (vmChannelPlaylistTimer) {
                    clearInterval(vmChannelPlaylistTimer);
                    vmChannelPlaylistTimer = null;
                }
            } catch (_) {/* noop */ }
        }

        // ---------------------------
        //    Watch right side buttons
        // ---------------------------
        let vmRightObserver = null;
        let vmRightScheduled = false;
        let vmRightLastRunAt = 0;
        let vmRightLastHref = '';
        const VM_RIGHT_MIN_INTERVAL_MS = 250;

        function createButton(video, getVideoInfo) {
            const btn = createHomeAddButton(video);
            btn.classList.add(VM_RIGHT_BTN_CLASS);
            try {
                btn.__getVideoInfo = typeof getVideoInfo === 'function' ? getVideoInfo : (() => video);
            } catch (_) {/* noop */ }
            return btn;
        }

        function addWatchRightTitleButtons() {
            try {
                if (!isWatchLikePath()) return { attached: 0, updated: 0, found: 0 };
                if (location.pathname.startsWith('/shorts')) return { attached: 0, updated: 0, found: 0 };

                ensureHomeAddButtonStyles();

                const rootSelectors = [
                    '#related',
                    '#secondary',
                    '#secondary-inner',
                    'ytd-watch-next-secondary-results-renderer'
                ];

                const roots = [];
                const rootSeen = new Set();
                for (const sel of rootSelectors) {
                    const el = document.querySelector(sel);
                    if (el && !rootSeen.has(el)) {
                        rootSeen.add(el);
                        roots.push(el);
                    }
                }

                const anchorSelector = [
                    'a#video-title[href*="watch?v="]',
                    'a#video-title-link[href*="watch?v="]',
                    'h3 a[href*="watch?v="]'
                ].join(', ');

                let attached = 0;
                let updated = 0;
                let found = 0;

                for (const root of roots) {
                    const anchors = root.querySelectorAll(anchorSelector);
                    for (const anchor of anchors) {
                        if (!(anchor instanceof HTMLAnchorElement)) continue;
                        found++;

                        try {
                            // スロットは <a> の内側または直後の兄弟に存在する場合がある
                            anchor.querySelector(':scope > .vm-mylist-inline-slot')?.remove();
                            const sib = anchor.nextElementSibling;
                            if (sib && sib.classList.contains('vm-mylist-inline-slot')) sib.remove();
                        } catch (_) {/* noop */ }

                        const hrefRaw = String(anchor.getAttribute('href') || anchor.href || '').trim();
                        if (!hrefRaw.includes('watch?v=')) continue;

                        const url = hrefRaw.startsWith('/') ? (new URL(hrefRaw, window.location.origin)).href : hrefRaw;
                        const videoId = extractVideoIdFromHref(url);
                        if (!videoId) continue;

                        const renderer = anchor.closest(
                            'ytd-compact-video-renderer, ytd-compact-radio-renderer, ytd-compact-movie-renderer, ytd-video-renderer, ytd-playlist-panel-video-renderer, ytd-rich-item-renderer'
                        );
                        const ch = (renderer && renderer instanceof HTMLElement)
                            ? parseChannelFromRenderer(renderer)
                            : { channelId: '', channelTitle: '' };

                        const publishedAt = (renderer && renderer instanceof HTMLElement) ? extractPublishedAtFromHomeCard(renderer) : '';
                        const duration = (renderer && renderer instanceof HTMLElement) ? extractDurationFromHomeCard(renderer) : '';

                        const titleText = String(anchor.getAttribute('title') || anchor.textContent || '').trim();
                        const video = {
                            id: videoId,
                            title: titleText || sanitizeTitle(document.title),
                            thumb: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
                            note: '',
                            publishedAt: publishedAt || '',
                            duration: duration || '',
                            channelId: ch.channelId || '',  // ucId || handle
                            channelTitle: ch.channelTitle || ''
                        };

                        // idempotent 判定（button + data marker の両方）
                        // スロットは <a> の直後の兄弟要素として挿入（overflow:hidden 回避）
                        const _findRightSlot = (a) => {
                            const sib = a.nextElementSibling;
                            if (sib && sib.classList.contains(VM_RIGHT_SLOT_CLASS)) return sib;
                            return a.querySelector(`:scope > .${VM_RIGHT_SLOT_CLASS}`) || null;
                        };
                        const hasMarker = anchor.dataset && anchor.dataset[VM_RIGHT_DATA_ATTACHED] === '1';
                        const existingRightSlot = _findRightSlot(anchor);
                        const existingBtn = existingRightSlot?.querySelector(`.${VM_RIGHT_BTN_CLASS}`);
                        if (existingBtn && existingBtn instanceof HTMLElement) {
                            try {
                                existingBtn.__vmMylistVideo = video;
                                existingBtn.__getVideoInfo = () => video;
                            } catch (_) {/* noop */ }
                            if (anchor.dataset) anchor.dataset[VM_RIGHT_DATA_ATTACHED] = '1';
                            updated++;
                            continue;
                        }
                        if (hasMarker && !existingBtn) {
                            if (anchor.dataset) delete anchor.dataset[VM_RIGHT_DATA_ATTACHED];
                        }

                        // 古い内部スロットを削除
                        anchor.querySelector(`:scope > .${VM_RIGHT_SLOT_CLASS}`)?.remove();

                        // 専用slotを <a> の直後の兄弟として挿入（overflow:hidden 回避）
                        let slot = _findRightSlot(anchor);
                        if (!(slot instanceof HTMLElement)) {
                            slot = document.createElement('span');
                            slot.className = VM_RIGHT_SLOT_CLASS;
                            anchor.insertAdjacentElement('afterend', slot);
                        }

                        const btn = createButton(video, () => video);
                        while (slot.firstChild) slot.removeChild(slot.firstChild);
                        slot.appendChild(btn);
                        // 追加フォルダボタン
                        try {
                            const extraList = getThumbExtraFolderBtns();
                            extraList.forEach(entry => {
                                if (entry && entry.folder) slot.appendChild(createHomeFolderAddButton(video, entry.folder, entry.color));
                            });
                        } catch (_) {/* noop */ }
                        if (anchor.dataset) anchor.dataset[VM_RIGHT_DATA_ATTACHED] = '1';
                        attached++;
                    }
                }

                if (attached === 0) {
                    vmRightLogOnce('warn', `watch-right-zero:${location.href}`,
                        'watch-right attached 0',
                        {
                            hasRelated: !!document.querySelector('#related'),
                            hasSecondary: !!document.querySelector('#secondary'),
                            hasSecondaryInner: !!document.querySelector('#secondary-inner'),
                            hasWatchNext: !!document.querySelector('ytd-watch-next-secondary-results-renderer'),
                            watchLinksInRight: roots.reduce((n, r) => n + (r.querySelectorAll ? r.querySelectorAll('a[href*="watch?v="]').length : 0), 0),
                            titleAnchorsFound: found
                        }
                    );
                }

                return { attached, updated, found };
            } catch (e) {
                vmRightLogOnce('error', `watch-right-error:${location.href}`, 'watch-right error', e);
                return { attached: 0, updated: 0, found: 0 };
            }
        }

        function addHomeListButtons() {
            try { scanAndAttachHomeAddButtons(document); } catch (_) {/* noop */ }
        }

        function scheduleCheck(reason) {
            if (vmRightScheduled) return;
            vmRightScheduled = true;
            requestAnimationFrame(() => {
                vmRightScheduled = false;
                const now = Date.now();

                if (now - vmRightLastRunAt < VM_RIGHT_MIN_INTERVAL_MS) {
                    setTimeout(() => scheduleCheck('throttled'), VM_RIGHT_MIN_INTERVAL_MS);
                    return;
                }
                vmRightLastRunAt = now;

                const hrefNow = String(location.href || '');
                if (hrefNow !== vmRightLastHref) {
                    vmRightLastHref = hrefNow;
                }

                addWatchRightTitleButtons();
            });
        }

        function observePage() {
            try {
                if (vmRightObserver) vmRightObserver.disconnect();
                vmRightObserver = new MutationObserver((mutationsList) => {
                    for (const mutation of mutationsList) {
                        if (mutation.type === 'childList') {
                            scheduleCheck('mutation:childList');
                            return;
                        }
                        if (mutation.type === 'attributes') {
                            const attr = mutation.attributeName;
                            if (attr !== 'src' && attr !== 'style' && attr !== 'class' && attr !== 'href') continue;
                            scheduleCheck(`mutation:attr:${attr}`);
                            return;
                        }
                    }
                });
                vmRightObserver.observe(document.body, {
                    childList: true,
                    subtree: true,
                    attributes: true,
                    attributeFilter: ['src', 'style', 'class', 'href']
                });
            } catch (e) {
                vmRightLogOnce('error', 'watch-right-observer-error', 'watch-right observer error', e);
            }
        }

        function setupWatchRightAddButtons() {
            if (!isWatchLikePath()) return;
            if (location.pathname.startsWith('/shorts')) return;

            ensureHomeAddButtonStyles();
            vmRightLastHref = String(location.href || '');

            setTimeout(() => scheduleCheck('initial-delayed'), 900);
            scheduleCheck('initial');
            observePage();
        }

        function teardownWatchRightAddButtons() {
            try {
                if (vmRightObserver) {
                    vmRightObserver.disconnect();
                    vmRightObserver = null;
                }
                vmRightScheduled = false;
            } catch (_) {/* noop */ }
        }

        function scanAndAttachWatchRightAddButtons() {
            scheduleCheck('legacy-call');
        }

        // ---------------------------
        //    Continuous playback
        // ---------------------------
        // グローバルにフルスクリーン状態を管理するフラグ
        let __vmIsFullscreen = false;
        // 動画の元のサイズを保持する変数
        let __vmOriginalVideoSize = { width: 0, height: 0 };
        const VM_PLAYLIST_KEY = 'vm-playlist';
        const VM_PLAY_INDEX_KEY = 'vm-play-index';
        const VM_PLAYLIST_META_KEY = 'vm-playlist-meta';
        const VM_PLAY_LOOP_KEY = 'vm-play-loop-enabled';
        const VM_PLAY_STOP_KEY = 'vm-play-stop-enabled';

        function vmPlaybackGetItem(key) {
            let value = null;
            try {
                if (typeof GM_getValue === 'function') {
                    const gmValue = GM_getValue(key, null);
                    if (gmValue !== null && typeof gmValue !== 'undefined') {
                        value = String(gmValue);
                    }
                }
            } catch (_) {/* noop */ }

            if (value === null) {
                try {
                    const lsValue = localStorage.getItem(key);
                    if (lsValue !== null) {
                        value = String(lsValue);
                        try {
                            if (typeof GM_setValue === 'function') GM_setValue(key, value);
                        } catch (_) {/* noop */ }
                    }
                } catch (_) {/* noop */ }
            }
            return value;
        }

        function vmPlaybackSetItem(key, value) {
            const stringValue = String(value);
            try {
                if (typeof GM_setValue === 'function') GM_setValue(key, stringValue);
            } catch (_) {/* noop */ }
            try {
                localStorage.setItem(key, stringValue);
            } catch (_) {/* noop */ }
        }

        function vmPlaybackRemoveItem(key) {
            try {
                if (typeof GM_deleteValue === 'function') GM_deleteValue(key);
            } catch (_) {/* noop */ }
            try {
                localStorage.removeItem(key);
            } catch (_) {/* noop */ }
        }

        function vmClearContinuousPlaybackState() {
            try { vmPlaybackRemoveItem(VM_PLAYLIST_KEY); } catch (_) {/* noop */ }
            try { vmPlaybackRemoveItem(VM_PLAY_INDEX_KEY); } catch (_) {/* noop */ }
            try { vmPlaybackRemoveItem(VM_PLAYLIST_META_KEY); } catch (_) {/* noop */ }
            try {
                const old = document.getElementById('vm-mini-pl');
                if (old) old.remove();
            } catch (_) {/* noop */ }
        }

        function vmNavigateNextVideo() {
            try {
                const stopEnabled = vmPlaybackGetItem(VM_PLAY_STOP_KEY) === '1';
                if (stopEnabled) { showToast(t('play.stopped')); return false; }
                const raw = vmPlaybackGetItem(VM_PLAYLIST_KEY) || '[]';
                const ids = JSON.parse(raw);
                if (!Array.isArray(ids) || ids.length === 0) { showToast(t('play.noList')); return false; }
                const current = new URL(location.href).searchParams.get('v') || '';
                let idx = parseInt(vmPlaybackGetItem(VM_PLAY_INDEX_KEY) || '0', 10);
                const found = ids.indexOf(current);
                if (found >= 0) idx = found;
                const nextIdx = idx + 1;
                if (nextIdx < ids.length) {
                    vmPlaybackSetItem(VM_PLAY_INDEX_KEY, String(nextIdx));
                    location.href = `https://www.youtube.com/watch?v=${ids[nextIdx]}`;
                    return true;
                } else {
                    const loopEnabled = vmPlaybackGetItem(VM_PLAY_LOOP_KEY) === '1';
                    if (loopEnabled && ids.length > 0) {
                        vmPlaybackSetItem(VM_PLAY_INDEX_KEY, '0');
                        location.href = `https://www.youtube.com/watch?v=${ids[0]}`;
                        return true;
                    }
                    showToast(t('play.last'));
                    return false;
                }
            } catch (e) { return false; }
        }

        function vmNavigatePrevVideo() {
            try {
                const raw = vmPlaybackGetItem(VM_PLAYLIST_KEY) || '[]';
                const ids = JSON.parse(raw);
                if (!Array.isArray(ids) || ids.length === 0) { showToast(t('play.noList')); return false; }
                const current = new URL(location.href).searchParams.get('v') || '';
                let idx = parseInt(vmPlaybackGetItem(VM_PLAY_INDEX_KEY) || '0', 10);
                const found = ids.indexOf(current);
                if (found >= 0) idx = found;
                const prevIdx = idx - 1;
                if (prevIdx >= 0) {
                    vmPlaybackSetItem(VM_PLAY_INDEX_KEY, String(prevIdx));
                    location.href = `https://www.youtube.com/watch?v=${ids[prevIdx]}`;
                    return true;
                } else {
                    const loopEnabled = vmPlaybackGetItem(VM_PLAY_LOOP_KEY) === '1';
                    if (loopEnabled && ids.length > 0) {
                        const lastIdx = ids.length - 1;
                        vmPlaybackSetItem(VM_PLAY_INDEX_KEY, String(lastIdx));
                        location.href = `https://www.youtube.com/watch?v=${ids[lastIdx]}`;
                        return true;
                    }
                    showToast(t('play.first'));
                    return false;
                }
            } catch (e) { return false; }
        }

        function vmSyncPlayIndexToCurrentVideo() {
            try {
                if (!isWatchLikePath()) return;
                const raw = vmPlaybackGetItem(VM_PLAYLIST_KEY);
                if (!raw) return;
                const ids = JSON.parse(raw || '[]');
                if (!Array.isArray(ids) || ids.length === 0) return;
                const current = getCurrentVideoId();
                if (!current) return;
                const idx = ids.indexOf(current);
                if (idx < 0) return;
                const prev = parseInt(vmPlaybackGetItem(VM_PLAY_INDEX_KEY) || '-1', 10);
                if (prev !== idx) {
                    vmPlaybackSetItem(VM_PLAY_INDEX_KEY, String(idx));
                }
            } catch (e) { }
        }

        function ensureContinuousPlaybackSetup(retryCount = 0) {
            try {
                const ok = setupContinuousPlayback();
                if (ok) return;
                if (retryCount >= 20) return;
                setTimeout(() => ensureContinuousPlaybackSetup(retryCount + 1), 500);
            } catch (e) { }
        }

        function setupContinuousPlayback() {
            try {
                const video = document.querySelector('video');
                if (!video) return false;
                if (video.__vmBoundForMylist) return true;
                video.__vmBoundForMylist = true;

                // シーク等でendedが発火しないケースのフォールバック
                let lastAdvanceAt = 0;
                let lastSeekedAt = 0;
                let lastEndToastSignature = '';

                // 動画の元のサイズを保存
                if (video.videoWidth > 0 && video.videoHeight > 0) {
                    __vmOriginalVideoSize = {
                        width: video.videoWidth,
                        height: video.videoHeight
                    };
                } else {
                    video.addEventListener('loadedmetadata', function onLoaded() {
                        __vmOriginalVideoSize = {
                            width: this.videoWidth,
                            height: this.videoHeight
                        };
                        video.removeEventListener('loadedmetadata', onLoaded);
                    });
                }

                // フルスクリーン状態の変更を監視
                const checkFullscreen = () => {
                    __vmIsFullscreen = !!(document.fullscreenElement ||
                        document.webkitFullscreenElement ||
                        document.mozFullScreenElement ||
                        document.msFullscreenElement ||
                        document.querySelector('.html5-video-player.ytp-fullscreen'));
                };

                // フルスクリーン状態の変更を監視
                ['fullscreenchange', 'webkitfullscreenchange', 'mozfullscreenchange', 'MSFullscreenChange']
                    .forEach(event => document.addEventListener(event, checkFullscreen));

                // 定期的にフルスクリーン状態をチェック
                const fullscreenCheckInterval = setInterval(checkFullscreen, 1000);

                // 次の動画に移動する関数
                const moveToNextVideo = () => {
                    try {
                        const stopEnabled = vmPlaybackGetItem(VM_PLAY_STOP_KEY) === '1';
                        if (stopEnabled) return false;
                        const raw = vmPlaybackGetItem(VM_PLAYLIST_KEY) || '[]';
                        const ids = JSON.parse(raw);
                        if (!Array.isArray(ids) || ids.length === 0) return false;

                        const current = new URL(location.href).searchParams.get('v') || '';
                        if (!current) {
                            showToast(t('play.noId'));
                            return false;
                        }

                        let idx = parseInt(vmPlaybackGetItem(VM_PLAY_INDEX_KEY) || '0', 10);
                        const found = ids.indexOf(current);
                        if (found >= 0) idx = found;

                        const nextIdx = idx + 1;
                        if (nextIdx < ids.length) {
                            lastEndToastSignature = '';
                            // フルスクリーン状態を保存
                            checkFullscreen();
                            vmPlaybackSetItem(VM_PLAY_INDEX_KEY, String(nextIdx));

                            // 次の動画に移動
                            const nextUrl = `https://www.youtube.com/watch?v=${ids[nextIdx]}`;
                            location.href = nextUrl;
                            return true;
                        } else {
                            const loopEnabled = vmPlaybackGetItem(VM_PLAY_LOOP_KEY) === '1';
                            if (loopEnabled && ids.length > 0) {
                                lastEndToastSignature = '';
                                checkFullscreen();
                                vmPlaybackSetItem(VM_PLAY_INDEX_KEY, '0');
                                const firstUrl = `https://www.youtube.com/watch?v=${ids[0]}`;
                                location.href = firstUrl;
                                return true;
                            }
                            const endSignature = `${current}|${ids.length}|${ids[ids.length - 1] || ''}`;
                            if (lastEndToastSignature !== endSignature) {
                                lastEndToastSignature = endSignature;
                                showToast(t('play.ended'));
                            }
                            return false;
                        }
                    } catch (e) {
                        console.error('連続再生中にエラーが発生しました:', e);
                        return false;
                    }
                };

                const maybeAdvanceNearEnd = (reason) => {
                    try {
                        const dur = Number(video.duration);
                        const cur = Number(video.currentTime);
                        if (!Number.isFinite(dur) || dur <= 0) return;
                        if (!Number.isFinite(cur) || cur < 0) return;

                        const remaining = dur - cur;
                        const now = Date.now();
                        if (now - lastAdvanceAt < 2500) return;

                        // ほぼ終端（誤差吸収）
                        if (video.ended || (remaining >= 0 && remaining < 0.4)) {
                            lastAdvanceAt = now;
                            moveToNextVideo();
                            return;
                        }

                        // シーク直後に終端へ飛んだが ended にならないケース
                        if (now - lastSeekedAt < 1200 && remaining >= 0 && remaining < 0.9) {
                            lastAdvanceAt = now;
                            setTimeout(() => moveToNextVideo(), 0);
                        }
                    } catch (e) { }
                };

                // 動画終了時の処理（endedイベント）
                video.addEventListener('ended', moveToNextVideo);

                // シーク/時間更新でも終端到達を拾う
                video.addEventListener('seeked', () => { lastSeekedAt = Date.now(); maybeAdvanceNearEnd('seeked'); });
                video.addEventListener('timeupdate', () => maybeAdvanceNearEnd('timeupdate'));

                // 長時間動画対策: 定期的に動画の終了状態を監視
                let lastCheckTime = 0;
                const endedCheckInterval = setInterval(() => {
                    // ── video 要素が DOM から切り離されていないか確認 ──
                    // YouTube は長時間動画の再生中に <video> を再生成することがある。
                    // その場合、古い参照ではイベントが届かないため、新しい要素に再バインドする。
                    if (!video.isConnected) {
                        clearInterval(endedCheckInterval);
                        clearInterval(fullscreenCheckInterval);
                        video.__vmBoundForMylist = false; // フラグをリセットして再バインドを許可
                        setTimeout(() => ensureContinuousPlaybackSetup(), 500);
                        return;
                    }

                    // 動画が終了している、または終了間近（残り1秒以内）の場合
                    const currentTime = video.currentTime;
                    const duration = video.duration;

                    if (duration && currentTime && duration > 0) {
                        const remaining = duration - currentTime;

                        // 終了済み、または残り0.5秒以内で次の動画へ
                        if (video.ended || (remaining > 0 && remaining < 0.5)) {
                            // 同じタイミングで複数回実行されないよう、前回チェックから3秒以上経過している場合のみ
                            const now = Date.now();
                            if (now - lastCheckTime > 3000) {
                                lastCheckTime = now;
                                moveToNextVideo();
                            }
                        }
                    }
                }, 1000); // 1秒ごとにチェック

                // クリーンアップ（pagehide / ページ遷移時）
                // ※ video 要素に "unload" イベントは存在しないため window で受け取る
                const onPageHide = () => {
                    clearInterval(fullscreenCheckInterval);
                    clearInterval(endedCheckInterval);
                };
                window.addEventListener('pagehide', onPageHide, { once: true });
                return true;
            } catch (e) { }
            return false;
        }

        // フルスクリーンに戻す関数
        function restoreFullscreen() {
            if (!__vmIsFullscreen) return;

            // 動画要素を取得
            const video = document.querySelector('video');
            if (!video) return;

            // 動画のサイズを元に戻す
            if (__vmOriginalVideoSize.width > 0 && __vmOriginalVideoSize.height > 0) {
                video.style.width = `${__vmOriginalVideoSize.width}px`;
                video.style.height = `${__vmOriginalVideoSize.height}px`;
                video.style.maxWidth = '100%';
                video.style.maxHeight = '100%';
            }

            // マイリストのサイズを復元
            const panel = document.getElementById('vm-mini-pl');
            if (panel) {
                const savedSize = getMiniPlaylistSize();
                if (savedSize.width) panel.style.width = savedSize.width;
                if (savedSize.height) panel.style.height = savedSize.height;
            }

            // YouTubeのフルスクリーンボタンを探す
            const fullscreenBtn = document.querySelector('.ytp-fullscreen-button, .ytp-fullscreen-button.ytp-button');
            if (fullscreenBtn) {
                // ボタンが見つかったらクリック
                fullscreenBtn.click();
            } else if (video.webkitRequestFullscreen || video.mozRequestFullScreen || video.msRequestFullscreen) {
                // ボタンが見つからない場合は直接フルスクリーンAPIを使用
                const requestFullscreen = video.requestFullscreen ||
                    video.webkitRequestFullscreen ||
                    video.mozRequestFullScreen ||
                    video.msRequestFullscreen;
                requestFullscreen.call(video).then(() => {
                    // フルスクリーン後にサイズを再設定
                    if (__vmOriginalVideoSize.width > 0 && __vmOriginalVideoSize.height > 0) {
                        video.style.width = `${__vmOriginalVideoSize.width}px`;
                        video.style.height = `${__vmOriginalVideoSize.height}px`;
                        video.style.maxWidth = '100%';
                        video.style.maxHeight = '100%';
                    }
                }).catch(() => { /* fullscreen restore failed */ });
            }
        }

        // 動画の読み込みを監視してフルスクリーンに戻す
        const handleNavigation = () => {
            if (!isWatchLikePath()) return;

            // マイリストのサイズを保存
            const saveMiniPlaylistSizeIfNeeded = () => {
                const panel = document.getElementById('vm-mini-pl');
                if (panel && !panel.classList.contains('vm-mini-pl-iconified')) {
                    const rect = panel.getBoundingClientRect();
                    const savedSize = getMiniPlaylistSize();

                    // 現在のサイズを保存（ただし最小サイズを下回らないように）
                    const newWidth = Math.max(200, rect.width);
                    const newHeight = Math.max(150, rect.height);

                    if (savedSize.width !== newWidth || savedSize.height !== newHeight) {
                        saveMiniPlaylistSize({
                            width: newWidth,
                            height: newHeight
                        });
                    }
                }
            };

            // 動画が読み込まれるのを待つ
            const checkVideoLoaded = setInterval(() => {
                const video = document.querySelector('video');
                if (video && video.readyState > 0) {
                    clearInterval(checkVideoLoaded);
                    // 動画のサイズを保存
                    if (video.videoWidth > 0 && video.videoHeight > 0) {
                        __vmOriginalVideoSize = {
                            width: video.videoWidth,
                            height: video.videoHeight
                        };
                    }

                    // マイリストのサイズを復元
                    const panel = document.getElementById('vm-mini-pl');
                    if (panel) {
                        const savedSize = getMiniPlaylistSize();
                        if (savedSize.width) panel.style.width = savedSize.width;
                        if (savedSize.height) panel.style.height = savedSize.height;
                    }

                    if (__vmIsFullscreen) {
                        // 少し待ってからフルスクリーンに戻す
                        setTimeout(() => {
                            restoreFullscreen();
                            // フルスクリーン復元後に再度サイズを適用
                            if (panel) {
                                const savedSize = getMiniPlaylistSize();
                                if (savedSize.width) panel.style.width = savedSize.width;
                                if (savedSize.height) panel.style.height = savedSize.height;
                            }
                        }, 300);
                    }
                }
            }, 100);

            // 連続再生のセットアップ
            setTimeout(setupContinuousPlayback, 500);
        };

        // ---------------------------
        //    Mini playlist (watch page)
        // ---------------------------
        function renderMiniPlaylist() {
            if (!isWatchLikePath()) return;

            const miniOpacityAlpha = (getMiniPlaylistOpacityPercent() / 100).toFixed(2);

            const st = document.getElementById('vm-mini-pl-style') || document.createElement('style');
            if (!st.id) {
                st.id = 'vm-mini-pl-style';
                st.textContent = `
    #vm-mini-pl-toggle{display:none !important;} /* 旧トグルボタンを完全に非表示 */
    #vm-mini-pl{
        position:fixed;right:10px;top:40px;z-index:9999998;background:rgba(17,17,17,${miniOpacityAlpha});color:#ddd;border:1px solid #444;border-radius:4px;padding:8px;min-width:200px;min-height:150px;width:300px;height:400px;max-width:calc(100vw - 20px);max-height:calc(100vh - 60px);overflow:auto;display:flex;flex-direction:column;resize:both;
        transition: width 0.2s ease, height 0.2s ease, border-radius 0.2s ease, opacity 0.2s ease; /* アニメーション対象を限定 */
    }
    #vm-mini-pl.dragging, #vm-mini-pl.resizing {
        transition: none !important; /* ドラッグ中はアニメーションを無効化 */
    }
    /* [変更] アイコン化された状態のスタイル */
    #vm-mini-pl.vm-mini-pl-iconified {
        width: 40px !important;
        height: 40px !important;
        min-width: 40px !important;
        min-height: 40px !important;
        padding: 0 !important;
        overflow: hidden;
        border-radius: 50%; /* 円形にする */
        display: flex !important;
        justify-content: center !important;
        align-items: center !important;
        cursor: move; /* [変更] カーソルを移動マークに */
        box-shadow: 0 2px 8px rgba(0,0,0,0.5);
        resize: none !important; /* アイコン化時はリサイズ不可 */
    }
    #vm-mini-pl.vm-mini-pl-iconified .vm-mini-pl-header,
    #vm-mini-pl.vm-mini-pl-iconified .vm-mini-pl-body {
        display: none !important; /* ヘッダーとボディを非表示 */
    }
    #vm-mini-pl.vm-mini-pl-iconified::before {
        content: '▶'; /* アイコンのコンテンツ、クリック不可にする */
        font-size: 20px;
        color: #fff;
    }
    #vm-mini-pl h4{margin:0;font-size:14px;color:#fff;font-weight:500;}
    #vm-mini-pl .vm-mini-pl-header{display:flex;align-items:center;gap:10px;margin-bottom:8px;user-select:none;padding-right:8px;cursor:move;}
    #vm-mini-pl .vm-mini-pl-loop{display:flex;align-items:center;gap:4px;font-size:12px;color:#ddd;user-select:none;white-space:nowrap;}
    #vm-mini-pl .vm-mini-pl-loop input{margin:0;accent-color:#ff4d4d;}
    #vm-mini-pl .vm-mini-pl-stop{display:flex;align-items:center;gap:4px;font-size:12px;color:#ddd;user-select:none;white-space:nowrap;}
    #vm-mini-pl .vm-mini-pl-stop input{margin:0;accent-color:#ff4d4d;}
    #vm-mini-pl .vm-mini-pl-loop input,
    #vm-mini-pl .vm-mini-pl-stop input{cursor:pointer;}
    #vm-mini-pl .vm-mini-pl-drag{flex:1 1 auto;min-width:20px;min-height:24px;}
    #vm-mini-pl .vm-mini-pl-body{flex:1 1 auto;overflow:auto;padding-right:4px;}
    #vm-mini-pl .vm-mini-pl-toggle-in{background:transparent;color:#ddd;border:1px solid rgba(255,255,255,.3);border-radius:4px;padding:4px 8px;cursor:pointer;font-size:12px;transition:all 0.2s;}
    #vm-mini-pl .vm-mini-pl-toggle-in:hover{background:rgba(255,255,255,.15);}
    #vm-mini-pl.collapsed .vm-mini-pl-body{display:none}
    #vm-mini-pl.collapsed .vm-mini-pl-header{margin-bottom:0}
    #vm-mini-pl ul{list-style:none;margin:0;padding:0;}
    #vm-mini-pl li{padding:8px 6px;border-bottom:1px solid rgba(255,255,255,0.1);cursor:pointer;display:flex;gap:8px;align-items:center;border-radius:4px;transition:background 0.2s;}
    #vm-mini-pl li:hover{background:rgba(255,255,255,.1);}
    #vm-mini-pl li.current{background:rgba(255,0,0,.25);color:#fff;font-weight:600;border-left:3px solid #FF0000;}
    #vm-mini-pl .idx{color:#aaa;min-width:20px;text-align:right;font-size:12px;font-family:monospace;}
    #vm-mini-pl .title{flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;font-size:13px;}
    `;
                document.head.appendChild(st);
            }
            try {
                const raw = vmPlaybackGetItem(VM_PLAYLIST_KEY) || '[]';
                const ids = JSON.parse(raw);
                if (!Array.isArray(ids) || ids.length === 0) {
                    const old = document.getElementById('vm-mini-pl');
                    if (old) old.remove();
                    return;
                }

                const current = getCurrentVideoId();
                if (!current) {
                    const old = document.getElementById('vm-mini-pl');
                    if (old) old.remove();
                    return;
                }
                if (!ids.includes(current)) {
                    vmClearContinuousPlaybackState();
                    return;
                }

                let panel = document.getElementById('vm-mini-pl');
                if (!panel) {
                    panel = document.createElement('div');
                    panel.id = 'vm-mini-pl';

                    // フルスクリーン状態を監視する関数
                    const updateFullscreenVisibility = () => {
                        // document.fullscreenElement が null でなければフルスクリーン状態
                        const isFullscreen = !!document.fullscreenElement;
                        panel.style.display = isFullscreen ? 'none' : 'flex';
                    };

                    // フルスクリーン状態の変更イベントを監視
                    document.addEventListener('fullscreenchange', updateFullscreenVisibility, false);

                    document.body.appendChild(panel);

                    // 保存された位置とサイズを取得（必ず数値で取得）
                    const savedPos = getMiniPlaylistPosition();
                    const savedSize = getMiniPlaylistSize();

                    // 位置を設定（比率保存形式と旧px形式に両対応、デフォルトは右上）
                    let pos;
                    if (savedPos.leftRatio != null && savedPos.topRatio != null) {
                        const vw = window.innerWidth || document.documentElement.clientWidth || 1;
                        const vh = window.innerHeight || document.documentElement.clientHeight || 1;
                        const panelW = parseInt(savedSize.width || '300', 10) || 300;
                        const panelH = parseInt(savedSize.height || '400', 10) || 400;
                        const leftPx = Math.max(0, Math.min(savedPos.leftRatio * vw, vw - panelW));
                        const topPx = Math.max(0, Math.min(savedPos.topRatio * vh, vh - panelH));
                        pos = {
                            top: `${Math.round(topPx)}px`,
                            left: `${Math.round(leftPx)}px`,
                            right: 'auto',
                            bottom: 'auto'
                        };
                    } else {
                        // 旧形式(px文字列)または未設定時はデフォルト右上
                        pos = {
                            top: savedPos.top || '40px',
                            right: savedPos.right || '10px',
                            left: savedPos.left || 'auto',
                            bottom: savedPos.bottom || 'auto'
                        };
                    }

                    // サイズを設定（最小サイズを保証）
                    const size = {
                        width: savedSize.width || '300px',
                        height: savedSize.height || '400px'
                    };

                    // パネルにスタイルを適用
                    Object.assign(panel.style, {
                        position: 'fixed',
                        zIndex: '9999998',
                        display: 'flex',
                        ...pos,
                        width: size.width,
                        height: size.height,
                        minWidth: '200px',
                        minHeight: '150px',
                        maxWidth: 'calc(100vw - 20px)',
                        maxHeight: 'calc(100vh - 60px)',
                        overflow: 'auto',
                        flexDirection: 'column',
                        resize: 'both',
                        transition: 'all 0.3s ease',
                        background: `rgba(17,17,17,${miniOpacityAlpha})`,
                        color: '#ddd',
                        border: '1px solid #444',
                        borderRadius: '4px',
                        padding: '8px'
                    });

                    // フルスクリーン状態を確認して必要に応じて非表示に
                    updateFullscreenVisibility();

                    // [変更] 初期状態を復元
                    const initialState = getMiniPlaylistState();
                    if (initialState === 'iconified') {
                        panel.classList.add('vm-mini-pl-iconified');
                    }

                    // サイズ変更を監視して保存するロジックを簡素化
                    let resizeTimer;
                    const resizeObserver = new ResizeObserver(debounce((entries) => {
                        // アイコン化されている場合や、パネルが表示されていない場合はサイズを保存しない
                        if (panel.classList.contains('vm-mini-pl-iconified') || panel.style.display === 'none') return;
                        for (const entry of entries) {
                            const { width, height } = entry.contentRect;
                            // ユーザーがリサイズ操作中の場合は保存を遅延させる
                            if (!panel.classList.contains('resizing')) {
                                saveMiniPlaylistSize({
                                    width: Math.round(width),
                                    height: Math.round(height)
                                });
                            }
                        }
                    }, 250)); // 250ms待ってから保存
                    resizeObserver.observe(panel);

                    // リサイズ操作の開始と終了を検知
                    panel.addEventListener('mousedown', e => { if (e.target === panel && e.offsetX > panel.clientWidth - 16 && e.offsetY > panel.clientHeight - 16) panel.classList.add('resizing'); });
                    document.addEventListener('mouseup', () => { if (panel.classList.contains('resizing')) { panel.classList.remove('resizing'); saveMiniPlaylistSize({ width: panel.offsetWidth, height: panel.offsetHeight }); } });

                    // ウィンドウリサイズ時にビューポート比率から位置を再計算
                    const onWindowResize = debounce(() => {
                        const p = getMiniPlaylistPosition();
                        if (p.leftRatio == null || p.topRatio == null) return;
                        const vw = window.innerWidth || document.documentElement.clientWidth || 1;
                        const vh = window.innerHeight || document.documentElement.clientHeight || 1;
                        const panelW = panel.offsetWidth || 300;
                        const panelH = panel.offsetHeight || 400;
                        const leftPx = Math.max(0, Math.min(p.leftRatio * vw, vw - panelW));
                        const topPx = Math.max(0, Math.min(p.topRatio * vh, vh - panelH));
                        panel.style.left = `${Math.round(leftPx)}px`;
                        panel.style.top = `${Math.round(topPx)}px`;
                        panel.style.right = 'auto';
                        panel.style.bottom = 'auto';
                    }, 100);
                    window.addEventListener('resize', onWindowResize, { passive: true });
                }
                panel.style.background = `rgba(17,17,17,${miniOpacityAlpha})`;

                const meta = JSON.parse(vmPlaybackGetItem(VM_PLAYLIST_META_KEY) || '[]');
                const metaMap = new Map((Array.isArray(meta) ? meta : []).map(m => [m.id, m.title || m.id]));

                let idx = ids.indexOf(current);
                if (idx >= 0) {
                    // 手動選択/SPA遷移後も連続再生が継続するよう index を同期
                    vmPlaybackSetItem(VM_PLAY_INDEX_KEY, String(idx));
                } else {
                    idx = parseInt(vmPlaybackGetItem(VM_PLAY_INDEX_KEY) || '0', 10);
                }

                const start = 0; // フルリストを描画し、スクロールで過去分も閲覧可能に
                const slice = ids;

                while (panel.firstChild) {
                    panel.removeChild(panel.firstChild);
                }
                // Header with internal toggle and drag zone
                const header = document.createElement('div'); header.className = 'vm-mini-pl-header';
                const titleEl = document.createElement('h4'); titleEl.textContent = '連続再生';
                header.appendChild(titleEl); // titleElを最初に追加

                const loopWrap = document.createElement('label');
                loopWrap.className = 'vm-mini-pl-loop';
                const loopCheckbox = document.createElement('input');
                loopCheckbox.type = 'checkbox';
                loopCheckbox.checked = vmPlaybackGetItem(VM_PLAY_LOOP_KEY) === '1';
                loopCheckbox.addEventListener('click', (e) => e.stopPropagation());
                loopCheckbox.addEventListener('change', () => {
                    vmPlaybackSetItem(VM_PLAY_LOOP_KEY, loopCheckbox.checked ? '1' : '0');
                });
                const loopText = document.createElement('span');
                loopText.textContent = 'ループ';
                loopWrap.appendChild(loopCheckbox);
                loopWrap.appendChild(loopText);
                header.appendChild(loopWrap);

                const stopWrap = document.createElement('label');
                stopWrap.className = 'vm-mini-pl-stop';
                const stopCheckbox = document.createElement('input');
                stopCheckbox.type = 'checkbox';
                stopCheckbox.checked = vmPlaybackGetItem(VM_PLAY_STOP_KEY) === '1';
                stopCheckbox.addEventListener('click', (e) => e.stopPropagation());
                stopCheckbox.addEventListener('change', () => {
                    vmPlaybackSetItem(VM_PLAY_STOP_KEY, stopCheckbox.checked ? '1' : '0');
                });
                const stopText = document.createElement('span');
                stopText.textContent = '連続再生を止める';
                stopWrap.appendChild(stopCheckbox);
                stopWrap.appendChild(stopText);
                header.appendChild(stopWrap);

                // [追加] ドラッグハンドルの追加とイベント設定
                const dragHandle = document.createElement('div');
                dragHandle.className = 'vm-mini-pl-drag';
                header.appendChild(dragHandle); // dragHandleを次に追加

                panel.addEventListener('mousedown', (e) => {
                    const target = e.target instanceof Element ? e.target : null;
                    const clickedHeader = target ? target.closest('.vm-mini-pl-header') : null;
                    const clickedInteractive = target ? target.closest('input, button, select, option, textarea, a') : null;
                    // ヘッダー全体をドラッグ対象に広げるが、入力系UIはそのまま操作できるよう除外
                    const isDragTarget = panel.classList.contains('vm-mini-pl-iconified') || (!!clickedHeader && !clickedInteractive);
                    if (!isDragTarget) return;

                    e.preventDefault();

                    // [追加] ドラッグ中はアニメーションを無効化
                    panel.classList.add('dragging');

                    const rect = panel.getBoundingClientRect();
                    const offsetX = e.clientX - rect.left;
                    const offsetY = e.clientY - rect.top;

                    const onMouseMove = (moveEvent) => {
                        const newLeft = moveEvent.clientX - offsetX;
                        const newTop = moveEvent.clientY - offsetY;
                        panel.style.left = `${newLeft}px`;
                        panel.style.top = `${newTop}px`;
                        panel.style.right = 'auto';
                        panel.style.bottom = 'auto';
                    };

                    const onMouseUp = () => {
                        document.removeEventListener('mousemove', onMouseMove);
                        document.removeEventListener('mouseup', onMouseUp);
                        // [追加] ドラッグ終了時にアニメーションを再度有効化
                        panel.classList.remove('dragging');
                        // ビューポート比率で保存（リサイズ後も位置が崩れない）
                        const vw = window.innerWidth || document.documentElement.clientWidth || 1;
                        const vh = window.innerHeight || document.documentElement.clientHeight || 1;
                        const leftPx = parseFloat(panel.style.left) || 0;
                        const topPx = parseFloat(panel.style.top) || 0;
                        saveMiniPlaylistPosition({
                            leftRatio: leftPx / vw,
                            topRatio: topPx / vh
                        });
                    };

                    document.addEventListener('mousemove', onMouseMove);
                    document.addEventListener('mouseup', onMouseUp);
                });

                // [追加] ダブルクリックで開く処理
                panel.addEventListener('dblclick', (e) => {
                    if (panel.classList.contains('vm-mini-pl-iconified')) {
                        panel.classList.remove('vm-mini-pl-iconified');
                        saveMiniPlaylistState('open');
                    }
                });

                // [追加] ヘッダーのダブルクリックで閉じる処理
                header.addEventListener('dblclick', (e) => {
                    // [変更] ヘッダーのどこをダブルクリックしてもアイコン化する
                    e.stopPropagation(); // 親要素へのイベント伝播を停止
                    panel.classList.add('vm-mini-pl-iconified');
                    saveMiniPlaylistState('iconified');
                });


                panel.appendChild(header);
                // Body (collapsible)
                const body = document.createElement('div'); body.className = 'vm-mini-pl-body'; panel.appendChild(body);
                const ul = document.createElement('ul'); body.appendChild(ul);
                let currentLi = null;
                slice.forEach((vid, i) => {
                    const li = document.createElement('li');
                    if (i === idx) { li.classList.add('current'); currentLi = li; }
                    const spanIdx = document.createElement('span'); spanIdx.className = 'idx'; spanIdx.textContent = String(i + 1);
                    const spanTitle = document.createElement('span'); spanTitle.className = 'title'; spanTitle.textContent = metaMap.get(vid) || vid;
                    li.appendChild(spanIdx); li.appendChild(spanTitle);
                    li.onclick = () => {
                        vmPlaybackSetItem(VM_PLAY_INDEX_KEY, String(i));
                        location.href = `https://www.youtube.com/watch?v=${vid}`;
                    };
                    ul.appendChild(li);
                });
                if (currentLi) {
                    setTimeout(() => body.scrollTop = Math.max(0, currentLi.offsetTop - body.offsetTop - 20), 400);
                }
            } catch (e) { }
        }

        // ---------------------------
        //    Auto-cancel playlist when off-track
        // ---------------------------
        // ページ読み込み直後（フルリロード）の誤クリアを防ぐため、
        // load イベントが発火した「絶対時刻」を記録し、その後 1.5 秒以内の
        // vmMaybeClearPlaylistIfNotMember 呼び出しは skip する。
        // これにより window.load と yt-navigate-finish が両方発火しても安全に動作する。
        let __vmPageLoadedAt = 0;
        window.addEventListener('load', () => { __vmPageLoadedAt = Date.now(); });
        function vmMaybeClearPlaylistIfNotMember() {
            try {
                if (!isWatchLikePath()) return;
                // フルページロード後 1.5 秒以内は誤クリアを防ぐためスキップ
                if (Date.now() - __vmPageLoadedAt < 1500) return;
                const raw = vmPlaybackGetItem(VM_PLAYLIST_KEY);
                if (!raw) return;
                const ids = JSON.parse(raw || '[]');
                if (!Array.isArray(ids) || ids.length === 0) return;
                const current = getCurrentVideoId();
                // 現在の動画がリストに含まれている場合は絶対に消去しない
                if (!current) return;
                if (ids.includes(current)) return;
                vmClearContinuousPlaybackState();
            } catch (e) { }
        }

        document.addEventListener('yt-navigate-finish', () => setTimeout(vmMaybeClearPlaylistIfNotMember, 300));
        window.addEventListener('load', () => setTimeout(vmMaybeClearPlaylistIfNotMember, 1600));

        /* ---------------------------
            Mylist render function (v20.25)
        --------------------------- */
        // 動画リストのソート状態（sessionStorage永続化）
        const GRID_SORT_SESSION_KEY = 'vm-grid-sort-state';
        let videoSortState = { key: null, dir: 0 }; // dir: 1=昇順, -1=降順, 0=手動順
        function getGridSortState() {
            try {
                const raw = sessionStorage.getItem(GRID_SORT_SESSION_KEY);
                if (raw) { const s = JSON.parse(raw); if (s && typeof s === 'object') return s; }
            } catch (e) { }
            return videoSortState;
        }
        function setGridSortState(state) {
            videoSortState = state;
            try { sessionStorage.setItem(GRID_SORT_SESSION_KEY, JSON.stringify(state)); } catch (e) { }
        }
        function resetVideoSort() { setGridSortState({ key: 'addedAt', dir: -1 }); }

        // ISO 8601 Duration (PT#H#M#S) を秒数に変換 (ソート用)
        function durationToSeconds(iso) {
            if (!iso || !iso.startsWith('PT')) return 0;
            let seconds = 0;
            // H, M, S の各部分を正規表現で抽出
            const hMatch = iso.match(/(\d+)H/);
            const mMatch = iso.match(/(\d+)M/);
            const sMatch = iso.match(/(\d+)S/);

            if (hMatch) seconds += parseInt(hMatch[1], 10) * 3600;
            if (mMatch) seconds += parseInt(mMatch[1], 10) * 60;
            if (sMatch) seconds += parseInt(sMatch[1], 10);

            return seconds;
        }
        // ISO 8601 Duration を人間が読める形式 (H:MM:SS) に変換 (表示用)
        function humanDuration(val) {
            if (!val) return '';
            // P0D (ライブ配信中/プレミア公開前) の場合は空文字列
            if (val === 'P0D') return '';
            // If ISO 8601 (PT..)
            if (typeof val === 'string' && val.startsWith('PT')) {
                const totalSeconds = durationToSeconds(val);
                if (totalSeconds === 0) return '';
                const hours = Math.floor(totalSeconds / 3600);
                const minutes = Math.floor((totalSeconds % 3600) / 60);
                const seconds = totalSeconds % 60;
                const pad = (num) => String(num).padStart(2, '0');
                return hours > 0 ? `${hours}:${pad(minutes)}:${pad(seconds)}` : `${minutes}:${pad(seconds)}`;
            }
            // If already a clock format like H:MM:SS or MM:SS, return as-is
            if (/^\d{1,2}:\d{2}(?::\d{2})?$/.test(String(val))) return String(val);
            return '';
        }
        function humanDate(iso) {
            if (!iso) return '';
            // YYYY-MM-DD または ISO形式 ('2025-10-12' または '2025-10-12T...' のような形式) の場合は日付変換を試みる
            if (/\d{4}-\d{2}-\d{2}/.test(iso)) {
                try {
                    // toLocaleString() で時間情報を含めて表示する
                    return new Date(iso).toLocaleString();
                } catch (e) {
                    return iso;
                }
            }
            // それ以外（相対日付テキストなど）はそのまま返す
            return iso;
        }

        function formatDateYmdSlash(iso) {
            if (!iso) return '';
            try {
                const d = new Date(iso);
                if (!isFinite(d.getTime())) return '';
                const y = d.getFullYear();
                const m = String(d.getMonth() + 1).padStart(2, '0');
                const day = String(d.getDate()).padStart(2, '0');
                return `${y}/${m}/${day}`;
            } catch (e) {
                return '';
            }
        }

        // ノート内の「再生位置: H:MM(:SS)」をクリック可能なリンクとして描画
        function renderNoteWithLinks(container, note, videoId) {
            while (container.firstChild) container.removeChild(container.firstChild);
            const text = (note == null ? '' : String(note));
            if (!text) {
                container.classList.add('note-empty');
                const p = container.parentElement;
                if (p && p.classList && p.classList.contains('note-cell')) p.classList.add('note-empty');
                container.textContent = 'メモなし';
                return;
            } else {
                container.classList.remove('note-empty');
                const p = container.parentElement;
                if (p && p.classList) p.classList.remove('note-empty');
            }

            // 時刻トークンやラベルが一切なければ高速描画（改行のみ維持）
            const hasTimeToken = /(\d{1,2}:\d{2}(?::\d{2})?)/.test(text) || text.includes('PT');
            const hasLegacyLabel = /再生位置:\s*/.test(text);
            if (!hasTimeToken && !hasLegacyLabel) {
                const lines = text.split('\n');
                for (let i = 0; i < lines.length; i++) {
                    container.appendChild(document.createTextNode(lines[i]));
                    if (i < lines.length - 1) container.appendChild(document.createElement('br'));
                }
                return;
            }

            const lines = text.split('\n');
            const timeRe = /(\d{1,2}:\d{2}(?::\d{2})?)/g; // 行内の時刻トークンをすべてリンク化

            for (let i = 0; i < lines.length; i++) {
                // 「再生位置: 」の表記は表示しない（過去データ互換のため見た目だけ削除）
                const rawLine = lines[i].replace(/再生位置:\s*/g, '');
                // タイムスタンプを含む行にのみ行頭絵文字除去を適用（通常メモの絵文字は保持）
                const hasTime = /\d{1,2}:\d{2}/.test(rawLine);
                const line = hasTime ? stripTimeEmoji(rawLine) : rawLine;
                let last = 0; let m;
                timeRe.lastIndex = 0;
                while ((m = timeRe.exec(line))) {
                    const idx = m.index;
                    if (idx > last) { container.appendChild(document.createTextNode(line.slice(last, idx))); }
                    const timeStr = m[1];
                    const secs = Math.max(0, durationToSecondsAny(timeStr) || 0);
                    const a = document.createElement('a');
                    a.textContent = timeStr;
                    a.href = `https://www.youtube.com/watch?v=${videoId}&t=${secs}s`;
                    a.target = '_blank';
                    a.rel = 'noopener noreferrer';
                    a.style.color = '#8ab4f8';
                    container.appendChild(a);
                    last = timeRe.lastIndex;
                }
                if (last < line.length) { container.appendChild(document.createTextNode(line.slice(last))); }
                if (i < lines.length - 1) container.appendChild(document.createElement('br'));
            }
        }

        function openMylistMemoEditorModal(video, data, options = {}) {
            if (!video || !data) return;

            const titleText = options.title || 'メモ編集';
            const initialNote = String(video.note || '');

            const overlay = document.createElement('div');
            overlay.className = 'vm-modal-overlay';

            const modal = document.createElement('div');
            modal.className = 'vm-modal-content';
            modal.style.maxWidth = '560px';
            modal.style.width = 'min(560px, 94vw)';

            const title = document.createElement('h3');
            title.textContent = titleText;
            modal.appendChild(title);

            const help = document.createElement('p');
            help.textContent = '※ メモ内の 0:45 などは保存後にクリックで指定時刻へ移動できます。';
            help.style.margin = '0 0 8px';
            help.style.fontSize = '12px';
            help.style.color = '#aaa';
            modal.appendChild(help);

            const textarea = document.createElement('textarea');
            textarea.value = initialNote;
            textarea.placeholder = 'メモを入力...';
            Object.assign(textarea.style, {
                width: '100%',
                minHeight: '180px',
                maxHeight: '50vh',
                resize: 'vertical',
                padding: '10px',
                boxSizing: 'border-box',
                background: '#222',
                color: '#fff',
                border: '1px solid #555',
                borderRadius: '6px',
                fontSize: '13px',
                lineHeight: '1.55'
            });
            modal.appendChild(textarea);

            const actions = document.createElement('div');
            actions.className = 'vm-modal-actions';
            const cancelBtn = document.createElement('button');
            cancelBtn.className = 'vm-btn';
            cancelBtn.textContent = 'キャンセル';
            const saveBtn = document.createElement('button');
            saveBtn.className = 'vm-btn vm-btn-primary';
            saveBtn.textContent = '保存';
            actions.appendChild(cancelBtn);
            actions.appendChild(saveBtn);
            modal.appendChild(actions);

            let closed = false;
            const close = () => {
                if (closed) return;
                closed = true;
                try { document.removeEventListener('keydown', onKeyDown, true); } catch (_) {/* noop */ }
                try { overlay.remove(); } catch (_) {/* noop */ }
            };

            const save = () => {
                if (closed) return;
                const nextNote = String(textarea.value || '');
                const updatedCount = updateVideoNoteAcrossAllFolders(data, video.id, nextNote, { skipTrash: true });
                if (updatedCount <= 0) {
                    showToast('保存先が見つかりませんでした');
                    return;
                }
                video.note = nextNote;
                saveMylistData(data);
                if (typeof options.onSaved === 'function') {
                    try { options.onSaved(nextNote); } catch (_) {/* noop */ }
                }
                showToast('メモを保存しました');
                close();
            };

            const onKeyDown = (ev) => {
                if (!ev) return;
                if (ev.key === 'Escape') {
                    ev.preventDefault();
                    close();
                    return;
                }
                if (ev.key === 'Enter' && (ev.ctrlKey || ev.metaKey)) {
                    ev.preventDefault();
                    save();
                }
            };

            cancelBtn.addEventListener('click', close);
            saveBtn.addEventListener('click', save);
            overlay.addEventListener('click', (ev) => {
                if (ev.target === overlay) close();
            });
            document.addEventListener('keydown', onKeyDown, true);

            overlay.appendChild(modal);
            document.body.appendChild(overlay);

            setTimeout(() => {
                try {
                    textarea.focus();
                    textarea.setSelectionRange(textarea.value.length, textarea.value.length);
                } catch (_) {/* noop */ }
            }, 0);
        }

        // 任意の形式の再生時間文字列を秒に変換（ISO8601 PT.. または H:MM:SS／MM:SS をサポート）
        function durationToSecondsAny(val) {
            if (!val) return 0;
            const s = String(val);
            if (s.startsWith('PT')) return durationToSeconds(s);
            const m = s.match(/^(\d+):(\d{2})(?::(\d{2}))?$/);
            if (m) {
                const h = m[3] ? parseInt(m[1], 10) : 0;
                const mm = m[3] ? parseInt(m[2], 10) : parseInt(m[1], 10);
                const ss = m[3] ? parseInt(m[3], 10) : parseInt(m[2], 10);
                return (h * 3600) + (mm * 60) + ss;
            }
            return 0;
        }

        // 行の高さに合わせてメモ表示領域の最大高さを設定（はみ出しはスクロール）
        function fitNoteHeightToRow(tr, td, noteEl) {
            // max-height は CSS (.note-text { max-height: 105px }) で固定しているため
            // JS による動的計算は行わない。visibility だけ解除する。
            try {
                if (noteEl) noteEl.style.visibility = '';
            } catch (e) { }
        }

        // 動画リストのソートロジック
        function sortVideoList(list, forceMobileSort = false, useGridSort = false) {
            // グリッドソートが設定されている場合はそちらを優先（グリッド表示時のみ）
            if (useGridSort) {
                const gridSort = getGridSortState();
                if (gridSort.key && gridSort.dir !== 0) {
                    const key = gridSort.key, dir = gridSort.dir;
                    return list.slice().sort((a, b) => {
                        let va, vb;
                        if (key === 'channel') {
                            va = (a.channelTitle || '').toLowerCase();
                            vb = (b.channelTitle || '').toLowerCase();
                        } else {
                            va = a[key] || ''; vb = b[key] || '';
                        }
                        if (key === 'addedAt' || key === 'publishedAt') {
                            va = va ? new Date(va).getTime() : 0;
                            vb = vb ? new Date(vb).getTime() : 0;
                        } else if (key === 'duration') {
                            va = durationToSecondsAny(va);
                            vb = durationToSecondsAny(vb);
                        } else if (key !== 'channel') {
                            va = String(va).toLowerCase();
                            vb = String(vb).toLowerCase();
                        }
                        return (va < vb ? -1 : va > vb ? 1 : 0) * dir;
                    });
                }
            }
            // スマホモードの場合、モバイルソート設定を使用
            const isMobile = window.innerWidth <= 768;
            if (isMobile || forceMobileSort) {
                const mobileSortMode = parseInt(localStorage.getItem('vm-mobile-sort-mode') || '0');
                // 0: 投稿日(降順), 1: 登録日(降順), 2: タイトル(昇順)
                return list.slice().sort((a, b) => {
                    let va, vb;
                    if (mobileSortMode === 0) {
                        // 投稿日
                        va = a.publishedAt ? new Date(a.publishedAt).getTime() : 0;
                        vb = b.publishedAt ? new Date(b.publishedAt).getTime() : 0;
                        return vb - va; // 降順（新しい順）
                    } else if (mobileSortMode === 1) {
                        // 登録日
                        va = a.addedAt ? new Date(a.addedAt).getTime() : 0;
                        vb = b.addedAt ? new Date(b.addedAt).getTime() : 0;
                        return vb - va; // 降順（新しい順）
                    } else {
                        // タイトル
                        va = (a.title || '').toLowerCase();
                        vb = (b.title || '').toLowerCase();
                        return va < vb ? -1 : va > vb ? 1 : 0; // 昇順（ABC順）
                    }
                });
            }

            // デスクトップモードは従来通り（gridSort=手動順のときのリスト表示用）
            if (!videoSortState.key || videoSortState.dir === 0) return list.slice();
            const key = videoSortState.key, dir = videoSortState.dir;
            return list.slice().sort((a, b) => {
                let va, vb;
                if (key === 'channel') {
                    va = (a.channelTitle || '').toLowerCase();
                    vb = (b.channelTitle || '').toLowerCase();
                } else {
                    va = a[key] || ''; vb = b[key] || '';
                }
                if (key === 'addedAt' || key === 'publishedAt') {
                    va = va ? new Date(va).getTime() : 0;
                    vb = vb ? new Date(vb).getTime() : 0;
                }
                if (key === 'duration') {
                    va = durationToSecondsAny(va);
                    vb = durationToSecondsAny(vb);
                } else {
                    if (key !== 'channel') {
                        va = String(va).toLowerCase();
                        vb = String(vb).toLowerCase();
                    }
                }
                return (va < vb ? -1 : va > vb ? 1 : 0) * dir;
            });
        }

        function getMylistBaseVideoList(data, selectedFolder, includeDesc) {
            const crossSearch = isVideoSearchCrossFolderEnabled();
            if (crossSearch) {
                return buildAllFoldersUniqueVideoList(data);
            }
            if (includeDesc && selectedFolder && selectedFolder !== TRASH_FOLDER_NAME) {
                const names = collectFolderSubtreeNames(data, selectedFolder);
                const uniqMap = new Map();
                names.forEach(name => {
                    const arr = Array.isArray(data.folders[name]) ? data.folders[name] : [];
                    arr.forEach(v => {
                        if (v && v.id && !uniqMap.has(v.id)) uniqMap.set(v.id, v);
                    });
                });
                return Array.from(uniqMap.values());
            }
            return Array.isArray(data.folders[selectedFolder]) ? data.folders[selectedFolder] : [];
        }

        function getMylistSortedDisplayList(data, selectedFolder, includeDesc) {
            const baseList = getMylistBaseVideoList(data, selectedFolder, includeDesc);
            const q = getVideoSearchQuery();
            return sortVideoList(filterVideoListBySearch(baseList, q));
        }

        const VIDEO_SEARCH_QUERY_KEY = 'vm-video-search-query';
        const VIDEO_SEARCH_CROSS_FOLDER_KEY = 'vm-video-search-cross-folder';

        const JUMP_PERCENT_KEY = 'vm-jump-percent-v1'; // 互換: グローバル既定
        const JUMP_PERCENT_BY_FOLDER_KEY = 'vm-jump-percent-by-folder-v1';
        const JUMP_PERCENT_CHOICES = [10, 20, 30, 40, 50];
        function getJumpPercent(folderKey) {
            const readGlobalDefault = () => {
                try {
                    const raw = parseInt(localStorage.getItem(JUMP_PERCENT_KEY) || '', 10);
                    if (JUMP_PERCENT_CHOICES.includes(raw)) return raw;
                } catch (e) { }
                return 30;
            };

            const fk = (folderKey == null) ? '' : String(folderKey);
            if (!fk) return readGlobalDefault();

            try {
                const obj = JSON.parse(localStorage.getItem(JUMP_PERCENT_BY_FOLDER_KEY) || '{}');
                if (obj && typeof obj === 'object') {
                    const raw = parseInt(obj[fk] || '', 10);
                    if (JUMP_PERCENT_CHOICES.includes(raw)) return raw;
                }
            } catch (e) { }
            return readGlobalDefault();
        }
        function setJumpPercent(p, folderKey) {
            const v = parseInt(String(p || ''), 10);
            if (!JUMP_PERCENT_CHOICES.includes(v)) return;

            const fk = (folderKey == null) ? '' : String(folderKey);
            if (!fk) {
                try { localStorage.setItem(JUMP_PERCENT_KEY, String(v)); } catch (e) { }
                return;
            }

            try {
                const obj = JSON.parse(localStorage.getItem(JUMP_PERCENT_BY_FOLDER_KEY) || '{}');
                const next = (obj && typeof obj === 'object') ? obj : {};
                next[fk] = v;
                localStorage.setItem(JUMP_PERCENT_BY_FOLDER_KEY, JSON.stringify(next));
            } catch (e) { }
        }
        function getVideoSearchQuery() {
            // 入力中の末尾スペースを維持しないと、再レンダリング時にスペースが消えてAND検索が組めなくなるためtrimしない。
            // 検索ロジック側（filterVideoListBySearch）でtrim/正規化する。
            try { return (sessionStorage.getItem(VIDEO_SEARCH_QUERY_KEY) || ''); } catch (e) { return ''; }
        }

        function isVideoSearchCrossFolderEnabled() {
            try { return sessionStorage.getItem(VIDEO_SEARCH_CROSS_FOLDER_KEY) === '1'; } catch (e) { return false; }
        }

        function buildAllFoldersUniqueVideoList(data) {
            const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
            const uniqMap = new Map();
            Object.keys(folders).forEach(folderName => {
                const arr = folders[folderName];
                if (!Array.isArray(arr) || !arr.length) return;
                arr.forEach(v => {
                    const id = v && v.id;
                    if (!id) return;
                    if (!uniqMap.has(id)) uniqMap.set(id, v);
                });
            });
            return Array.from(uniqMap.values());
        }

        function areAllIdsInTrashFolder(data, ids) {
            const trashArr = Array.isArray(data?.folders?.[TRASH_FOLDER_NAME]) ? data.folders[TRASH_FOLDER_NAME] : [];
            if (!trashArr.length) return false;
            const trashIds = new Set(trashArr.map(v => v && v.id).filter(Boolean));
            if (!ids || !ids.size) return false;
            for (const id of ids) {
                if (!trashIds.has(id)) return false;
            }
            return true;
        }

        function normalizeTagsFromInput(input) {
            const raw = String(input || '').trim();
            if (!raw) return [];
            const parts = raw
                .split(/[\s,，、]+/)
                .map(s => s.trim())
                .filter(Boolean)
                .map(s => s.replace(/^#+/, ''))
                .map(s => s.trim())
                .filter(Boolean);

            const out = [];
            const seen = new Set();
            for (const t of parts) {
                const key = t.toLowerCase();
                if (seen.has(key)) continue;
                seen.add(key);
                out.push(t.slice(0, 40));
                if (out.length >= 30) break;
            }
            return out;
        }

        function tagsToDisplayParts(tags) {
            const arr = Array.isArray(tags) ? tags.filter(Boolean).map(String) : [];
            if (!arr.length) return [];
            const max = 6;
            const head = arr.slice(0, max);
            if (arr.length > max) head.push(`+${arr.length - max}`);
            return head;
        }

        function removeSingleTagFromTagList(tags, tagToRemove) {
            const arr = Array.isArray(tags) ? tags.filter(Boolean).map(String) : [];
            const target = String(tagToRemove || '').trim();
            if (!target) return arr;
            const tgtKey = target.toLowerCase();
            const out = [];
            for (const t of arr) {
                if (String(t).toLowerCase() === tgtKey) continue;
                out.push(t);
            }
            return out;
        }

        function mergeTagsCaseInsensitive(existingTags, tagsToAdd) {
            const base = Array.isArray(existingTags) ? existingTags.filter(Boolean).map(String) : [];
            const add = Array.isArray(tagsToAdd) ? tagsToAdd.filter(Boolean).map(String) : [];
            if (!add.length) return base;
            const seen = new Set(base.map(t => String(t).toLowerCase()));
            const out = base.slice();
            for (const t of add) {
                const key = String(t).toLowerCase();
                if (seen.has(key)) continue;
                seen.add(key);
                out.push(String(t));
                if (out.length >= 30) break;
            }
            return out;
        }

        function removeTagsCaseInsensitive(existingTags, tagsToRemove) {
            const base = Array.isArray(existingTags) ? existingTags.filter(Boolean).map(String) : [];
            const rm = Array.isArray(tagsToRemove) ? tagsToRemove.filter(Boolean).map(String) : [];
            if (!rm.length || !base.length) return base;
            const rmSet = new Set(rm.map(t => String(t).toLowerCase()));
            return base.filter(t => !rmSet.has(String(t).toLowerCase()));
        }

        function addTagsForVideosByIdsAcrossAllFolders(data, ids, tagsToAdd) {
            const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
            const uniqueUpdated = new Set();
            const add = Array.isArray(tagsToAdd) ? tagsToAdd.slice() : [];
            if (!ids || !ids.size) return 0;
            if (!add.length) return 0;

            Object.keys(folders).forEach(folderName => {
                const arr = folders[folderName];
                if (!Array.isArray(arr) || !arr.length) return;
                for (const v of arr) {
                    if (!v || !v.id) continue;
                    if (!ids.has(v.id)) continue;
                    const next = mergeTagsCaseInsensitive(v.tags, add);
                    if (next.length) v.tags = next;
                    uniqueUpdated.add(v.id);
                }
            });
            return uniqueUpdated.size;
        }

        function removeTagsForVideosByIdsAcrossAllFolders(data, ids, tagsToRemove) {
            const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
            const uniqueUpdated = new Set();
            const rm = Array.isArray(tagsToRemove) ? tagsToRemove.slice() : [];
            if (!ids || !ids.size) return 0;
            if (!rm.length) return 0;

            Object.keys(folders).forEach(folderName => {
                const arr = folders[folderName];
                if (!Array.isArray(arr) || !arr.length) return;
                for (const v of arr) {
                    if (!v || !v.id) continue;
                    if (!ids.has(v.id)) continue;
                    const next = removeTagsCaseInsensitive(v.tags, rm);
                    if (next.length) v.tags = next;
                    else delete v.tags;
                    uniqueUpdated.add(v.id);
                }
            });
            return uniqueUpdated.size;
        }

        function setVideoSearchQueryAndRender(query) {
            try { sessionStorage.setItem('vm-video-search-keep-focus', '1'); } catch (e) { }
            try { sessionStorage.setItem(VIDEO_SEARCH_QUERY_KEY, String(query || '')); } catch (e) { }
            renderMylistPage();
        }

        const TAG_PRESETS_KEY = 'vm-tag-presets';
        function getTagPresets() {
            try {
                const raw = String(localStorage.getItem(TAG_PRESETS_KEY) || '').trim();
                return normalizeTagsFromInput(raw);
            } catch (e) {
                return [];
            }
        }
        function setTagPresets(tags) {
            try {
                const arr = Array.isArray(tags) ? tags.filter(Boolean).map(String) : [];
                localStorage.setItem(TAG_PRESETS_KEY, arr.join(' '));
            } catch (e) { }
        }

        // グリッドカード移動ボタンの編集モーダル
        // onSave: モーダルを閉じた後に各カードのボタン行を再構築するコールバック（省略可）
        function showGridMoveButtonsEditor(onSave) {
            const data = getMylistData();
            // ゴミ箱・デフォルト以外のフォルダ一覧
            const allFolders = (data.folderOrder || Object.keys(data.folders || {}))
                .filter(f => f !== TRASH_FOLDER_NAME);

            const overlay = document.createElement('div');
            Object.assign(overlay.style, {
                position: 'fixed', inset: '0', background: 'rgba(0,0,0,0.65)',
                display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: '1000010'
            });

            const box = document.createElement('div');
            Object.assign(box.style, {
                background: '#1e1e1e', padding: '16px', borderRadius: '10px',
                width: 'min(460px, 92vw)', maxHeight: '80vh', overflowY: 'auto',
                color: '#fff', display: 'flex', flexDirection: 'column', gap: '12px', fontSize: '14px'
            });

            const titleEl = document.createElement('div');
            titleEl.textContent = t('movebtn.title');
            titleEl.style.fontWeight = '700';
            box.appendChild(titleEl);

            const desc = document.createElement('div');
            desc.textContent = t('movebtn.desc');
            desc.style.cssText = 'font-size:12px;opacity:0.8;';
            box.appendChild(desc);

            // 現在の設定リスト
            const listWrap = document.createElement('div');
            listWrap.style.cssText = 'display:flex;flex-direction:column;gap:6px;';

            const renderList = () => {
                while (listWrap.firstChild) listWrap.removeChild(listWrap.firstChild);
                const current = getGridMoveButtons();
                if (!current.length) {
                    const empty = document.createElement('div');
                    empty.style.cssText = 'opacity:0.6;font-size:12px;';
                    empty.textContent = t('movebtn.empty');
                    listWrap.appendChild(empty);
                }
                current.forEach((folderName, idx) => {
                    const row = document.createElement('div');
                    row.style.cssText = 'display:flex;align-items:center;gap:8px;background:#2a2a2a;padding:6px 10px;border-radius:6px;';

                    const label = document.createElement('span');
                    label.style.flex = '1';
                    label.textContent = formatFolderDisplayName(folderName, null);

                    const upBtn = document.createElement('button');
                    upBtn.textContent = '↑';
                    upBtn.title = '上へ';
                    Object.assign(upBtn.style, { background: '#333', border: 'none', color: '#ccc', borderRadius: '4px', cursor: 'pointer', padding: '2px 6px' });
                    upBtn.disabled = idx === 0;
                    upBtn.onclick = () => {
                        const arr = getGridMoveButtons();
                        if (idx > 0) { [arr[idx - 1], arr[idx]] = [arr[idx], arr[idx - 1]]; saveGridMoveButtons(arr); renderList(); }
                    };

                    const downBtn = document.createElement('button');
                    downBtn.textContent = '↓';
                    downBtn.title = '下へ';
                    Object.assign(downBtn.style, { background: '#333', border: 'none', color: '#ccc', borderRadius: '4px', cursor: 'pointer', padding: '2px 6px' });
                    downBtn.disabled = idx === current.length - 1;
                    downBtn.onclick = () => {
                        const arr = getGridMoveButtons();
                        if (idx < arr.length - 1) { [arr[idx], arr[idx + 1]] = [arr[idx + 1], arr[idx]]; saveGridMoveButtons(arr); renderList(); }
                    };

                    const delBtn = document.createElement('button');
                    delBtn.textContent = '❌';
                    delBtn.title = '削除';
                    Object.assign(delBtn.style, { background: 'transparent', border: 'none', cursor: 'pointer', padding: '2px 4px' });
                    delBtn.onclick = () => {
                        const arr = getGridMoveButtons().filter((_, i) => i !== idx);
                        saveGridMoveButtons(arr);
                        renderList();
                        renderAddSection();
                    };

                    row.appendChild(label);
                    row.appendChild(upBtn);
                    row.appendChild(downBtn);
                    row.appendChild(delBtn);
                    listWrap.appendChild(row);
                });
            };

            box.appendChild(listWrap);

            // 追加セクション
            const addWrap = document.createElement('div');
            addWrap.style.cssText = 'display:flex;flex-direction:column;gap:8px;';

            const renderAddSection = () => {
                while (addWrap.firstChild) addWrap.removeChild(addWrap.firstChild);
                const current = getGridMoveButtons();
                const _moveBtnMax = isPremiumUser() ? PREMIUM_MOVE_BTN_LIMIT : FREE_PLAN_MOVE_BTN_LIMIT;
                if (current.length >= _moveBtnMax) {
                    const msg = document.createElement('div');
                    msg.textContent = t('movebtn.limit').replace('{n}', _moveBtnMax);
                    msg.style.cssText = 'font-size:12px;opacity:0.7;';
                    addWrap.appendChild(msg);
                    return;
                }

                const addLabel = document.createElement('div');
                addLabel.textContent = t('movebtn.addLabel');
                addLabel.style.cssText = 'font-size:12px;opacity:0.85;';
                addWrap.appendChild(addLabel);

                // 既存フォルダから選択
                const remaining = allFolders.filter(f => !current.includes(f));
                if (remaining.length) {
                    const sel = document.createElement('select');
                    Object.assign(sel.style, {
                        background: '#2a2a2a', color: '#fff', border: '1px solid #555',
                        borderRadius: '6px', padding: '6px', fontSize: '13px', width: '100%'
                    });
                    const placeholder = document.createElement('option');
                    placeholder.value = '';
                    placeholder.textContent = t('movebtn.selectPlaceholder');
                    sel.appendChild(placeholder);
                    remaining.forEach(f => {
                        const opt = document.createElement('option');
                        opt.value = f;
                        opt.textContent = formatFolderDisplayName(f, null);
                        sel.appendChild(opt);
                    });
                    sel.onchange = () => {
                        if (!sel.value) return;
                        const arr = getGridMoveButtons();
                        const _max1 = isPremiumUser() ? PREMIUM_MOVE_BTN_LIMIT : FREE_PLAN_MOVE_BTN_LIMIT;
                        if (arr.length >= _max1) { showToast(t('movebtn.limit').replace('{n}', _max1)); sel.value = ''; return; }
                        if (!arr.includes(sel.value)) { arr.push(sel.value); saveGridMoveButtons(arr); }
                        renderList();
                        renderAddSection();
                    };
                    addWrap.appendChild(sel);
                }

                // 新規フォルダを作って追加
                const newRow = document.createElement('div');
                newRow.style.cssText = 'display:flex;gap:6px;align-items:center;';
                const newInput = document.createElement('input');
                newInput.type = 'text';
                newInput.className = 'vm-form-input';
                newInput.placeholder = t('movebtn.newPlaceholder');
                newInput.style.flex = '1';
                const newBtn = document.createElement('button');
                newBtn.className = 'vm-btn vm-btn-primary';
                newBtn.textContent = t('movebtn.createAdd');
                newBtn.style.whiteSpace = 'nowrap';
                const doCreate = () => {
                    const name = newInput.value.trim();
                    if (!name) { showToast(t('movebtn.noName')); return; }
                    const arr = getGridMoveButtons();
                    const _max2 = isPremiumUser() ? PREMIUM_MOVE_BTN_LIMIT : FREE_PLAN_MOVE_BTN_LIMIT;
                    if (arr.length >= _max2) { showToast(t('movebtn.limit').replace('{n}', _max2)); return; }
                    // フォルダをデータに追加
                    const latest = getMylistData();
                    if (!latest.folders[name]) {
                        latest.folders[name] = [];
                        if (!Array.isArray(latest.folderOrder)) latest.folderOrder = Object.keys(latest.folders);
                        if (!latest.folderOrder.includes(name)) latest.folderOrder.push(name);
                        saveMylistData(latest);
                        allFolders.push(name);
                    }
                    if (!arr.includes(name)) { arr.push(name); saveGridMoveButtons(arr); }
                    newInput.value = '';
                    renderList();
                    renderAddSection();
                    showToast(t('movebtn.created').replace('{name}', name));
                };
                newBtn.onclick = doCreate;
                let isComposing = false;
                newInput.addEventListener('compositionstart', () => { isComposing = true; });
                newInput.addEventListener('compositionend', () => { isComposing = false; });
                newInput.addEventListener('keydown', (e) => { if (e.key === 'Enter' && !isComposing) { e.preventDefault(); doCreate(); } });
                newRow.appendChild(newInput);
                newRow.appendChild(newBtn);
                addWrap.appendChild(newRow);
            };

            box.appendChild(addWrap);

            // 閉じるボタン
            const closeBtn = document.createElement('button');
            closeBtn.className = 'vm-btn';
            closeBtn.textContent = t('common.close');
            closeBtn.onclick = () => {
                overlay.remove();
                // 全カードのアクション行を再構築
                if (typeof onSave === 'function') {
                    // 同じグリッド内の全カードを再構築するため renderMylistPage を呼ぶ
                    try { renderMylistPage(); } catch (e) { }
                }
            };
            box.appendChild(closeBtn);

            overlay.appendChild(box);
            document.body.appendChild(overlay);

            overlay.addEventListener('click', (e) => { if (e.target === overlay) closeBtn.click(); });
            const onKey = (e) => { if (e.key === 'Escape') { document.removeEventListener('keydown', onKey); closeBtn.click(); } };
            document.addEventListener('keydown', onKey);

            renderList();
            renderAddSection();
        }

        function showTagEditorPanel(ids) {
            const count = ids?.size || 0;
            if (!count) { showToast('対象がありません'); return; }

            let needsRender = false;

            const getTagsMapForIds = (data, targetIds) => {
                const map = new Map();
                const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
                Object.keys(folders).forEach(folderName => {
                    const arr = folders[folderName];
                    if (!Array.isArray(arr) || !arr.length) return;
                    for (const v of arr) {
                        if (!v || !v.id) continue;
                        if (!targetIds.has(v.id)) continue;
                        if (!map.has(v.id)) {
                            map.set(v.id, Array.isArray(v.tags) ? v.tags.filter(Boolean).map(String) : []);
                        }
                    }
                });
                // 見つからないIDも空配列として扱う
                for (const id of targetIds) {
                    if (!map.has(id)) map.set(id, []);
                }
                return map;
            };

            const overlay = document.createElement('div');
            Object.assign(overlay.style, {
                position: 'fixed',
                inset: 0,
                background: 'rgba(0,0,0,0.6)',
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                zIndex: 1000003
            });

            const box = document.createElement('div');
            Object.assign(box.style, {
                background: '#1e1e1e',
                padding: '14px',
                borderRadius: '10px',
                width: 'min(520px, 92vw)',
                minWidth: '360px',
                maxWidth: '92vw',
                boxSizing: 'border-box',
                maxHeight: '80vh',
                overflowY: 'auto',
                color: '#fff',
                display: 'flex',
                flexDirection: 'column',
                gap: '10px',
                fontSize: '14px'
            });

            const title = document.createElement('div');
            title.textContent = 'タグ編集';
            title.style.fontWeight = '700';
            box.appendChild(title);

            const meta = document.createElement('div');
            meta.textContent = `選択: ${count}件`;
            meta.style.opacity = '0.85';
            meta.style.fontSize = '12px';
            box.appendChild(meta);

            const hint = document.createElement('div');
            hint.textContent = 'スペース or , 区切りで入力（#は付けてもOK）';
            hint.style.opacity = '0.75';
            hint.style.fontSize = '12px';
            box.appendChild(hint);

            // 選択タグ（よく使うタグ）
            const presetWrap = document.createElement('div');
            presetWrap.style.display = 'flex';
            presetWrap.style.flexDirection = 'column';
            presetWrap.style.gap = '6px';

            const presetLabel = document.createElement('div');
            presetLabel.textContent = '選択タグ（よく使うタグ）';
            presetLabel.style.fontSize = '12px';
            presetLabel.style.opacity = '0.85';
            presetWrap.appendChild(presetLabel);

            const presetInput = document.createElement('input');
            presetInput.type = 'text';
            presetInput.className = 'vm-form-input';
            presetInput.placeholder = '例: 後で見る 勉強 作業用';
            presetInput.autocomplete = 'off';
            // Enterで1つずつ（または複数まとめて）追加できるように、入力欄は常に空から開始
            presetInput.value = '';
            presetWrap.appendChild(presetInput);

            const presetLine = document.createElement('div');
            presetLine.className = 'vm-tags-line';
            presetLine.style.minHeight = '30px';
            presetWrap.appendChild(presetLine);

            const renderPresetLine = () => {
                while (presetLine.firstChild) presetLine.removeChild(presetLine.firstChild);
                const presets = getTagPresets();
                if (!presets.length) {
                    const msg = document.createElement('span');
                    msg.style.opacity = '0.7';
                    msg.style.fontSize = '12px';
                    msg.textContent = '（ここに入力 → Enterで追加 / クリックで付与）';
                    presetLine.appendChild(msg);
                    return;
                }
                presets.forEach(t => {
                    const chip = document.createElement('span');
                    chip.className = 'vm-tag vm-tag-removable';
                    chip.textContent = String(t);
                    chip.title = 'クリックでこのタグを追加';
                    chip.addEventListener('click', (e) => {
                        e.preventDefault();
                        e.stopPropagation();
                        const latest = getMylistData();
                        const updated = addTagsForVideosByIdsAcrossAllFolders(latest, ids, [String(t)]);
                        if (!updated) { showToast('対象がありません'); return; }
                        saveMylistData(latest);
                        showToast(`🏷️ ${updated}件にタグを追加しました`);
                        needsRender = true;
                        updateCurrentLine();
                    });
                    presetLine.appendChild(chip);
                });
            };

            const addPresetsFromInput = () => {
                const toAdd = normalizeTagsFromInput(presetInput.value);
                if (!toAdd.length) return;
                const current = getTagPresets();
                const merged = mergeTagsCaseInsensitive(current, toAdd);
                setTagPresets(merged);
                presetInput.value = '';
                renderPresetLine();
                try { presetInput.focus(); } catch (e) { }
            };

            let presetIsComposing = false;
            presetInput.addEventListener('compositionstart', () => { presetIsComposing = true; });
            presetInput.addEventListener('compositionend', () => { presetIsComposing = false; });
            presetInput.addEventListener('blur', addPresetsFromInput);
            presetInput.addEventListener('keydown', (e) => {
                if (e.key === 'Enter') {
                    if (presetIsComposing || e.isComposing) return;
                    e.preventDefault();
                    addPresetsFromInput();
                }
            });

            renderPresetLine();
            box.appendChild(presetWrap);

            const currentWrap = document.createElement('div');
            currentWrap.style.display = 'flex';
            currentWrap.style.flexDirection = 'column';
            currentWrap.style.gap = '6px';

            const currentLabel = document.createElement('div');
            currentLabel.textContent = '現在のタグ';
            currentLabel.style.fontSize = '12px';
            currentLabel.style.opacity = '0.85';
            currentWrap.appendChild(currentLabel);

            const currentLine = document.createElement('div');
            currentLine.className = 'vm-tags-line';
            currentLine.style.minHeight = '34px';
            currentWrap.appendChild(currentLine);

            const updateCurrentLine = () => {
                while (currentLine.firstChild) currentLine.removeChild(currentLine.firstChild);
                if (count !== 1) {
                    const latest = getMylistData();
                    const tagMap = getTagsMapForIds(latest, ids);
                    let commonKeys = null;
                    const keyToLabel = new Map();
                    for (const tags of tagMap.values()) {
                        const keys = new Set(tags.map(t => String(t).toLowerCase()));
                        tags.forEach(t => {
                            const k = String(t).toLowerCase();
                            if (!keyToLabel.has(k)) keyToLabel.set(k, String(t));
                        });
                        if (commonKeys === null) {
                            commonKeys = keys;
                        } else {
                            commonKeys = new Set([...commonKeys].filter(k => keys.has(k)));
                        }
                        if (commonKeys.size === 0) break;
                    }

                    const head = document.createElement('div');
                    head.style.opacity = '0.7';
                    head.style.fontSize = '12px';
                    head.textContent = '複数選択中（共通タグは❌で一括削除）';
                    currentLine.appendChild(head);

                    const keysArr = commonKeys ? Array.from(commonKeys) : [];
                    if (!keysArr.length) {
                        const msg = document.createElement('span');
                        msg.style.opacity = '0.7';
                        msg.style.fontSize = '12px';
                        msg.textContent = '共通タグなし';
                        msg.style.marginLeft = '6px';
                        currentLine.appendChild(msg);
                        return;
                    }

                    keysArr.slice(0, 20).forEach(k => {
                        const label = keyToLabel.get(k) || k;
                        const chip = document.createElement('span');
                        chip.className = 'vm-tag vm-tag-with-x';

                        const lbl = document.createElement('span');
                        lbl.textContent = String(label);
                        chip.appendChild(lbl);

                        const xBtn = document.createElement('button');
                        xBtn.type = 'button';
                        xBtn.className = 'vm-tag-xbtn';
                        xBtn.textContent = '❌';
                        xBtn.title = 'このタグを一括削除';
                        xBtn.addEventListener('click', (e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            const latest = getMylistData();
                            const updated = removeTagsForVideosByIdsAcrossAllFolders(latest, ids, [String(label)]);
                            if (!updated) { showToast('対象がありません'); return; }
                            saveMylistData(latest);
                            showToast('🏷️ タグを削除しました');
                            needsRender = true;
                            updateCurrentLine();
                        });
                        chip.appendChild(xBtn);
                        currentLine.appendChild(chip);
                    });
                    return;
                }
                const latest = getMylistData();
                const onlyId = ids.values().next().value;
                const v = findAnyVideoById(latest, onlyId);
                const tags = Array.isArray(v?.tags) ? v.tags.filter(Boolean).map(String) : [];
                if (!tags.length) {
                    const msg = document.createElement('span');
                    msg.style.opacity = '0.7';
                    msg.style.fontSize = '12px';
                    msg.textContent = '（なし）';
                    currentLine.appendChild(msg);
                    return;
                }
                tags.forEach(t => {
                    const chip = document.createElement('span');
                    chip.className = 'vm-tag vm-tag-with-x';

                    const label = document.createElement('span');
                    label.textContent = String(t);
                    chip.appendChild(label);

                    const xBtn = document.createElement('button');
                    xBtn.type = 'button';
                    xBtn.className = 'vm-tag-xbtn';
                    xBtn.textContent = '❌';
                    xBtn.title = 'このタグを削除';
                    xBtn.addEventListener('click', (e) => {
                        e.preventDefault();
                        e.stopPropagation();
                        const latest = getMylistData();
                        const updated = removeTagsForVideosByIdsAcrossAllFolders(latest, ids, [String(t)]);
                        if (!updated) { showToast('対象がありません'); return; }
                        saveMylistData(latest);
                        showToast('🏷️ タグを削除しました');
                        needsRender = true;
                        updateCurrentLine();
                    });
                    chip.appendChild(xBtn);
                    currentLine.appendChild(chip);
                });
            };

            updateCurrentLine();
            box.appendChild(currentWrap);

            const input = document.createElement('input');
            input.type = 'text';
            input.className = 'vm-form-input';
            input.placeholder = '例: 勉強 料理 #あとで見る';
            input.autocomplete = 'off';
            box.appendChild(input);

            let tagPanelIsComposing = false;
            input.addEventListener('compositionstart', () => { tagPanelIsComposing = true; });
            input.addEventListener('compositionend', () => { tagPanelIsComposing = false; });

            const btnRow = document.createElement('div');
            Object.assign(btnRow.style, { display: 'flex', gap: '8px', justifyContent: 'flex-end', flexWrap: 'wrap' });

            const addBtn = document.createElement('button');
            addBtn.className = 'vm-btn vm-btn-primary';
            addBtn.textContent = '追加';

            const closeBtn = document.createElement('button');
            closeBtn.className = 'vm-btn';
            closeBtn.textContent = '閉じる';

            const doAdd = () => {
                const tags = normalizeTagsFromInput(input.value);
                if (!tags.length) { showToast('タグを入力してください'); return; }
                const latest = getMylistData();
                const updated = addTagsForVideosByIdsAcrossAllFolders(latest, ids, tags);
                if (!updated) { showToast('対象がありません'); return; }
                saveMylistData(latest);
                showToast(`🏷️ ${updated}件にタグを追加しました`);
                needsRender = true;
                input.value = '';
                updateCurrentLine();
                try { input.focus(); } catch (e) { }
            };

            addBtn.addEventListener('click', doAdd);
            closeBtn.addEventListener('click', () => overlay.remove());

            input.addEventListener('keydown', (e) => {
                if (e.key === 'Enter') {
                    if (tagPanelIsComposing || e.isComposing) return;
                    e.preventDefault();
                    doAdd();
                } else if (e.key === 'Escape') {
                    e.preventDefault();
                    overlay.remove();
                }
            });

            btnRow.appendChild(addBtn);
            btnRow.appendChild(closeBtn);
            box.appendChild(btnRow);

            overlay.appendChild(box);
            document.body.appendChild(overlay);

            const onKey = (ev) => {
                if (ev.key === 'Escape') {
                    ev.preventDefault();
                    overlay.remove();
                }
            };
            document.addEventListener('keydown', onKey);
            const cleanup = () => {
                document.removeEventListener('keydown', onKey);
            };
            overlay.addEventListener('click', (ev) => {
                if (ev.target === overlay) {
                    cleanup();
                    overlay.remove();
                }
            });
            const origRemove = overlay.remove.bind(overlay);
            overlay.remove = () => {
                cleanup();
                origRemove();
                if (needsRender) {
                    try { renderMylistPage(); } catch (e) { }
                }
            };

            setTimeout(() => { try { input.focus(); } catch (e) { } }, 0);
        }

        function removeSingleTagForVideoIdAcrossAllFolders(data, videoId, tagToRemove) {
            const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
            const updated = new Set();
            const id = String(videoId || '').trim();
            if (!id) return 0;
            const target = String(tagToRemove || '').trim();
            if (!target) return 0;

            Object.keys(folders).forEach(folderName => {
                const arr = folders[folderName];
                if (!Array.isArray(arr) || !arr.length) return;
                for (const v of arr) {
                    if (!v || v.id !== id) continue;
                    const next = removeSingleTagFromTagList(v.tags, target);
                    if (next.length) v.tags = next;
                    else delete v.tags;
                    updated.add(id);
                }
            });
            return updated.size;
        }

        function findAnyVideoById(data, id) {
            const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
            for (const folderName of Object.keys(folders)) {
                const arr = folders[folderName];
                if (!Array.isArray(arr) || !arr.length) continue;
                const v = arr.find(x => x && x.id === id);
                if (v) return v;
            }
            return null;
        }

        function setTagsForVideosByIdsAcrossAllFolders(data, ids, tags) {
            const folders = data?.folders && typeof data.folders === 'object' ? data.folders : {};
            const uniqueUpdated = new Set();
            const newTags = Array.isArray(tags) ? tags.slice() : [];

            Object.keys(folders).forEach(folderName => {
                const arr = folders[folderName];
                if (!Array.isArray(arr) || !arr.length) return;
                for (const v of arr) {
                    if (!v || !v.id) continue;
                    if (!ids.has(v.id)) continue;
                    if (newTags.length) v.tags = newTags.slice();
                    else delete v.tags;
                    uniqueUpdated.add(v.id);
                }
            });
            return uniqueUpdated.size;
        }

        function normalizeSearchText(s) {
            let out = String(s || '');
            // 半角カナ等も含めてできるだけ素直に揃える
            try { out = out.normalize('NFKC'); } catch (_) { }
            out = out.toLowerCase();

            // カタカナ→ひらがな（ひらがな/カタカナを区別しない）
            // U+30A1(ァ)〜U+30F6(ヶ) を U+3041(ぁ)〜U+3096(ゖ) に寄せる（-0x60）
            let buf = '';
            for (let i = 0; i < out.length; i++) {
                const code = out.charCodeAt(i);
                if (code >= 0x30A1 && code <= 0x30F6) {
                    buf += String.fromCharCode(code - 0x60);
                } else {
                    buf += out[i];
                }
            }
            return buf;
        }

        function filterVideoListBySearch(list, query) {
            const q = normalizeSearchText(query).trim();
            if (!q) return list;
            const rawTokens = q.split(/\s+/).filter(Boolean);
            if (!rawTokens.length) return list;

            // AND検索 + マイナス検索
            // 例: "スポーツ 2026 -切り抜き" → "スポーツ"と"2026"を含み、"切り抜き"を含まない
            // NOTE: "-"単体は無視、"- #tag" のように分離されたケースは対象外（"-#tag"を推奨）
            const pos = [];
            const neg = [];
            for (const t of rawTokens) {
                if (!t) continue;
                if (t === '-') continue;
                if (t.startsWith('-') && t.length >= 2) {
                    const nt = t.slice(1).trim();
                    if (nt) neg.push(nt);
                    continue;
                }
                pos.push(t);
            }
            if (!pos.length && !neg.length) return list;
            return list.filter(v => {
                const tags = Array.isArray(v?.tags) ? v.tags.filter(Boolean).map(String) : [];
                const tagHay = tags.length ? `${tags.join(' ')} ${tags.map(t => '#' + t).join(' ')}` : '';
                const hayRaw = `${v?.title || ''}\n${v?.channelTitle || ''}\n${v?.note || ''}\n${tagHay}\n${v?.id || ''}`;
                const hay = normalizeSearchText(hayRaw);

                // positive tokens: 全て含む
                for (const t of pos) {
                    if (!hay.includes(t)) return false;
                }
                // negative tokens: 1つでも含んだら除外
                for (const t of neg) {
                    if (hay.includes(t)) return false;
                }
                return true;
            });
        }

        // フォルダリストのソートロジック
        function sortFolderList(folderData, folderOrder) {
            let list = folderOrder.slice();
            list.sort((a, b) => {
                // デフォルトフォルダは常に先頭
                if (a === getDefaultFolder()) return -1;
                if (b === getDefaultFolder()) return 1;
                // ゴミ箱は常に最後
                if (a === TRASH_FOLDER_NAME) return 1;
                if (b === TRASH_FOLDER_NAME) return -1;
                let va = a.toLowerCase();
                let vb = b.toLowerCase();
                return (va < vb ? -1 : va > vb ? 1 : 0);
            });
            return list;
        }

        // ファイルダウンロードヘルパー
        function downloadFile(dataStr, filename, mimeType) {
            const blob = new Blob([dataStr], { type: mimeType });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = filename;
            document.body.appendChild(a);
            a.click();

            // クリーンアップ
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

