        function collectUnifiedBackupExtraPersistedSettings() {
            const result = {};
            UNIFIED_BACKUP_EXTRA_PERSISTED_SPECS.forEach((spec) => {
                const entry = {};
                if (spec.gm) {
                    try {
                        const sentinel = { __missing: true };
                        const value = GM_getValue(spec.key, sentinel);
                        if (value !== sentinel) entry.gm = value;
                    } catch (_) { }
                }
                if (spec.local) {
                    try {
                        const value = localStorage.getItem(spec.key);
                        if (value !== null) entry.local = value;
                    } catch (_) { }
                }
                if (Object.keys(entry).length) result[spec.key] = entry;
            });
            return result;
        }

        function applyUnifiedBackupExtraPersistedSettings(settings) {
            const source = (settings && typeof settings === 'object') ? settings : {};
            UNIFIED_BACKUP_EXTRA_PERSISTED_SPECS.forEach((spec) => {
                const entry = (source[spec.key] && typeof source[spec.key] === 'object') ? source[spec.key] : null;
                if (spec.gm) {
                    try {
                        if (entry && Object.prototype.hasOwnProperty.call(entry, 'gm')) {
                            GM_setValue(spec.key, entry.gm);
                        } else if (typeof GM_deleteValue === 'function') {
                            GM_deleteValue(spec.key);
                        }
                    } catch (_) { }
                }
                if (spec.local) {
                    try {
                        if (entry && Object.prototype.hasOwnProperty.call(entry, 'local')) {
                            localStorage.setItem(spec.key, String(entry.local));
                        } else {
                            localStorage.removeItem(spec.key);
                        }
                    } catch (_) { }
                }
            });
        }

        function buildUnifiedBackupPayload(mylistDataOverride) {
            return {
                __version__: 4,
                __format__: 'ytvp-backup',
                exportedAt: new Date().toISOString(),
                defaultFolderName: getDefaultFolder(),
                mylist: mylistDataOverride || getMylistData(),
                channelList: getChannelListData(),
                syncSettings: getPlaylistSyncData(),
                ytApiKey: shouldIncludeYtApiKeyInBackup() ? (getApiKey() || '') : '',
                autoExport: getAutoExportConfig(),
                trashAutoDelete: getTrashAutoDeleteConfig(),
                thumbExtraFolderBtns: getThumbExtraFolderBtns(),
                folderViewModes: getViewModeMap(),
                gridMoveButtons: getGridMoveButtons(),
                shortcutKeyConfig: getShortcutKeyConfig(),
                watchNoteAutoSaveDisabled: isWatchNoteAutoSaveDisabled(),
                extraPersistedSettings: collectUnifiedBackupExtraPersistedSettings()
            };
        }

        function parseUnifiedBackupPayload(parsed) {
            let mylistData = null;
            let channelListData = null;
            let syncData = null;
            let syncConfig = null;
            let ytApiKey = null;
            let autoExport = null;
            let trashAutoDelete = null;
            let thumbExtraFolderBtns = null;
            let folderViewModes = null;
            let gridMoveButtons = null;
            let shortcutKeyConfig = null;
            let watchNoteAutoSaveDisabled = null;
            let extraPersistedSettings = null;

            if (parsed && parsed.__version__ && parsed.mylist) {
                mylistData = parsed.mylist;
                channelListData = parsed.channelList || null;
                syncData = parsed.syncSettings || null;
                syncConfig = parsed.syncConfig || null;
                ytApiKey = parsed.ytApiKey || null;
                autoExport = parsed.autoExport || null;
                trashAutoDelete = parsed.trashAutoDelete || null;
                thumbExtraFolderBtns = Array.isArray(parsed.thumbExtraFolderBtns) ? parsed.thumbExtraFolderBtns : null;
                folderViewModes = (parsed.folderViewModes && typeof parsed.folderViewModes === 'object') ? parsed.folderViewModes : null;
                gridMoveButtons = Array.isArray(parsed.gridMoveButtons) ? parsed.gridMoveButtons : null;
                shortcutKeyConfig = parsed.shortcutKeyConfig || null;
                if (typeof parsed.watchNoteAutoSaveDisabled === 'boolean') {
                    watchNoteAutoSaveDisabled = parsed.watchNoteAutoSaveDisabled;
                }
                extraPersistedSettings = (parsed.extraPersistedSettings && typeof parsed.extraPersistedSettings === 'object')
                    ? parsed.extraPersistedSettings
                    : null;
            } else if (parsed && typeof parsed === 'object' && parsed.folders) {
                mylistData = parsed;
            }

            return {
                mylistData,
                channelListData,
                syncData,
                syncConfig,
                ytApiKey,
                autoExport,
                trashAutoDelete,
                thumbExtraFolderBtns,
                folderViewModes,
                gridMoveButtons,
                shortcutKeyConfig,
                watchNoteAutoSaveDisabled,
                extraPersistedSettings,
                defaultFolderName: (parsed && parsed.defaultFolderName) || null
            };
        }

        function showImportTargetSelectorModal(hasMylist, hasChannel) {
            if (hasMylist && !hasChannel) return Promise.resolve('mylist');
            if (!hasMylist && hasChannel) return Promise.resolve('channel');
            if (!hasMylist && !hasChannel) return Promise.resolve(null);

            return new Promise((resolve) => {
                const overlay = document.createElement('div');
                overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:2147483647;display:flex;align-items:center;justify-content:center;padding:16px;';

                const modal = document.createElement('div');
                modal.style.cssText = 'width:min(520px,94vw);background:#1f1f1f;color:#f3f3f3;border:1px solid #3a3a3a;border-radius:12px;padding:16px 16px 12px;box-shadow:0 12px 32px rgba(0,0,0,.45);';

                const title = document.createElement('h3');
                title.textContent = t('import.target.title');
                title.style.cssText = 'margin:0 0 8px;font-size:18px;';

                const desc = document.createElement('p');
                desc.textContent = t('import.target.desc');
                desc.style.cssText = 'margin:0 0 12px;color:#bcbcbc;font-size:13px;line-height:1.5;';

                const list = document.createElement('div');
                list.style.cssText = 'display:flex;flex-direction:column;gap:8px;margin-bottom:12px;';

                const makeChoiceBtn = (label, sub, mode, enabled = true) => {
                    const button = document.createElement('button');
                    button.type = 'button';
                    button.disabled = !enabled;
                    button.style.cssText = `text-align:left;padding:12px;border-radius:10px;border:1px solid ${enabled ? '#4a4a4a' : '#353535'};background:${enabled ? '#2a2a2a' : '#242424'};color:${enabled ? '#fff' : '#8f8f8f'};cursor:${enabled ? 'pointer' : 'not-allowed'};`;

                    const main = document.createElement('div');
                    main.textContent = label;
                    main.style.cssText = 'font-weight:700;font-size:14px;';

                    const subText = document.createElement('div');
                    subText.textContent = sub;
                    subText.style.cssText = 'margin-top:4px;font-size:12px;color:#b5b5b5;';

                    button.appendChild(main);
                    button.appendChild(subText);
                    if (enabled) {
                        button.addEventListener('mouseenter', () => { button.style.background = '#333'; });
                        button.addEventListener('mouseleave', () => { button.style.background = '#2a2a2a'; });
                        button.addEventListener('click', () => {
                            cleanup();
                            resolve(mode);
                        });
                    }
                    return button;
                };

                list.appendChild(makeChoiceBtn(t('import.target.all'), t('import.target.all.sub'), 'all', true));
                list.appendChild(makeChoiceBtn(t('import.target.mylist'), t('import.target.mylist.sub'), 'mylist', !!hasMylist));
                list.appendChild(makeChoiceBtn(t('import.target.channel'), t('import.target.channel.sub'), 'channel', !!hasChannel));

                const footer = document.createElement('div');
                footer.style.cssText = 'display:flex;justify-content:flex-end;';
                const cancel = document.createElement('button');
                cancel.type = 'button';
                cancel.textContent = t('common.cancel');
                cancel.style.cssText = 'padding:8px 12px;border:none;border-radius:8px;background:#4c4c4c;color:#fff;cursor:pointer;';

                const onEsc = (event) => {
                    if (event.key === 'Escape') {
                        event.preventDefault();
                        cleanup();
                        resolve(null);
                    }
                };

                const cleanup = () => {
                    document.removeEventListener('keydown', onEsc);
                    if (overlay.parentNode) overlay.parentNode.removeChild(overlay);
                };

                cancel.addEventListener('click', () => {
                    cleanup();
                    resolve(null);
                });

                overlay.addEventListener('click', (event) => {
                    if (event.target === overlay) {
                        cleanup();
                        resolve(null);
                    }
                });

                document.addEventListener('keydown', onEsc);
                footer.appendChild(cancel);

                modal.appendChild(title);
                modal.appendChild(desc);
                modal.appendChild(list);
                modal.appendChild(footer);
                overlay.appendChild(modal);
                document.body.appendChild(overlay);
            });
        }

        // YouTube Data API v3 を利用して再生リストの動画情報を取得する
        async function fetchPlaylistVideos(playlistUrl) {
            const key = getApiKey();
            if (!key || key === 'YOUR_API_KEY_HERE') {
                throw new Error('APIキーが設定されていません。スクリプト設定からAPIキーを保存してください。');
            }

            if (!playlistUrl || !playlistUrl.includes('list=')) {
                throw new Error('無効な再生リストURLです。');
            }

            const playlistIdMatch = playlistUrl.match(/list=([a-zA-Z0-9_-]+)/);
            if (!playlistIdMatch) {
                throw new Error('再生リストIDが見つかりません。');
            }
            const playlistId = playlistIdMatch[1];
            let videos = [];
            let pageToken = null;
            let playlistTitle = '再生リスト';

            const maxResults = 50; // 1回のAPIコールで取得する最大件数
            let totalItems = 0;

            try {
                do {
                    // 1. playlistItemsを呼び出し、動画IDを取得
                    let playlistItemsUrl = `https://www.googleapis.com/youtube/v3/playlistItems?part=snippet&maxResults=${maxResults}&playlistId=${playlistId}&key=${key}`;
                    if (pageToken) {
                        playlistItemsUrl += `&pageToken=${pageToken}`;
                    }

                    const resItems = await fetch(playlistItemsUrl);
                    if (!resItems.ok) throw new Error(`playlistItems HTTP ${resItems.status}`);
                    const jsonItems = await resItems.json();

                    if (jsonItems.error) {
                        throw new Error(jsonItems.error.message || 'API呼び出しエラー');
                    }

                    const videoIds = jsonItems.items.map(item => item.snippet.resourceId.videoId).join(',');

                    // 2. videos.listを呼び出し、投稿日や再生時間などの詳細を取得
                    // 💡 liveStreamingDetails パートを追加
                    const videoDetailsUrl = `https://www.googleapis.com/youtube/v3/videos?part=snippet,contentDetails,liveStreamingDetails&id=${videoIds}&key=${key}`;

                    const resDetails = await fetch(videoDetailsUrl);
                    if (!resDetails.ok) throw new Error(`videos.list HTTP ${resDetails.status}`);
                    const jsonDetails = await resDetails.json();

                    if (jsonDetails.error) {
                        throw new Error(jsonDetails.error.message || '動画詳細取得エラー');
                    }

                    // 3. データをマージして整形
                    jsonDetails.items.forEach(detail => {
                        const durationIso = detail.contentDetails.duration;

                        // ライブ配信詳細を取得
                        const liveDetails = detail.liveStreamingDetails;

                        // ライブ配信かどうかを判断
                        const isLiveArchive = !!liveDetails && !!detail.contentDetails.duration;

                        // 優先順位: 1. actualStartTime (正確な開始時刻) -> 2. publishedAt (公開時刻)
                        let finalPublishedAt = liveDetails?.actualStartTime || detail.snippet.publishedAt;

                        // 💡 【補正ロジック】正確な開始時刻がなく、ライブアーカイブである場合
                        if (isLiveArchive && !liveDetails?.actualStartTime) {
                            const publishedDate = new Date(detail.snippet.publishedAt);
                            const durationSeconds = durationToSeconds(durationIso);

                            // 補正時間（秒） = 再生時間 + 20分（1200秒）
                            const correctionSeconds = durationSeconds + (20 * 60);

                            // 投稿時刻から補正時間を引く
                            // DateオブジェクトのsetTimeはミリ秒単位
                            publishedDate.setTime(publishedDate.getTime() - (correctionSeconds * 1000));

                            // 補正後の時刻をISO形式で格納
                            finalPublishedAt = publishedDate.toISOString();
                        }

                        videos.push({
                            id: detail.id,
                            title: detail.snippet.title,
                            thumb: detail.snippet.thumbnails?.medium?.url || detail.snippet.thumbnails?.default?.url || '',
                            note: '',
                            addedAt: new Date().toISOString(),
                            publishedAt: finalPublishedAt, // 💡 補正後の時刻、または正確な開始時刻
                            duration: durationIso,
                            channelId: detail.snippet.channelId,
                            channelTitle: detail.snippet.channelTitle,
                        });
                    });

                    // 削除済み動画の判別 (playlistItemsにはあるがvideos.listにないもの)
                    totalItems += jsonDetails.items.length;

                    // 4. 次のページへの処理
                    pageToken = jsonItems.nextPageToken;
                } while (pageToken && totalItems < 500); // 処理が重くなるのを防ぐため、最大200件で停止

                // 再生リストのタイトルを取得
                if (videos.length > 0) {
                    const resPlaylist = await fetch(`https://www.googleapis.com/youtube/v3/playlists?part=snippet&id=${playlistId}&key=${key}`);
                    const jsonPlaylist = await resPlaylist.json();
                    playlistTitle = jsonPlaylist.items?.[0]?.snippet?.title || playlistTitle;
                }

                return { title: playlistTitle, videos: videos };

            } catch (error) {
                // エラーを再スローして呼び出し元に伝える
                throw new Error(`APIによる再生リストの取得中にエラーが発生しました: ${error.message}`);
            }
        }


