                        const playBtn = document.createElement('button'); playBtn.className = 'play-btn'; playBtn.textContent = '▶'; playBtn.title = t('toolbar.playAll');
                        playBtn.onclick = (e) => { e.stopPropagation(); const list = Array.isArray(data.folders[sf]) ? data.folders[sf] : []; if (!list.length) { showToast('動画がありません'); return; } const sorted = sortVideoList(list); vmPlaybackSetItem(VM_PLAYLIST_KEY, JSON.stringify(sorted.map(v => v.id))); vmPlaybackSetItem(VM_PLAYLIST_META_KEY, JSON.stringify(sorted.map(v => ({ id: v.id, title: sanitizeTitle(v.title || '') })))); vmPlaybackSetItem(VM_PLAY_INDEX_KEY, '0'); const urlFirst = `https://www.youtube.com/watch?v=${sorted[0].id}`; if (typeof GM_openInTab === 'function') { GM_openInTab(urlFirst, { active: true }); } else { window.open(urlFirst, '_blank'); } };
                        badge.appendChild(playBtn);
