                                const customInput = document.createElement('input'); customInput.type = 'color'; customInput.value = /^#([0-9a-fA-F]{6})$/.test(selectedColor || '') ? (selectedColor) : '#4DABF7'; customInput.style.height = '28px'; customInput.style.width = '36px'; customInput.style.border = 'none'; customInput.style.background = 'transparent';
