                                const cancel = document.createElement('button'); cancel.textContent = t('common.cancel'); Object.assign(cancel.style, { padding: '6px 10px', border: 'none', borderRadius: '4px', background: '#555', color: '#fff', cursor: 'pointer' });
                                btns.appendChild(ok); btns.appendChild(cancel); box.appendChild(btns);
                                overlay.appendChild(box); document.body.appendChild(overlay);
                                const onKeyRenameCtx = (ev) => { if (ev.key === 'Escape') cleanupRenameCtx(); };
                                const cleanupRenameCtx = () => { document.removeEventListener('keydown', onKeyRenameCtx); if (document.body.contains(overlay)) document.body.removeChild(overlay); };
                                document.addEventListener('keydown', onKeyRenameCtx);
                                overlay.addEventListener('click', (ev) => { if (ev.target === overlay) cleanupRenameCtx(); });
                                cancel.onclick = () => { cleanupRenameCtx(); };
