                                    if (newLeaf.includes(FOLDER_PATH_SEPARATOR)) { showToast(t('folder.dialog.err.sep').replace('{sep}', FOLDER_PATH_SEPARATOR)); return; }
                                    const parentPath = getFolderParentPath(sf);
                                    const newPath = (parentPath ? parentPath + FOLDER_PATH_SEPARATOR : '') + newLeaf;
                                    const res = renameFolderBranch(latest, sf, newPath);
                                    if (!res.success) { showToast(t('folder.dialog.err.dup')); return; }
                                    if (!latest.iconColorByFolder) latest.iconColorByFolder = {};
                                    const targetKey = res.renameMap.get(sf) || sf;
                                    if (selectedColor) { latest.iconColorByFolder[targetKey] = selectedColor; } else { delete latest.iconColorByFolder[targetKey]; }
                                    saveMylistData(latest);
