                                    const overlay = document.createElement('div'); Object.assign(overlay.style, { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.6)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 999999 });
                                    const box = document.createElement('div'); Object.assign(box.style, { background: '#1e1e1e', padding: '16px', borderRadius: '8px', minWidth: '280px', maxWidth: '90%', color: '#fff', display: 'flex', flexDirection: 'column', gap: '8px', fontSize: '14px' });
                                    const msg = document.createElement('div'); msg.textContent = '移動先のフォルダ（親）を選択'; box.appendChild(msg);
                                    // スクロール可能な候補リスト（約10件表示）
