                                    const videoCount = subtree.reduce((sum, name) => sum + (Array.isArray(latest.folders[name]) ? latest.folders[name].length : 0), 0);
                                    const subCount = Math.max(0, subtree.length - 1);
                                    const lines = [t('folder.delete.msg').replace('{name}', formatFolderPathLabel(sf, latest)), t('folder.delete.videos').replace('{n}', videoCount), ...(subCount > 0 ? [t('folder.delete.subfolders').replace('{n}', subCount)] : [])];
                                    const confirmed = await showCustomModal({ type: 'confirm', title: t('folder.delete.title'), message: lines.join('\n'), okText: t('common.delete') });
                                    if (!confirmed) return;

