            // disabled は使わず cursor + opacity で視覚的に表現（クリックでログイン誘導するため）
            function applyGdriveToolbarState(loggedIn) {
                // loggedIn が渡されなければ非同期で取得
                if (typeof loggedIn === 'boolean') {
                    const opacity = loggedIn ? '1' : '0.45';
                    const cursor = loggedIn ? '' : 'pointer';
                    gdriveSaveBtn.style.opacity = opacity;
                    gdriveSaveBtn.style.cursor = cursor;
                    gdriveRestoreBtn.style.opacity = opacity;
                    gdriveRestoreBtn.style.cursor = cursor;
                    gdriveSaveBtn.title = loggedIn
                        ? t('toolbar.gdriveSave.title')
                        : t('gdrive.notLoggedIn.hoverHint');
                    gdriveRestoreBtn.title = loggedIn
                        ? t('toolbar.gdriveRestore.title')
                        : t('gdrive.notLoggedIn.hoverHint');
                    return;
                }
                gdriveAuthStatus().then(st => {
                    applyGdriveToolbarState(!!(st && st.loggedIn));
                }).catch(() => {
                    applyGdriveToolbarState(false);
                });
            }
            // 初期状態を反映（ページ表示時に非同期チェック）
